import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Bell,
  Ticket,
  ArrowUpRight,
  CheckCircle,
  Check,
  AlertTriangle,
  FileText,
  Trash2,
  MailOpen,
  BellOff,
  MessageSquare,
  Info,
  X,
} from 'lucide-react';

type Role = 'SuperAdmin' | 'Admin' | 'Employee' | 'Technical' | 'Technical Staff' | 'Sales' | 'Client';

export type NotificationType =
  | 'assignment'
  | 'escalation'
  | 'status_change'
  | 'new_ticket'
  | 'sla_warning'
  | 'closure'
  | 'message'
  | 'general';

export interface NotificationItem {
  id: number;
  notification_type: NotificationType;
  title: string;
  message: string;
  ticket_id: number | null;
  ticket_stf_no: string | null;
  is_read: boolean;
  created_at: string;
}

/** Convert backend notification shape to our panel shape. */
export function backendToNotificationItem(raw: {
  id: number;
  notification_type: string;
  title: string;
  message: string;
  ticket?: number | null;
  ticket_id?: number | null;
  ticket_stf_no?: string | null;
  is_read: boolean;
  created_at: string;
}): NotificationItem {
  return {
    id: raw.id,
    notification_type: raw.notification_type as NotificationType,
    title: raw.title,
    message: raw.message,
    ticket_id: raw.ticket_id ?? raw.ticket ?? null,
    ticket_stf_no: raw.ticket_stf_no ?? null,
    is_read: raw.is_read,
    created_at: raw.created_at,
  };
}

function getNotificationPath(role: Role, type: NotificationType): string {
  switch (role) {
    case 'Admin':
      switch (type) {
        case 'escalation':  return '/admin/escalation';
        case 'new_ticket':  return '/admin/tickets';
        default:            return '/admin/ticket-details';
      }
    case 'Sales':
      switch (type) {
        case 'new_ticket':  return '/sales/tickets';
        default:            return '/sales/ticket-details';
      }
    case 'Employee':
    case 'Technical':
    case 'Technical Staff':
      return '/technical-staff/ticket-details';
    case 'SuperAdmin':
      switch (type) {
        case 'escalation': return '/superadmin/dashboard';
        default:           return '/superadmin/dashboard';
      }
    default:
      return '/';
  }
}

function getIcon(type: NotificationType) {
  switch (type) {
    case 'assignment':     return Ticket;
    case 'escalation':     return ArrowUpRight;
    case 'status_change':  return CheckCircle;
    case 'new_ticket':     return FileText;
    case 'sla_warning':    return AlertTriangle;
    case 'closure':        return Check;
    case 'message':        return MessageSquare;
    case 'general':        return Info;
    default:               return Bell;
  }
}

function formatTimeAgo(isoDate: string): string {
  const now = Date.now();
  const then = new Date(isoDate).getTime();
  const diffMs = now - then;
  const diffSec = Math.floor(diffMs / 1000);
  if (diffSec < 60) return 'just now';
  const diffMin = Math.floor(diffSec / 60);
  if (diffMin < 60) return `${diffMin}m ago`;
  const diffHr = Math.floor(diffMin / 60);
  if (diffHr < 24) return `${diffHr}h ago`;
  const diffDays = Math.floor(diffHr / 24);
  if (diffDays < 7) return `${diffDays}d ago`;
  return new Date(isoDate).toLocaleDateString();
}

type FilterTab = 'all' | 'unread';

interface NotificationPanelProps {
  isOpen: boolean;
  onClose: () => void;
  role: Role;
  notifications: NotificationItem[];
  onMarkRead: (ids: number[]) => void;
  onMarkAllRead: () => void;
  onDelete: (id: number) => void;
  onClearAll: () => void;
}

export function NotificationPanel({
  isOpen, onClose, role, notifications,
  onMarkRead, onMarkAllRead, onDelete, onClearAll,
}: NotificationPanelProps) {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<FilterTab>('all');

  const unreadCount = notifications.filter((n) => !n.is_read).length;

  const displayedNotifications = activeTab === 'unread'
    ? notifications.filter((n) => !n.is_read)
    : notifications;

  const handleClick = (item: NotificationItem) => {
    if (!item.is_read) onMarkRead([item.id]);
    onClose();
    const path = getNotificationPath(role, item.notification_type);
    navigate(path, item.ticket_stf_no ? { state: { ticketId: item.ticket_stf_no } } : undefined);
  };

  const handleMarkAllRead = (e: React.MouseEvent) => {
    e.stopPropagation();
    onMarkAllRead();
  };

  const toggleRead = (e: React.MouseEvent, item: NotificationItem) => {
    e.stopPropagation();
    onMarkRead([item.id]);
  };

  const handleDeleteNotification = (e: React.MouseEvent, itemId: number) => {
    e.stopPropagation();
    onDelete(itemId);
  };

  const handleClearAll = (e: React.MouseEvent) => {
    e.stopPropagation();
    onClearAll();
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Invisible backdrop to close on outside click */}
      <div
        className="fixed inset-0 z-40"
        onClick={onClose}
        aria-hidden="true"
      />
      {/* Dropdown below bell */}
      <div
        className="fixed inset-x-2 top-16 bottom-2 sm:absolute sm:inset-auto sm:right-0 sm:top-full sm:mt-2 sm:w-96 w-auto bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-700 shadow-2xl flex flex-col sm:max-h-[70vh] overflow-hidden z-50"
        role="dialog"
        aria-label="Notifications"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex-shrink-0 border-b border-gray-200 dark:border-gray-700">
          <div className="flex items-start sm:items-center justify-between px-3 sm:px-4 py-3 gap-2">
            <h2 className="text-sm font-bold text-gray-900 dark:text-white flex items-center gap-2 flex-wrap">
              <Bell className="w-4 h-4 text-[#0E8F79]" />
              Notifications
              {unreadCount > 0 && (
                <span className="px-2 py-0.5 rounded-full bg-red-500 text-white text-xs font-semibold">
                  {unreadCount}
                </span>
              )}
            </h2>
            <div className="flex items-center gap-2 flex-wrap justify-end">
              {unreadCount > 0 && (
                <button
                  onClick={handleMarkAllRead}
                  className="text-xs text-[#0E8F79] hover:underline font-medium"
                  title="Mark all as read"
                >
                  Mark all read
                </button>
              )}
              {notifications.length > 0 && (
                <button
                  onClick={handleClearAll}
                  className="text-xs text-red-500 hover:underline font-medium"
                  title="Clear all notifications"
                >
                  Clear all
                </button>
              )}
              <button
                onClick={onClose}
                className="sm:hidden p-1 rounded-md text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800"
                title="Close notifications"
                aria-label="Close notifications"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          </div>

          {/* Tabs: All / Unread */}
          <div className="flex px-3 sm:px-4 gap-1 pb-2 overflow-x-auto">
            <button
              onClick={() => setActiveTab('all')}
              className={`px-3 py-1 rounded-full text-xs font-medium transition-colors ${
                activeTab === 'all'
                  ? 'bg-[#0E8F79] text-white'
                  : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700'
              }`}
            >
              All ({notifications.length})
            </button>
            <button
              onClick={() => setActiveTab('unread')}
              className={`px-3 py-1 rounded-full text-xs font-medium transition-colors ${
                activeTab === 'unread'
                  ? 'bg-[#0E8F79] text-white'
                  : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700'
              }`}
            >
              Unread ({unreadCount})
            </button>
          </div>
        </div>

        {/* Scrollable list */}
        <div className="flex-1 overflow-y-auto overscroll-contain min-h-0">
          {displayedNotifications.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 px-4 text-center">
              <BellOff className="w-10 h-10 text-gray-300 dark:text-gray-600 mb-3" />
              <p className="text-sm font-medium text-gray-500 dark:text-gray-400">
                {activeTab === 'unread' ? 'No unread notifications' : 'No notifications'}
              </p>
              <p className="text-xs text-gray-400 dark:text-gray-500 mt-1">
                {activeTab === 'unread' ? 'You\'re all caught up!' : 'When you get notifications, they\'ll show up here.'}
              </p>
            </div>
          ) : (
            displayedNotifications.map((item) => {
              const Icon = getIcon(item.notification_type);
              return (
                <div
                  key={item.id}
                  className={`group relative flex items-start gap-3 px-4 py-3 text-left transition-colors border-b border-gray-100 dark:border-gray-800 last:border-0 cursor-pointer ${
                    item.is_read
                      ? 'hover:bg-gray-50 dark:hover:bg-gray-800'
                      : 'bg-red-50/40 dark:bg-red-900/10 hover:bg-red-50 dark:hover:bg-red-900/20'
                  }`}
                  onClick={() => handleClick(item)}
                  role="button"
                  tabIndex={0}
                  onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); handleClick(item); } }}
                >
                  {/* Icon */}
                  <div className="flex-shrink-0 w-9 h-9 rounded-lg bg-[#0E8F79]/10 dark:bg-[#0E8F79]/20 flex items-center justify-center mt-0.5">
                    <Icon className="w-4 h-4 text-[#0E8F79]" />
                  </div>

                  {/* Text */}
                  <div className="flex-1 min-w-0">
                    <p className={`text-sm leading-tight ${item.is_read ? 'font-normal text-gray-600 dark:text-gray-300' : 'font-semibold text-gray-900 dark:text-white'}`}>
                      {item.title}
                    </p>
                    {item.message && (
                      <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5 truncate">{item.message}</p>
                    )}
                    {item.ticket_stf_no && (
                      <p className="text-xs text-gray-400 dark:text-gray-500 mt-0.5 font-mono truncate">{item.ticket_stf_no}</p>
                    )}
                    <p className="text-xs text-gray-400 dark:text-gray-500 mt-0.5">{formatTimeAgo(item.created_at)}</p>
                  </div>

                  {/* Action buttons — visible on hover */}
                  <div className="flex-shrink-0 flex items-center gap-0.5 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                    {/* Toggle read */}
                    {!item.is_read && (
                      <button
                        onClick={(e) => toggleRead(e, item)}
                        className="p-1.5 rounded-md text-gray-400 hover:text-[#0E8F79] hover:bg-[#0E8F79]/10 transition-colors"
                        title="Mark as read"
                      >
                        <MailOpen className="w-3.5 h-3.5" />
                      </button>
                    )}

                    {/* Delete */}
                    <button
                      onClick={(e) => handleDeleteNotification(e, item.id)}
                      className="p-1.5 rounded-md text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                      title="Delete notification"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                  </div>

                  {/* Read/Unread dot (visible when actions are hidden) */}
                  <div className="flex-shrink-0 mt-2 sm:group-hover:hidden">
                    {item.is_read
                      ? <span className="w-2 h-2 rounded-full bg-gray-300 dark:bg-gray-600 inline-block" title="Read" />
                      : <span className="w-2 h-2 rounded-full bg-red-500 inline-block animate-pulse" title="Unread" />
                    }
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>
    </>
  );
}

import React, { useEffect, useState } from 'react';
import {
  LayoutDashboard,
  Users,
  BarChart3,
  Settings,
  FileText,
  LogOut,
  Ticket,
  ShieldAlert,
  ChevronDown,
  X,
} from 'lucide-react';
import { SignOutModal } from '../ui/SignOutModal';

export interface NavItem {
  id: string;
  label: string;
  icon: React.ComponentType<{ className?: string }>;
  path: string;
  exact?: boolean;
  children?: NavItem[];
}

interface SidebarProps {
  role: 'SuperAdmin' | 'Admin' | 'Employee' | 'Technical' | 'Technical Staff' | 'Client' | 'Sales';
  onNavigate: (page: string) => void;
  currentPage: string;
  /** When provided, use these items (path = route path). Otherwise derive from role (legacy). */
  navItems?: NavItem[];
  onExpandChange?: (isExpanded: boolean) => void;
  isMobileOpen?: boolean;
  onNavigateItem?: () => void;
}

export function Sidebar({
  role,
  onNavigate,
  currentPage,
  navItems: navItemsProp,
  onExpandChange,
  isMobileOpen = false,
  onNavigateItem,
}: SidebarProps) {
  const [isExpanded, setIsExpanded] = useState(false);
  const [showSignOutModal, setShowSignOutModal] = useState(false);
  const [expandedGroups, setExpandedGroups] = useState<Set<string>>(new Set());
  const [isDesktopViewport, setIsDesktopViewport] = useState(() =>
    typeof window !== 'undefined' ? window.innerWidth >= 1024 : true
  );

  useEffect(() => {
    const handleResize = () => setIsDesktopViewport(window.innerWidth >= 1024);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const sidebarExpanded = !isDesktopViewport || isMobileOpen || isExpanded;

  const toggleGroup = (id: string) => {
    setExpandedGroups((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const handleMouseEnter = () => {
    if (isMobileOpen) return;
    setIsExpanded(true);
    onExpandChange?.(true);
  };

  const handleMouseLeave = () => {
    if (isMobileOpen) return;
    setIsExpanded(false);
    onExpandChange?.(false);
  };

  const getNavItems = (): NavItem[] => {
    const common: NavItem[] = [
      { id: 'logout', label: 'Logout', icon: LogOut, path: 'logout' },
    ];
    switch (role) {
      case 'SuperAdmin':
        return [
          { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, path: 'superadmin-dashboard' },
          { id: 'user-management', label: 'User Management', icon: Users, path: 'user-management' },
          { id: 'reports', label: 'Global Reports', icon: BarChart3, path: 'reports' },
          { id: 'settings', label: 'Settings', icon: Settings, path: 'settings' },
          ...common,
        ];
      case 'Admin':
        return [
          { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, path: 'admin-dashboard' },
          { id: 'tickets', label: 'Tickets', icon: Ticket, path: 'admin-tickets' },
          { id: 'escalation', label: 'Escalation', icon: ShieldAlert, path: 'escalation' },
          { id: 'reports', label: 'Reports', icon: BarChart3, path: 'reports' },
          ...common,
        ];
      case 'Employee':
      case 'Technical Staff':
        return [
          { id: 'dashboard', label: 'My Dashboard', icon: LayoutDashboard, path: 'technical-staff-dashboard' },
          { id: 'my-tickets', label: 'My Tickets', icon: Ticket, path: 'technical-staff-my-tickets' },
          ...common,
        ];
      case 'Client':
        return [
          { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, path: 'client-dashboard' },
          { id: 'create-ticket', label: 'Create Ticket', icon: FileText, path: 'create-ticket' },
          { id: 'my-tickets', label: 'My Tickets', icon: Ticket, path: 'client-my-tickets' },
          ...common,
        ];
      default:
        return common;
    }
  };

  const navItems = navItemsProp ?? getNavItems();
  const isPathMatch = (item: NavItem) => {
    if (item.path === 'logout') return false;
    if (item.exact) return currentPage === item.path;
    return currentPage === item.path || currentPage.startsWith(item.path + '/');
  };

  return (
    <aside 
      className={`bg-white dark:bg-[#0a0a0a] text-gray-900 dark:text-white flex flex-col h-full border-r border-gray-200 dark:border-gray-800 transition-all duration-300 ${sidebarExpanded ? 'w-[85vw] max-w-72 lg:w-64' : 'w-20'}`}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      {/* Logo Area */}
      <div className="p-4 sm:p-6 border-b border-gray-200 dark:border-gray-800 flex flex-col items-center relative">
        {isMobileOpen && (
          <button
            onClick={onNavigateItem}
            className="lg:hidden absolute top-3 right-3 p-1.5 rounded-md text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800"
            aria-label="Close menu"
          >
            <X className="w-4 h-4" />
          </button>
        )}
        <img
          src="/Maptech%20Official%20Logo%20version2%20(1).png"
          alt="Maptech Logo"
          className="h-16 w-auto mb-2 object-contain" />

        {sidebarExpanded && (
          <span className="text-xs text-gray-500 dark:text-gray-400 text-center tracking-wide font-medium leading-tight">
            Maptech Information Solutions Inc.
          </span>
        )}
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-4 py-6 space-y-1 overflow-y-auto">
        {navItems.map((item) => {
          if (item.id === 'logout') return null;
          const Icon = item.icon;
          const hasChildren = item.children && item.children.length > 0;
          const isChildActive = hasChildren && item.children!.some((c) => isPathMatch(c));
          const isActive = navItemsProp ? (isPathMatch(item) || isChildActive) : currentPage === item.path;
          const isGroupOpen = expandedGroups.has(item.id) || isChildActive;

          if (hasChildren) {
            return (
              <div key={item.id}>
                <button
                  onClick={() => { if (sidebarExpanded) toggleGroup(item.id); else onNavigate(item.children![0].path); }}
                  className={`w-full flex items-center px-4 py-3 text-sm font-medium rounded-lg transition-all duration-200 group ${sidebarExpanded ? '' : 'justify-center'} ${isActive ? 'bg-gradient-to-r from-[#63D44A] to-[#0E8F79] text-white shadow-lg shadow-[#3BC25B]/20' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5 hover:text-gray-900 dark:hover:text-white'}`}
                  title={!sidebarExpanded ? item.label : undefined}
                >
                  <Icon className={`w-5 h-5 flex-shrink-0 ${sidebarExpanded ? 'mr-3' : ''} ${isActive ? 'text-white' : 'text-gray-400 dark:text-gray-500 group-hover:text-gray-900 dark:group-hover:text-white'}`} />
                  {sidebarExpanded && (
                    <>
                      <span className="flex-1 text-left">{item.label}</span>
                      <ChevronDown className={`w-4 h-4 transition-transform duration-200 ${isGroupOpen ? 'rotate-180' : ''}`} />
                    </>
                  )}
                </button>
                {sidebarExpanded && isGroupOpen && (
                  <div className="ml-6 mt-1 space-y-1">
                    {item.children!.map((child) => {
                      const childActive = isPathMatch(child);
                      const ChildIcon = child.icon;
                      return (
                        <button
                          key={child.id}
                          onClick={() => {
                            onNavigate(child.path);
                            onNavigateItem?.();
                          }}
                          className={`w-full flex items-center px-4 py-2 text-sm rounded-lg transition-all duration-200 group ${childActive ? 'bg-[#3BC25B]/15 text-[#0E8F79] dark:text-[#63D44A] font-semibold' : 'text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5 hover:text-gray-900 dark:hover:text-white'}`}
                        >
                          <ChildIcon className={`w-4 h-4 flex-shrink-0 mr-3 ${childActive ? 'text-[#0E8F79] dark:text-[#63D44A]' : 'text-gray-400 dark:text-gray-500 group-hover:text-gray-900 dark:group-hover:text-white'}`} />
                          {child.label}
                        </button>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          }

          return (
            <button
              key={item.id}
              onClick={() => {
                onNavigate(item.path);
                onNavigateItem?.();
              }}
              className={`w-full flex items-center px-4 py-3 text-sm font-medium rounded-lg transition-all duration-200 group ${sidebarExpanded ? '' : 'justify-center'} ${isActive ? 'bg-gradient-to-r from-[#63D44A] to-[#0E8F79] text-white shadow-lg shadow-[#3BC25B]/20' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5 hover:text-gray-900 dark:hover:text-white'}`}
              title={!sidebarExpanded ? item.label : undefined}
            >
              <Icon
                className={`w-5 h-5 flex-shrink-0 ${sidebarExpanded ? 'mr-3' : ''} ${isActive ? 'text-white' : 'text-gray-400 dark:text-gray-500 group-hover:text-gray-900 dark:group-hover:text-white'}`} />

              {sidebarExpanded && item.label}
            </button>
          );
        })}
      </nav>

      {/* Bottom Actions */}
      <div className="p-4 border-t border-gray-200 dark:border-gray-800">
        <button
          onClick={() => setShowSignOutModal(true)}
          className={`w-full flex items-center px-4 py-3 text-sm font-medium text-gray-500 dark:text-gray-400 rounded-lg hover:bg-red-50 dark:hover:bg-red-500/10 hover:text-red-500 dark:hover:text-red-400 transition-colors ${sidebarExpanded ? '' : 'justify-center'}`}
          title={!sidebarExpanded ? 'Sign Out' : undefined}
        >
          <LogOut className={`w-5 h-5 flex-shrink-0 ${sidebarExpanded ? 'mr-3' : ''}`} />
          {sidebarExpanded && 'Sign Out'}
        </button>
      </div>

      {/* Sign Out Confirmation Modal */}
      <SignOutModal
        isOpen={showSignOutModal}
        onConfirm={() => {
          setShowSignOutModal(false);
          onNavigate('logout');
          onNavigateItem?.();
        }}
        onCancel={() => setShowSignOutModal(false)}
      />
    </aside>
  );
}

import { createContext, useContext, useState, useCallback, useEffect, ReactNode } from 'react';
import {
  loginWithCredentials as apiLogin,
  fetchCurrentUser,
  logoutRequest,
  refreshAccessToken,
} from '../services/authService';
import {
  clearLegacyAuthStorage,
} from '../utils/authStorage';

export type Role = 'superadmin' | 'admin' | 'employee' | 'sales' | null;

export interface AuthUser {
  role: Role;
  id?: number;
  username?: string;
  email?: string;
  name?: string;
  first_name?: string;
  middle_name?: string;
  last_name?: string;
  suffix?: string;
  phone?: string;
  profile_picture_url?: string | null;
}

interface AuthContextValue {
  user: AuthUser | null;
  /** True while the app is checking stored tokens on first load. */
  loading: boolean;
  /** Login with backend credentials. Returns redirect path derived from role. */
  loginWithCredentials: (email: string, password: string, rememberMe?: boolean) => Promise<string>;
  logout: () => void;
  /** Derive dashboard path from role. */
  getRedirectPath: (role: Role) => string;
  /** Current access token (for API calls elsewhere). */
  accessToken: string | null;
  /** Update the in-memory user after a profile edit. */
  updateUser: (partial: Partial<AuthUser>) => void;
}

const AuthContext = createContext<AuthContextValue | null>(null);

function normalizeRole(role: string): Role {
  const r = (role || '').toLowerCase();
  if (r === 'superadmin' || r === 'super_admin') return 'superadmin';
  if (r === 'admin') return 'admin';
  if (r === 'employee') return 'employee';
  if (r === 'sales') return 'sales';
  return null;
}

function roleToPath(role: Role): string {
  switch (role) {
    case 'superadmin': return '/superadmin/dashboard';
    case 'admin': return '/admin/dashboard';
    case 'sales': return '/sales/tickets';
    case 'employee': return '/technical-staff/dashboard';
    case null:
    default: return '/login';
  }
}

function normalizeRedirectPath(role: Role, path?: string): string {
  if (!path) return roleToPath(role);
  if (role === 'sales' && path.startsWith('/admin')) {
    return path.replace('/admin', '/sales');
  }
  if (role === 'employee' && path.startsWith('/employee')) {
    return path.replace('/employee', '/technical-staff');
  }
  return path;
}

function buildAuthUser(apiUser: Record<string, unknown>): AuthUser | null {
  const role = normalizeRole(apiUser.role as string);
  if (!role) return null; // Unknown role — deny access
  return {
    role,
    id: apiUser.id as number | undefined,
    username: apiUser.username as string | undefined,
    email: apiUser.email as string | undefined,
    first_name: apiUser.first_name as string | undefined,
    middle_name: apiUser.middle_name as string | undefined,
    last_name: apiUser.last_name as string | undefined,
    suffix: apiUser.suffix as string | undefined,
    phone: apiUser.phone as string | undefined,
    profile_picture_url: apiUser.profile_picture_url as string | null | undefined,
    name: [apiUser.first_name, apiUser.last_name].filter(Boolean).join(' ') || (apiUser.username as string),
  };
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [accessToken, setAccessToken] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  // On mount: try to restore session from stored tokens
  useEffect(() => {
    let cancelled = false;

    async function restore() {
      clearLegacyAuthStorage();

      // Try current access cookie.
      try {
        const apiUser = await fetchCurrentUser();
        if (!cancelled) {
          const authUser = buildAuthUser(apiUser as unknown as Record<string, unknown>);
          if (authUser) {
            setAccessToken(null);
            setUser(authUser);
          } else {
            clearLegacyAuthStorage();
          }
        }
      } catch {
        // Access may be expired; try refresh cookie.
        try {
          await refreshAccessToken();
          const apiUser = await fetchCurrentUser();
          if (!cancelled) {
            const authUser = buildAuthUser(apiUser as unknown as Record<string, unknown>);
            if (authUser) {
              setAccessToken(null);
              setUser(authUser);
            } else {
              clearLegacyAuthStorage();
            }
          }
        } catch {
          clearLegacyAuthStorage();
        }
      }

      if (!cancelled) setLoading(false);
    }

    restore();
    return () => { cancelled = true; };
  }, []);

  const loginWithCredentials = useCallback(
    async (email: string, password: string, rememberMe?: boolean): Promise<string> => {
      const trimmedEmail = email.trim().toLowerCase();
      const data = await apiLogin({ email: trimmedEmail, password, remember_me: !!rememberMe });

      const token = data.access;
      clearLegacyAuthStorage();

      // Build user from response
      const authUser = buildAuthUser(data.user as unknown as Record<string, unknown>);
      if (!authUser) {
        clearLegacyAuthStorage();
        throw new Error('Your account role is not authorized to access this system.');
      }

      setAccessToken(token);
      setUser(authUser);

      return normalizeRedirectPath(authUser.role, data.redirect_path);
    },
    [],
  );

  const updateUser = useCallback((partial: Partial<AuthUser>) => {
    setUser((prev) => {
      if (!prev) return prev;
      const next = { ...prev, ...partial, name: [partial.first_name ?? prev.first_name, partial.last_name ?? prev.last_name].filter(Boolean).join(' ') || prev.username || '' };
      return next;
    });
  }, []);

  const logout = useCallback(() => {
    void logoutRequest();
    setUser(null);
    setAccessToken(null);
    clearLegacyAuthStorage();
  }, []);

  const getRedirectPath = useCallback((role: Role) => roleToPath(role), []);

  return (
    <AuthContext.Provider
      value={{
        user,
        loading,
        loginWithCredentials,
        logout,
        getRedirectPath,
        accessToken,
        updateUser,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider.');
  return ctx;
}

import React, { createContext, useContext, useState, useEffect, useCallback, ReactNode } from 'react';

interface ThemeContextValue {
  isDark: boolean;
  toggleDark: () => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

const STORAGE_KEY = 'maptech_dark_mode';

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [isDark, setIsDark] = useState(() => {
    // Restore from localStorage; fall back to checking the DOM class
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored !== null) return stored === 'true';
    return document.documentElement.classList.contains('dark');
  });

  // Keep <html> class and localStorage in sync whenever isDark changes
  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDark);
    localStorage.setItem(STORAGE_KEY, String(isDark));
  }, [isDark]);

  const toggleDark = useCallback(() => setIsDark((d) => !d), []);

  return (
    <ThemeContext.Provider value={{ isDark, toggleDark }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme must be used within ThemeProvider.');
  return ctx;
}

import React from 'react';
import { useNavigate, useLocation, Outlet } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { Layout } from '../components/layout/Layout';
import { Sidebar, type NavItem } from '../components/layout/Sidebar';
import { LayoutDashboard, Users, BarChart3, Settings, ScrollText, Award } from 'lucide-react';
import { NetworkErrorModal, useNetworkStatus } from '../shared';

const NAV_ITEMS: NavItem[] = [
  { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, path: '/superadmin/dashboard' },
  { id: 'users', label: 'User Management', icon: Users, path: '/superadmin/users' },
  { id: 'audit-logs', label: 'Audit Logs', icon: ScrollText, path: '/superadmin/audit-logs' },
  { id: 'reports', label: 'Reports', icon: BarChart3, path: '/superadmin/reports' },
  { id: 'technical-staff-ratings', label: 'Technical Staff Ratings', icon: Award, path: '/superadmin/technical-staff-ratings' },
  { id: 'settings', label: 'Settings', icon: Settings, path: '/superadmin/settings' },
];

export function SuperAdminLayout() {
  const { user, logout } = useAuth();
  const { isDark, toggleDark } = useTheme();
  const navigate = useNavigate();
  const location = useLocation();

  const handleNavigate = (path: string) => {
    if (path === 'logout') {
      logout();
      navigate('/login', { replace: true });
      return;
    }
    navigate(path);
  };

  const { isOffline, retry, dismiss, retrying } = useNetworkStatus();

  if (!user) return null;
  const layoutRole = 'SuperAdmin' as const;

  return (
    <Layout
      role={layoutRole}
      currentPage={location.pathname}
      onNavigate={handleNavigate}
      isDark={isDark}
      onToggleDark={toggleDark}
      navItems={NAV_ITEMS}
    >
      <NetworkErrorModal isOpen={isOffline} onRetry={retry} onDismiss={dismiss} retrying={retrying} />
      <Outlet />
    </Layout>
  );
}

