    last_name: user?.last_name || '',
    suffix: user?.suffix || '',
    phone: user?.phone || '',
  });
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});

  const startEdit = () => {
    setForm({
      first_name: user?.first_name || '',
      middle_name: user?.middle_name || '',
      last_name: user?.last_name || '',
      suffix: user?.suffix || '',
      phone: user?.phone || '',
    });
    setFieldErrors({});
    setEditing(true);
  };

  const cancelEdit = () => { setEditing(false); setFieldErrors({}); };

  /* ── Avatar upload ── */
  const avatarInputRef = useRef<HTMLInputElement>(null);
  const [avatarLoading, setAvatarLoading] = useState(false);
  const [removeAvatarLoading, setRemoveAvatarLoading] = useState(false);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
  const [avatarImgError, setAvatarImgError] = useState(false);
  const [avatarLightboxOpen, setAvatarLightboxOpen] = useState(false);

  const avatarSrc = avatarPreview
    ? avatarPreview
    : user?.profile_picture_url
    ? `${user.profile_picture_url}?t=${encodeURIComponent(user.profile_picture_url.split('/').pop() || '')}`
    : null;

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const blobUrl = URL.createObjectURL(file);
    setAvatarPreview(blobUrl);
    setAvatarImgError(false);
    setAvatarLoading(true);
    // Update navbar instantly with the local blob so the circle reflects the new photo right away
    updateUser({ profile_picture_url: blobUrl });
    try {
      const updated = await uploadAvatar(file);
      // Replace blob URL in context with the permanent server URL
      updateUser({ profile_picture_url: updated.profile_picture_url ?? null });
      toast.success('Profile picture updated.');
    } catch (err) {
      setAvatarPreview(null);
      updateUser({ profile_picture_url: user?.profile_picture_url ?? null });
      toast.error(err instanceof Error ? err.message : 'Failed to upload picture.');
    } finally {
      setAvatarLoading(false);
      // Delay revocation so React can flush the server URL update to the navbar before the blob dies
      setTimeout(() => URL.revokeObjectURL(blobUrl), 5000);
      if (avatarInputRef.current) avatarInputRef.current.value = '';
    }
  };

  const handleRemoveAvatar = async () => {
    setRemoveAvatarLoading(true);
    try {
      await removeAvatar();
      setAvatarPreview(null);
      setAvatarImgError(false);
      updateUser({ profile_picture_url: null });
      toast.success('Profile picture removed.');
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to remove picture.');
    } finally {
      setRemoveAvatarLoading(false);
    }
  };

  const handleField = (field: string, value: string) => {
    setForm((p) => ({ ...p, [field]: value }));
    setFieldErrors((p) => ({ ...p, [field]: '' }));
  };

  const handleSaveProfile = async () => {
    const errs: Record<string, string> = {};
    const fnErr = validateName(form.first_name, 'First name');
    if (fnErr) errs.first_name = fnErr;
    const lnErr = validateName(form.last_name, 'Last name');
    if (lnErr) errs.last_name = lnErr;
    if (form.phone) {
      const phErr = validatePhone(form.phone);
      if (phErr) errs.phone = phErr;
    }
    if (Object.keys(errs).length) { setFieldErrors(errs); return; }

    setProfileLoading(true);
    try {
      const updated = await updateProfile(form);
      updateUser({
        first_name: updated.first_name,
        middle_name: updated.middle_name,
        last_name: updated.last_name,
        suffix: updated.suffix,
        phone: updated.phone,
      });
      toast.success('Profile updated successfully.');
      setEditing(false);
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to update profile.');
    } finally {
      setProfileLoading(false);
    }
  };

  /* ── Password state ── */
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [pwError, setPwError] = useState('');
  const [pwLoading, setPwLoading] = useState(false);
  const [pwRules, setPwRules] = useState<PasswordRules | null>(null);
  const [showCurrent, setShowCurrent] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setPwError('');
    if (!currentPassword || !newPassword || !confirmPassword) {
      setPwError('All fields are required.');
      return;
    }
    const { error } = validatePassword(newPassword);
    if (error) { setPwError(error); return; }
    const confirmErr = validateConfirmPassword(newPassword, confirmPassword);
    if (confirmErr) { setPwError(confirmErr); return; }

    setPwLoading(true);
    try {
      const breached = await checkPasswordPwned(newPassword);
      if (breached) {
        setPwError('This password has been found in a data breach. Please choose a different password.');
        setPwRules((prev) => prev ? { ...prev, notBreached: false } : prev);
        return;
      }
      await changePassword(currentPassword, newPassword);
      toast.success('Password changed successfully.');
      setCurrentPassword('');
      setNewPassword('');
      setConfirmPassword('');
      setPwRules(null);
    } catch (err) {
      setPwError(err instanceof Error ? err.message : 'Failed to change password.');
    } finally {
      setPwLoading(false);
    }
  };

  /* ── Helpers ── */
  const inputClass = 'w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400';
  const boxEdit = 'flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B]';
  const boxReadonly = 'flex items-center gap-2 px-3 py-2.5 rounded-lg bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700';

  return (
    <div className="space-y-6 max-w-3xl">
      <div>
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Settings</h1>
        <p className="text-gray-500 dark:text-gray-400">Manage your supervisor account settings</p>
      </div>

      {/* ── Personal Details ── */}
      <Card accent>
        {/* Avatar */}
        <div className="flex items-center gap-6 mb-6">
          <div className="relative flex-shrink-0">
            {/* Circle: click image → preview; click empty circle → file picker */}
            <div
              className="w-28 h-28 rounded-full overflow-hidden bg-gray-200 dark:bg-gray-700 border-2 border-gray-300 dark:border-gray-600 flex items-center justify-center cursor-pointer group"
              onClick={() => {
                if (avatarLoading || removeAvatarLoading) return;
                if (avatarSrc && !avatarImgError) setAvatarLightboxOpen(true);
                else avatarInputRef.current?.click();
              }}
            >
              {avatarSrc && !avatarImgError ? (
                <img
                  src={avatarSrc}
                  alt="Profile"
                  className="w-full h-full object-cover"
                  onError={() => setAvatarImgError(true)}
                />
              ) : (
                <User className="w-12 h-12 text-gray-400" />
              )}
              <div className="absolute inset-0 rounded-full flex items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity">
                {avatarLoading
                  ? <Loader2 className="w-6 h-6 text-white animate-spin" />
                  : (avatarSrc && !avatarImgError)
                  ? <Eye className="w-6 h-6 text-white" />
                  : <Camera className="w-6 h-6 text-white" />}
              </div>
            </div>
            <input ref={avatarInputRef} type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
          </div>
          <div>
            <p className="text-sm font-semibold text-gray-900 dark:text-white">Profile Picture</p>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">JPG, PNG or GIF · Max 5 MB</p>
            <div className="flex items-center gap-3 mt-2">
              <button
                type="button"
                onClick={() => !avatarLoading && !removeAvatarLoading && avatarInputRef.current?.click()}
                disabled={avatarLoading || removeAvatarLoading}
                className="text-xs font-medium text-[#3BC25B] hover:text-[#63D44A] transition-colors disabled:opacity-50"
              >
                {avatarLoading ? 'Uploading…' : 'Change photo'}
              </button>
              {(user?.profile_picture_url || avatarPreview) && (
                <>
                  <span className="text-gray-500 dark:text-gray-600 text-xs">·</span>
                  <button
                    type="button"
                    onClick={handleRemoveAvatar}
                    disabled={avatarLoading || removeAvatarLoading}
                    className="text-xs font-medium text-red-400 hover:text-red-500 transition-colors disabled:opacity-50"
                  >
                    {removeAvatarLoading ? 'Removing…' : 'Remove photo'}
                  </button>
                </>
              )}
            </div>
          </div>
        </div>

        {/* Lightbox */}
        {avatarLightboxOpen && avatarSrc && createPortal(
          <div
            className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm"
            onClick={() => setAvatarLightboxOpen(false)}
          >
            <div className="relative max-w-sm w-full mx-4" onClick={(e) => e.stopPropagation()}>
              <button
                onClick={() => setAvatarLightboxOpen(false)}
                className="absolute -top-3 -right-3 z-10 w-8 h-8 rounded-full bg-gray-800 border border-gray-600 flex items-center justify-center text-gray-300 hover:text-white hover:bg-gray-700 transition-colors"
              >
                <X className="w-4 h-4" />
              </button>
              <img
                src={avatarSrc}
                alt="Profile preview"
                className="w-full rounded-2xl object-cover shadow-2xl"
              />
            </div>
          </div>
        , document.body)}

        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Personal Details</h2>
        </div>

        {!editing ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {[
              { label: 'First Name', value: user?.first_name || '—', icon: User },
              { label: 'Last Name', value: user?.last_name || '—', icon: User },
              { label: 'Middle Name', value: user?.middle_name || '—', icon: User },
              { label: 'Suffix', value: user?.suffix || '—', icon: User },
              { label: 'Email', value: user?.email || '—', icon: Mail },
              { label: 'Phone', value: user?.phone || '—', icon: Phone },
              { label: 'Department', value: 'Administration', icon: Building },
              { label: 'Role', value: 'Supervisor', icon: Shield },
            ].map((f) => (
              <div key={f.label}>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">{f.label}</label>
                <div className={boxReadonly}>
                  <f.icon className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-700 dark:text-gray-300">{f.value}</span>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">First Name <span className="text-red-400">*</span></label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.first_name} maxLength={MAX_NAME} onChange={(e) => handleField('first_name', e.target.value)} className={inputClass} placeholder="First name" />
                </div>
                {fieldErrors.first_name && <p className="text-xs text-red-400 mt-1">{fieldErrors.first_name}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Last Name <span className="text-red-400">*</span></label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.last_name} maxLength={MAX_NAME} onChange={(e) => handleField('last_name', e.target.value)} className={inputClass} placeholder="Last name" />
                </div>
                {fieldErrors.last_name && <p className="text-xs text-red-400 mt-1">{fieldErrors.last_name}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Middle Name</label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.middle_name} maxLength={MAX_NAME} onChange={(e) => handleField('middle_name', e.target.value)} className={inputClass} placeholder="Middle name (optional)" />
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Suffix</label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.suffix} maxLength={10} onChange={(e) => handleField('suffix', e.target.value)} className={inputClass} placeholder="e.g. Jr., Sr., III" />
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Phone</label>
                <div className={boxEdit}>
                  <Phone className="w-4 h-4 text-gray-400" />
                  <input value={form.phone} maxLength={MAX_PHONE} onChange={(e) => handleField('phone', e.target.value)} className={inputClass} placeholder="+63 9XX XXX XXXX" />
                </div>
                {fieldErrors.phone && <p className="text-xs text-red-400 mt-1">{fieldErrors.phone}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Email</label>
                <div className={boxReadonly}>
                  <Mail className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-500 dark:text-gray-400">{user?.email || '—'}</span>
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Role</label>
                <div className={boxReadonly}>
                  <Shield className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-500 dark:text-gray-400">Supervisor</span>
                </div>
              </div>
            </div>
            <div className="flex gap-3 pt-2">
              <GreenButton type="button" onClick={handleSaveProfile} disabled={profileLoading}>
                {profileLoading ? <><Loader2 className="w-4 h-4 animate-spin" /> Saving…</> : 'Save Changes'}
              </GreenButton>
              <button type="button" onClick={cancelEdit} className="px-4 py-2 rounded-lg text-sm font-medium text-gray-400 hover:text-white border border-gray-600 hover:border-gray-500 transition-colors">
                Cancel
              </button>
            </div>
          </div>
        )}
      </Card>

      <Card accent>
        <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">Change Password</h2>
        <form onSubmit={handleChangePassword} className="space-y-4 max-w-md">
          {pwError && <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 text-sm">{pwError}</div>}
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Current Password</label>
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B] relative">
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showCurrent ? 'text' : 'password'} value={currentPassword} maxLength={MAX_PASSWORD} onChange={(e) => setCurrentPassword(e.target.value)} placeholder="••••••••" className="w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400 pr-10" />
              <button type="button" onClick={() => setShowCurrent((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showCurrent ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">New Password</label>
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B] relative">
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showNew ? 'text' : 'password'} value={newPassword} maxLength={MAX_PASSWORD} onChange={(e) => { setNewPassword(e.target.value); const { rules } = validatePassword(e.target.value); setPwRules(rules); }} placeholder="••••••••" className="w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400 pr-10" />
              <button type="button" onClick={() => setShowNew((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showNew ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
            {newPassword && pwRules && (
              <ul className="text-xs space-y-0.5 mt-1.5">
                {[
                  { ok: pwRules.minLength, text: 'At least 8 characters' },
                  { ok: pwRules.hasUppercase, text: 'An uppercase letter' },
                  { ok: pwRules.hasLowercase, text: 'A lowercase letter' },
                  { ok: pwRules.hasNumber, text: 'A number' },
                  { ok: pwRules.hasSpecial, text: 'A special character' },
                ].map((r) => (
                  <li key={r.text} className={r.ok ? 'text-green-600' : 'text-red-500'}>
                    {r.ok ? '\u2713' : '\u2717'} {r.text}
                  </li>
                ))}
              </ul>
            )}
          </div>
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Confirm New Password</label>
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B] relative">
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showConfirm ? 'text' : 'password'} value={confirmPassword} maxLength={MAX_PASSWORD} onChange={(e) => setConfirmPassword(e.target.value)} placeholder="••••••••" className="w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400 pr-10" />
              <button type="button" onClick={() => setShowConfirm((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showConfirm ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <GreenButton type="submit" disabled={pwLoading}>
            {pwLoading ? 'Updating…' : 'Update Password'}
          </GreenButton>
        </form>
      </Card>
    </div>
  );
}

﻿import { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useNavigate } from 'react-router-dom';
import { Card } from '../../components/ui/Card';
import { StatusBadge } from '../../components/ui/StatusBadge';
import { PriorityBadge } from '../../components/ui/PriorityBadge';
import { SLATimer } from '../../components/ui/SLATimer';
import {
  Filter,
  MoreHorizontal,
  Eye,
  Pencil,
  Trash2,
  ChevronLeft,
  ChevronRight as ChevronRightIcon,
  X,
  Search,
} from 'lucide-react';
import { toast } from 'sonner';
import {
  fetchTickets,
  fetchEmployees,
  deleteTicket as apiDeleteTicket,
  updateTicket as apiUpdateTicket,
  assignTicket,
} from '../../services/api';
import type { BackendTicket } from '../../services/api';
import { mapBackendTicketToUI, reverseMapStatus, reverseMapPriority } from '../../services/ticketMapper';
import type { UITicket } from '../../services/ticketMapper';
import { useAuth } from '../../context/AuthContext';

const ITEMS_PER_PAGE = 5;
const PRIORITIES = ['Critical', 'High', 'Medium', 'Low'];
const STATUSES = ['Pending', 'Assigned', 'In Progress', 'Resolved', 'Closed'];

function truncateText(value: string, maxLength: number): string {
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength)}...`;
}

export default function AdminTickets() {
  const navigate = useNavigate();
  const { user } = useAuth();
  const routeBase = user?.role === 'sales' ? '/sales' : '/admin';
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [showFilter, setShowFilter] = useState(false);
  const [filterPriority, setFilterPriority] = useState<string[]>([]);
  const [filterStatus, setFilterStatus] = useState<string[]>([]);
  const [openMenuId, setOpenMenuId] = useState<string | null>(null);
  const [tickets, setTickets] = useState<UITicket[]>([]);
  const [backendTickets, setBackendTickets] = useState<BackendTicket[]>([]);
  const [editTicket, setEditTicket] = useState<UITicket | null>(null);
  const [editFields, setEditFields] = useState({ status: '', priority: '', assigneeId: '' });
  const [employees, setEmployees] = useState<{ id: number; first_name: string; last_name: string; username: string; active_ticket_count: number }[]>([]);
  const [loading, setLoading] = useState(true);

  // Fetch tickets from backend
  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const [raw, emps] = await Promise.all([
          fetchTickets(),
          fetchEmployees().catch(() => []),
        ]);
        const visibleTickets = raw.filter((ticket) => ticket.status !== 'escalated' && ticket.status !== 'escalated_external');
        if (cancelled) return;
        setBackendTickets(visibleTickets);
        setTickets(visibleTickets.map(mapBackendTicketToUI));
        if (emps) setEmployees(emps);
      } catch (err) {
        if (!cancelled) toast.error('Failed to load tickets.');
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, []);

  // Close open menu when clicking anywhere outside
  useEffect(() => {
    const handler = () => setOpenMenuId(null);
    document.addEventListener('click', handler);
    return () => document.removeEventListener('click', handler);
  }, []);

  const openEdit = (ticket: UITicket) => {
    setEditTicket(ticket);
    setEditFields({ status: ticket.status, priority: ticket.priority, assigneeId: ticket.assigneeId != null ? String(ticket.assigneeId) : '' });
    setOpenMenuId(null);
  };

  const saveEdit = async () => {
    if (!editTicket) return;
    try {
      const assignedToId = editFields.assigneeId ? Number(editFields.assigneeId) : null;

      // Update status & priority via PATCH
      await apiUpdateTicket(editTicket.backendId, {
        status: reverseMapStatus(editFields.status),
        priority: reverseMapPriority(editFields.priority),
      } as any);

      // Assign employee via dedicated endpoint (if changed)
      if (assignedToId && assignedToId !== editTicket.assigneeId) {
        await assignTicket(editTicket.backendId, assignedToId);
      }

      const emp = employees.find((e) => e.id === assignedToId);
      const assigneeName = emp ? `${emp.first_name} ${emp.last_name}`.trim() : null;
      setTickets((prev) =>
        prev.map((t) =>
          t.id === editTicket.id
            ? { ...t, status: editFields.status, priority: editFields.priority as UITicket['priority'], assignee: assigneeName, assigneeId: assignedToId }
            : t
        )
      );
      toast.success(`Ticket ${editTicket.id} updated.`);
    } catch (err: any) {
      toast.error(err?.message || 'Failed to update ticket.');
    }
    setEditTicket(null);
  };

  const deleteTicket = async (id: string) => {
    const bt = backendTickets.find((t) => t.stf_no === id);
    if (!bt) return;
    try {
      await apiDeleteTicket(bt.id);
      setTickets((prev) => prev.filter((t) => t.id !== id));
      toast.success(`Ticket ${id} deleted.`);
    } catch (err: any) {
      toast.error(err?.message || 'Failed to delete ticket.');
    }
    setOpenMenuId(null);
  };

  const filtered = tickets.filter((t) => {
    if (filterPriority.length > 0 && !filterPriority.includes(t.priority)) return false;
    if (filterStatus.length > 0 && !filterStatus.includes(t.status)) return false;
    if (search && !t.subject.toLowerCase().includes(search.toLowerCase()) && !t.id.toLowerCase().includes(search.toLowerCase()) && !t.client.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const totalPages = Math.max(1, Math.ceil(filtered.length / ITEMS_PER_PAGE));
  const paged = filtered.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);
  const toggleFilter = (arr: string[], val: string) => arr.includes(val) ? arr.filter((v) => v !== val) : [...arr, val];

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#3BC25B]"></div>
        <span className="ml-3 text-gray-500">Loading tickets...</span>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Tickets</h1>
        <p className="text-gray-500 dark:text-gray-400">Manage and assign all tickets</p>
      </div>

      <Card accent>
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
          <div className="relative flex-1 w-full md:max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input value={search} onChange={(e) => { setSearch(e.target.value); setCurrentPage(1); }} type="text" placeholder="Search by ticket ID, subject or client..." className="w-full pl-10 pr-4 py-2 border border-gray-200 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 placeholder-gray-400 dark:placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-[#3BC25B]" />
          </div>
          <button onClick={() => setShowFilter(true)} className="w-full sm:w-auto justify-center flex items-center gap-2 px-4 py-2 border border-gray-200 dark:border-gray-600 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 text-gray-600 dark:text-gray-400 text-sm font-medium">
            <Filter className="w-4 h-4" /> Filter {(filterPriority.length + filterStatus.length > 0) && <span className="bg-[#3BC25B] text-white text-xs rounded-full px-1.5">{filterPriority.length + filterStatus.length}</span>}
          </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full min-w-[800px] text-sm text-left">
            <thead className="text-xs text-gray-500 dark:text-gray-400 uppercase bg-gray-50 dark:bg-gray-700/50 border-b border-gray-100 dark:border-gray-700">
              <tr>
                <th className="px-6 py-4 font-semibold">Ticket Details</th>
                <th className="px-6 py-4 font-semibold">Client</th>
                <th className="px-6 py-4 font-semibold">Priority</th>
                <th className="px-6 py-4 font-semibold">Status</th>
                <th className="px-6 py-4 font-semibold">SLA Timer</th>
                <th className="px-6 py-4 font-semibold min-w-[180px]">Assignee</th>
                <th className="px-6 py-4 font-semibold">Ticket Created by</th>
                <th className="px-6 py-4 font-semibold text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
              {paged.length === 0 && (
                <tr><td colSpan={8} className="px-6 py-12 text-center text-gray-400 dark:text-gray-500">No tickets match your filters.</td></tr>
              )}
              {paged.map((ticket) => (
                <tr key={ticket.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/40 transition-colors">
                  <td className="px-6 py-4">
                    <span className="font-bold text-gray-900 dark:text-white text-xs block mb-1">{ticket.id}</span>
                    <span className="font-medium text-gray-800 dark:text-gray-200 break-all">{truncateText(ticket.subject, 73)}</span>
                  </td>
                  <td className="px-6 py-4 text-gray-600 dark:text-gray-400">{ticket.client}</td>
                  <td className="px-6 py-4"><PriorityBadge priority={ticket.priority} /></td>
                  <td className="px-6 py-4"><StatusBadge status={ticket.status} /></td>
                  <td className="px-6 py-4">
                    {ticket.status === 'Resolved' || ticket.status === 'Closed' ? (
                      <span className="text-xs text-gray-500 dark:text-gray-400">Completed</span>
                    ) : ticket.totalSla === 0 ? (
                      <span className="text-xs text-gray-400 dark:text-gray-500">No SLA</span>
                    ) : (
                      <SLATimer hoursRemaining={ticket.sla} totalHours={ticket.totalSla} status={ticket.status} />
                    )}
                  </td>
                  <td className="px-6 py-4 min-w-[180px]">
                    {ticket.assignee ? (
                      <div className="flex items-center gap-2 min-w-0">
                        <div className="w-6 h-6 aspect-square shrink-0 rounded-full bg-gray-200 dark:bg-gray-600 flex items-center justify-center text-xs text-gray-700 dark:text-gray-300">{ticket.assignee.charAt(0)}</div>
                        <span className="text-gray-600 dark:text-gray-400 whitespace-nowrap">{ticket.assignee}</span>
                      </div>
                    ) : (
                      <span className="text-xs text-gray-400 italic">Unassigned</span>
                    )}
                  </td>
                  <td className="px-6 py-4 text-gray-500 dark:text-gray-400 text-xs">
                    <div className="font-medium text-gray-700 dark:text-gray-200">{ticket.createdBy}</div>
                    <div className="text-[11px] text-gray-400 dark:text-gray-500">{ticket.created}</div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => navigate(`${routeBase}/ticket-details?stf=${ticket.id}`)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200" aria-label="View ticket details"><Eye className="w-5 h-5" /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mt-6 pt-4 border-t border-gray-100 dark:border-gray-700">
          <span className="text-sm text-gray-500 dark:text-gray-400">Showing {filtered.length === 0 ? 0 : (currentPage - 1) * ITEMS_PER_PAGE + 1}-{Math.min(currentPage * ITEMS_PER_PAGE, filtered.length)} of {filtered.length} tickets</span>
          <div className="flex items-center gap-1 flex-wrap justify-end">
            <button onClick={() => setCurrentPage((p) => Math.max(1, p - 1))} disabled={currentPage === 1} className="p-1.5 rounded-lg border border-gray-200 dark:border-gray-600 hover:bg-[#3BC25B] hover:text-white dark:hover:bg-[#3BC25B] text-gray-600 dark:text-gray-400 disabled:opacity-40 disabled:hover:bg-transparent disabled:hover:text-gray-600 transition-colors" aria-label="Previous page"><ChevronLeft className="w-4 h-4" /></button>
            {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
              <button key={page} onClick={() => setCurrentPage(page)} className={`w-8 h-8 rounded-lg text-sm font-medium transition-colors ${currentPage === page ? 'bg-[#3BC25B] text-white shadow-sm' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700'}`} aria-label={`Page ${page}`} aria-current={currentPage === page ? 'page' : undefined}>{page}</button>
            ))}
            <button onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="p-1.5 rounded-lg border border-gray-200 dark:border-gray-600 hover:bg-[#3BC25B] hover:text-white dark:hover:bg-[#3BC25B] text-gray-600 dark:text-gray-400 disabled:opacity-40 disabled:hover:bg-transparent disabled:hover:text-gray-600 transition-colors" aria-label="Next page"><ChevronRightIcon className="w-4 h-4" /></button>
          </div>
        </div>
      </Card>

      {/* Edit Ticket Modal */}
      {editTicket && createPortal(
        <div className="fixed inset-0 z-[9999] bg-black/50 flex items-center justify-center p-4" onClick={() => setEditTicket(null)}>
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-sm p-6" onClick={(e) => e.stopPropagation()}>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white">Edit Ticket</h3>
              <button onClick={() => setEditTicket(null)} className="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg" aria-label="Close edit modal"><X className="w-4 h-4 text-gray-500" /></button>
            </div>
            <p className="text-xs font-mono text-[#0E8F79] dark:text-green-400 bg-gray-50 dark:bg-gray-700/50 rounded px-2 py-1 mb-4">{editTicket.id}</p>
            <p className="text-sm text-gray-700 dark:text-gray-300 font-medium mb-4 truncate">{editTicket.subject}</p>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Status</label>
                <select value={editFields.status} onChange={(e) => setEditFields((p) => ({ ...p, status: e.target.value }))} className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-[#3BC25B] outline-none">
                  {STATUSES.map((s) => <option key={s}>{s}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Priority</label>
                <select value={editFields.priority} onChange={(e) => setEditFields((p) => ({ ...p, priority: e.target.value }))} className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-[#3BC25B] outline-none">
                  {PRIORITIES.map((p) => <option key={p}>{p}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Assignee</label>
                {editTicket && !['Pending', 'Assigned', 'Escalated'].includes(editTicket.status) ? (
                  <>
                    <select disabled className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-sm bg-gray-100 dark:bg-gray-700 text-gray-500 dark:text-gray-400 cursor-not-allowed outline-none">
                      <option>{editTicket.assignee || 'Unassigned'}</option>
                    </select>
                    <p className="text-xs text-amber-600 dark:text-amber-400 mt-1">Cannot reassign after the employee has started working.</p>
                  </>
                ) : (
                  <select value={editFields.assigneeId} onChange={(e) => setEditFields((p) => ({ ...p, assigneeId: e.target.value }))} className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-[#3BC25B] outline-none">
                    <option value="">Unassigned</option>
                    {employees.map((emp) => <option key={emp.id} value={emp.id}>{emp.first_name} {emp.last_name}</option>)}
                  </select>
                )}
              </div>
            </div>
            <div className="flex gap-3 mt-5">
              <button onClick={() => setEditTicket(null)} className="flex-1 px-4 py-2 border border-gray-200 dark:border-gray-600 text-sm text-gray-600 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors">Cancel</button>
              <button onClick={saveEdit} className="flex-1 px-4 py-2 bg-[#3BC25B] hover:bg-[#2ea34a] text-white text-sm font-medium rounded-lg transition-colors">Save Changes</button>
            </div>
          </div>
        </div>
      , document.body)}

      {/* Filter Modal */}
      {showFilter && createPortal(
        <div className="fixed inset-0 z-[9999] bg-black/50 flex items-center justify-center p-4" onClick={() => setShowFilter(false)}>
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-md p-6" onClick={(e) => e.stopPropagation()}>
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white">Filter Tickets</h3>
              <button onClick={() => setShowFilter(false)} className="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg" aria-label="Close filter modal"><X className="w-5 h-5 text-gray-500" /></button>
            </div>
            <div className="space-y-5">
              <div>
                <h4 className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-3">Priority</h4>
                <div className="flex flex-wrap gap-2">
                  {PRIORITIES.map((p) => (
                    <button key={p} onClick={() => setFilterPriority((prev) => toggleFilter(prev, p))} className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${filterPriority.includes(p) ? 'bg-[#0E8F79] text-white border-[#0E8F79]' : 'bg-white dark:bg-gray-700 text-gray-600 dark:text-gray-300 border-gray-200 dark:border-gray-600 hover:border-[#0E8F79]/50'}`}>{p}</button>
                  ))}
                </div>
              </div>
              <div>
                <h4 className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-3">Status</h4>
                <div className="flex flex-wrap gap-2">
                  {STATUSES.map((s) => (
                    <button key={s} onClick={() => setFilterStatus((prev) => toggleFilter(prev, s))} className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${filterStatus.includes(s) ? 'bg-[#0E8F79] text-white border-[#0E8F79]' : 'bg-white dark:bg-gray-700 text-gray-600 dark:text-gray-300 border-gray-200 dark:border-gray-600 hover:border-[#0E8F79]/50'}`}>{s}</button>
                  ))}
                </div>
              </div>
            </div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => { setFilterPriority([]); setFilterStatus([]); }} className="flex-1 px-4 py-2 rounded-lg border border-gray-200 dark:border-gray-600 text-sm font-medium text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700">Clear All</button>
              <button onClick={() => { setCurrentPage(1); setShowFilter(false); }} className="flex-1 px-4 py-2 rounded-lg bg-[#3BC25B] hover:bg-[#2ea34a] text-white text-sm font-medium">Apply Filters</button>
            </div>
          </div>
        </div>
      , document.body)}
    </div>
  );
}

﻿import React, { useState, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { Card } from '../../components/ui/Card';
import { GreenButton } from '../../components/ui/GreenButton';
import {
  Search,
  Plus,
  Eye,
  Edit2,
  Trash2,
  X,
  Loader2,
  RefreshCw,
  Settings2,
} from 'lucide-react';
import { toast } from 'sonner';
import {
  fetchTypesOfService,
  createTypeOfService,
  updateTypeOfService,
  deleteTypeOfService,
  type TypeOfService,
} from '../../services/api';

const ITEMS_PER_PAGE = 10;

export default function TypesOfService() {
  const [services, setServices] = useState<TypeOfService[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Active' | 'Inactive'>('All');
  const [currentPage, setCurrentPage] = useState(1);

  // Modal state
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingService, setEditingService] = useState<TypeOfService | null>(null);
  const [formData, setFormData] = useState({ name: '', description: '', is_active: true, estimated_resolution_days: 0 });
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});

  // Delete confirmation state
  const [deleteTarget, setDeleteTarget] = useState<TypeOfService | null>(null);
  const [viewingService, setViewingService] = useState<TypeOfService | null>(null);

  // ── Load services ──
  const loadServices = useCallback(async () => {
    try {
      setLoading(true);
      const data = await fetchTypesOfService();
      setServices(data);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Failed to fetch types of service.';
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadServices();
  }, [loadServices]);

  // ── Filtering ──
  const filtered = services.filter((s) => {
    const matchesStatus =
      statusFilter === 'All' ||
      (statusFilter === 'Active' && s.is_active) ||
      (statusFilter === 'Inactive' && !s.is_active);
    const matchesSearch =
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      s.description.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const totalPages = Math.max(1, Math.ceil(filtered.length / ITEMS_PER_PAGE));
  const paged = filtered.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  // ── Modal helpers ──
  const openAddModal = () => {
    setEditingService(null);
    setFormData({ name: '', description: '', is_active: true, estimated_resolution_days: 0 });
    setFieldErrors({});
    setIsModalOpen(true);
  };

  const openEditModal = (service: TypeOfService) => {
    setEditingService(service);
    setFormData({
      name: service.name,
      description: service.description,
      is_active: service.is_active,
      estimated_resolution_days: service.estimated_resolution_days || 0,
    });
    setFieldErrors({});
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingService(null);
    setFieldErrors({});
  };

  const validate = (): boolean => {
    const errors: Record<string, string> = {};
    if (!formData.name.trim()) errors.name = 'Name is required.';
    else if (formData.name.trim().length > 200) errors.name = 'Name must be at most 200 characters.';
    setFieldErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setSubmitting(true);
    try {
      if (editingService) {
        const updated = await updateTypeOfService(editingService.id, {
          name: formData.name.trim(),
          description: formData.description.trim(),
          is_active: formData.is_active,
          estimated_resolution_days: formData.estimated_resolution_days,
        });
        setServices((prev) =>
          prev.map((s) => (s.id === updated.id ? updated : s))
        );
        toast.success(`"${updated.name}" updated successfully.`);
      } else {
        const created = await createTypeOfService({
          name: formData.name.trim(),
          description: formData.description.trim(),
          estimated_resolution_days: formData.estimated_resolution_days,
        } as any);
        setServices((prev) => [...prev, created]);
        toast.success(`"${created.name}" created successfully.`);
      }
      closeModal();
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Failed to save type of service.';
      toast.error(msg);
    } finally {
      setSubmitting(false);
    }
  };

  // ── Delete ──
  const confirmDelete = async () => {
    if (!deleteTarget) return;
    setSubmitting(true);
    try {
      await deleteTypeOfService(deleteTarget.id);
      setServices((prev) => prev.filter((s) => s.id !== deleteTarget.id));
      toast.success(`"${deleteTarget.name}" deleted.`);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Failed to delete type of service.';
      toast.error(msg);
    } finally {
      setSubmitting(false);
      setDeleteTarget(null);
    }
  };

  // ── Toggle active ──
  const toggleActive = async (service: TypeOfService) => {
    try {
      const updated = await updateTypeOfService(service.id, {
        is_active: !service.is_active,
      });
      setServices((prev) =>
        prev.map((s) => (s.id === updated.id ? updated : s))
      );
      toast.success(`"${updated.name}" ${updated.is_active ? 'activated' : 'deactivated'}.`);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : 'Failed to update status.';
      toast.error(msg);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#3BC25B]"></div>
        <span className="ml-3 text-gray-500 dark:text-gray-400">Loading types of service...</span>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Types of Service</h1>
          <p className="text-gray-500 dark:text-gray-400">Manage the service types available for tickets</p>
        </div>
        <div className="flex gap-2">
          <GreenButton variant="outline" onClick={loadServices} disabled={loading}>
            <RefreshCw className={`w-4 h-4 mr-2 ${loading ? 'animate-spin' : ''}`} /> Refresh
          </GreenButton>
          <GreenButton onClick={openAddModal}>
            <Plus className="w-4 h-4 mr-2" /> Add Service Type
          </GreenButton>
        </div>
      </div>

      {/* Table Card */}
      <Card accent>
        {/* Search & Filter Bar */}
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4 p-6 pb-0">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              value={searchTerm}
              onChange={(e) => { setSearchTerm(e.target.value); setCurrentPage(1); }}
              type="text"
              placeholder="Search by name or description..."
              className="w-full pl-10 pr-4 py-2 border border-gray-200 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 placeholder-gray-400 dark:placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-[#3BC25B]"
            />
          </div>
          <div className="flex gap-2">
            {(['All', 'Active', 'Inactive'] as const).map((s) => (
              <button
                key={s}
                onClick={() => { setStatusFilter(s); setCurrentPage(1); }}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                  statusFilter === s
                    ? 'bg-[#3BC25B] text-white'
                    : 'bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto px-6 pb-6">
          <table className="w-full text-sm text-left">
            <thead>
              <tr className="text-gray-500 dark:text-gray-400 border-b border-gray-100 dark:border-gray-700">
                <th className="pb-3 font-medium">Name</th>
                <th className="pb-3 font-medium">Description</th>
                <th className="pb-3 font-medium text-center">Est. Days</th>
                <th className="pb-3 font-medium text-center">Status</th>
                <th className="pb-3 font-medium text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50 dark:divide-gray-700">
              {paged.length === 0 ? (
                <tr>
                  <td colSpan={5} className="py-12 text-center text-gray-400 dark:text-gray-500">
                    <Settings2 className="w-10 h-10 mx-auto mb-2 opacity-30" />
                    No types of service found.
                  </td>
                </tr>
              ) : (
                paged.map((service) => (
                  <tr key={service.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
                    <td className="py-3 font-medium text-gray-900 dark:text-white">{service.name}</td>
                    <td className="py-3 text-gray-600 dark:text-gray-300 max-w-xs truncate">
                      {service.description || <span className="text-gray-400 italic">—</span>}
                    </td>
                    <td className="py-3 text-center text-gray-600 dark:text-gray-300">
                      {service.estimated_resolution_days ? `${service.estimated_resolution_days}d` : '—'}
                    </td>
                    <td className="py-3 text-center">
                      <button
                        onClick={() => toggleActive(service)}
                        className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium cursor-pointer transition-colors ${
                          service.is_active
                            ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400 hover:bg-green-200 dark:hover:bg-green-900/50'
                            : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400 hover:bg-red-200 dark:hover:bg-red-900/50'
                        }`}
                        title={`Click to ${service.is_active ? 'deactivate' : 'activate'}`}
                      >
                        {service.is_active ? 'Active' : 'Inactive'}
                      </button>
                    </td>
                    <td className="py-3 text-right">
                      <div className="flex items-center justify-end gap-2">
                        <button
                          onClick={() => setViewingService(service)}
                          className="p-1.5 rounded-lg text-gray-400 hover:text-[#0E8F79] hover:bg-green-50 dark:hover:bg-green-900/20 transition-colors"
                          title="View"
                        >
                          <Eye className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => openEditModal(service)}
                          className="p-1.5 rounded-lg text-gray-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 transition-colors"
                          title="Edit"
                        >
                          <Edit2 className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => setDeleteTarget(service)}
                          className="p-1.5 rounded-lg text-gray-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                          title="Delete"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between px-6 pb-6 text-sm text-gray-500 dark:text-gray-400">
            <span>
              Showing {(currentPage - 1) * ITEMS_PER_PAGE + 1}–{Math.min(currentPage * ITEMS_PER_PAGE, filtered.length)} of {filtered.length}
            </span>
            <div className="flex gap-1">
              <button
                disabled={currentPage === 1}
                onClick={() => setCurrentPage((p) => p - 1)}
                className="px-3 py-1 rounded-lg border border-gray-200 dark:border-gray-600 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-40"
              >
                Previous
              </button>
              {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
                <button
                  key={page}
                  onClick={() => setCurrentPage(page)}
                  className={`px-3 py-1 rounded-lg ${
                    page === currentPage
                      ? 'bg-[#3BC25B] text-white'
                      : 'border border-gray-200 dark:border-gray-600 hover:bg-gray-50 dark:hover:bg-gray-700'
                  }`}
                >
                  {page}
                </button>
              ))}
              <button
                disabled={currentPage === totalPages}
                onClick={() => setCurrentPage((p) => p + 1)}
                className="px-3 py-1 rounded-lg border border-gray-200 dark:border-gray-600 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-40"
              >
                Next
              </button>
            </div>
          </div>
        )}
      </Card>

      {/* ── Add / Edit Modal ── */}
      {isModalOpen && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/50 p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-xl w-full max-w-lg relative">
            {/* Header */}
            <div className="flex items-center justify-between p-6 border-b border-gray-100 dark:border-gray-700">
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
                {editingService ? 'Edit Service Type' : 'Add Service Type'}
              </h2>
              <button onClick={closeModal} className="p-1 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                <X className="w-5 h-5 text-gray-500" />
              </button>
            </div>

            {/* Form */}
            <form onSubmit={handleSave} className="p-6 space-y-4">
              {/* Name */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Name <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  maxLength={200}
                  className={`w-full px-3 py-2 border rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:outline-none focus:ring-2 focus:ring-[#3BC25B] ${
                    fieldErrors.name ? 'border-red-400' : 'border-gray-200 dark:border-gray-600'
                  }`}
                  placeholder="e.g. Hardware Repair"
                  autoFocus
                />
                {fieldErrors.name && (
                  <p className="mt-1 text-xs text-red-500">{fieldErrors.name}</p>
                )}
              </div>

              {/* Description */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Description</label>
                <textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  rows={3}
                  className="w-full px-3 py-2 border border-gray-200 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:outline-none focus:ring-2 focus:ring-[#3BC25B] resize-none"
                  placeholder="Optional description of this service type..."
                />
              </div>

              {/* Estimated Resolution Days */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Estimated Resolution Days
                </label>
                <input
                  type="number"
                  min={0}
                  value={formData.estimated_resolution_days}
                  onChange={(e) => setFormData({ ...formData, estimated_resolution_days: Math.max(0, parseInt(e.target.value) || 0) })}
                  className="w-full px-3 py-2 border border-gray-200 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:outline-none focus:ring-2 focus:ring-[#3BC25B]"
                  placeholder="e.g. 5"
                />
                <p className="mt-1 text-xs text-gray-400 dark:text-gray-500">
                  SLA basis: estimated number of days to resolve tickets of this type. Set 0 for no SLA.
                </p>
              </div>

              {/* Active toggle (only when editing) */}
              {editingService && (
                <div className="flex items-center gap-3">
                  <label className="relative inline-flex items-center cursor-pointer">
                    <input
                      type="checkbox"
                      checked={formData.is_active}
                      onChange={(e) => setFormData({ ...formData, is_active: e.target.checked })}
                      className="sr-only peer"
                    />
                    <div className="w-9 h-5 bg-gray-200 peer-focus:outline-none peer-focus:ring-2 peer-focus:ring-[#3BC25B] dark:peer-focus:ring-[#3BC25B] rounded-full peer dark:bg-gray-600 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all dark:border-gray-600 peer-checked:bg-[#3BC25B]"></div>
                  </label>
                  <span className="text-sm font-medium text-gray-700 dark:text-gray-300">Active</span>
                </div>
              )}

              {/* Footer */}
              <div className="flex justify-end gap-3 pt-4 border-t border-gray-100 dark:border-gray-700">
                <GreenButton type="button" variant="outline" onClick={closeModal} disabled={submitting}>
                  Cancel
                </GreenButton>
                <GreenButton type="submit" isLoading={submitting} disabled={submitting}>
                  {editingService ? 'Save Changes' : 'Create'}
                </GreenButton>
              </div>
            </form>
          </div>
        </div>,
        document.body
      )}

      {/* View Modal */}
      {viewingService && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/50 p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-xl w-full max-w-lg relative">
            <div className="flex items-center justify-between p-6 border-b border-gray-100 dark:border-gray-700">
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Service Type Details</h2>
              <button onClick={() => setViewingService(null)} className="p-1 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors">
                <X className="w-5 h-5 text-gray-500" />
              </button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <p className="text-xs font-semibold uppercase text-gray-500 dark:text-gray-400">Name</p>
                <p className="text-sm text-gray-900 dark:text-white mt-1">{viewingService.name || '—'}</p>
              </div>
              <div>
                <p className="text-xs font-semibold uppercase text-gray-500 dark:text-gray-400">Description</p>
                <p className="text-sm text-gray-900 dark:text-white mt-1 whitespace-pre-wrap">{viewingService.description || '—'}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-xs font-semibold uppercase text-gray-500 dark:text-gray-400">Estimated Days</p>
                  <p className="text-sm text-gray-900 dark:text-white mt-1">{viewingService.estimated_resolution_days ?? 0}</p>
                </div>
                <div>
                  <p className="text-xs font-semibold uppercase text-gray-500 dark:text-gray-400">Status</p>
                  <p className="text-sm text-gray-900 dark:text-white mt-1">{viewingService.is_active ? 'Active' : 'Inactive'}</p>
                </div>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Delete Confirmation Modal ── */}
      {deleteTarget && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/50 p-4">
          <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-xl w-full max-w-sm p-6">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">Delete Service Type</h3>
            <p className="text-sm text-gray-600 dark:text-gray-300 mb-6">
              Are you sure you want to delete <strong>"{deleteTarget.name}"</strong>? Tickets using this service type will have it cleared.
            </p>
            <div className="flex justify-end gap-3">
              <GreenButton variant="outline" onClick={() => setDeleteTarget(null)} disabled={submitting}>
                Cancel
              </GreenButton>
              <button
                onClick={confirmDelete}
                disabled={submitting}
                className="inline-flex items-center justify-center rounded-lg font-medium px-4 py-2.5 text-sm bg-red-600 text-white hover:bg-red-700 disabled:opacity-50 transition-colors"
              >
                {submitting ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Trash2 className="w-4 h-4 mr-2" />}
                Delete
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card } from '../../components/ui/Card';
import { StatCard } from '../../components/ui/StatCard';
import { StatusBadge } from '../../components/ui/StatusBadge';
import { PriorityBadge } from '../../components/ui/PriorityBadge';
import {
  Ticket,
  Clock,
  CheckCircle2,
  AlertTriangle,
  Users,
  Package,
  PlusCircle,
  ChevronRight,
  Search,
  RefreshCw,
} from 'lucide-react';
import { toast } from 'sonner';
import { AnnouncementBanner } from '../../components/ui/AnnouncementBanner';
import { fetchTickets, fetchClients, fetchProducts } from '../../services/api';
import type { BackendTicket } from '../../services/api';
import { mapBackendTicketToUI } from '../../services/ticketMapper';
import type { UITicket } from '../../services/ticketMapper';

const ITEMS_PER_PAGE = 5;

function truncateText(value: string | undefined | null, maxLength: number): string {
  if (!value) return '';
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength)}...`;
}

export default function SalesDashboard() {
  const navigate = useNavigate();
  const [tickets, setTickets] = useState<UITicket[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [stats, setStats] = useState({
    totalTickets: 0,
    pendingTickets: 0,
    resolvedTickets: 0,
    escalatedTickets: 0,
    totalClients: 0,
    totalProducts: 0,
  });

  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [ticketsData, clientsData, productsData] = await Promise.all([
        fetchTickets(),
        fetchClients().catch(() => []),
        fetchProducts().catch(() => []),
      ]);

      const mapped = ticketsData.map(mapBackendTicketToUI);
      setTickets(mapped);

      // Calculate stats
      const pending = mapped.filter(t => ['Pending', 'Assigned', 'In Progress'].includes(t.status)).length;
      const resolved = mapped.filter(t => ['Resolved', 'Closed'].includes(t.status)).length;
      const escalated = mapped.filter(t => t.status === 'Escalated').length;

      setStats({
        totalTickets: mapped.length,
        pendingTickets: pending,
        resolvedTickets: resolved,
        escalatedTickets: escalated,
        totalClients: Array.isArray(clientsData) ? clientsData.length : 0,
        totalProducts: Array.isArray(productsData) ? productsData.length : 0,
      });
    } catch (err) {
      console.error('Failed to load dashboard data:', err);
      setError('Failed to load dashboard data. Please try again.');
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  // Filter tickets by search
  const filteredTickets = tickets.filter(t => {
    if (!searchQuery) return true;
    const q = searchQuery.toLowerCase();
    return (
      t.id.toLowerCase().includes(q) ||
      t.client.toLowerCase().includes(q) ||
      t.subject.toLowerCase().includes(q)
    );
  });

  // Get recent tickets (last 5)
  const recentTickets = filteredTickets.slice(0, ITEMS_PER_PAGE);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#3BC25B]"></div>
        <span className="ml-3 text-gray-500 dark:text-gray-400">Loading dashboard...</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-64 space-y-4">
        <AlertTriangle className="w-12 h-12 text-red-500" />
        <p className="text-gray-600 dark:text-gray-400">{error}</p>
        <button
          onClick={loadData}
          className="flex items-center gap-2 px-4 py-2 bg-[#3BC25B] text-white rounded-lg hover:bg-[#33a34d] transition-colors"
        >
          <RefreshCw className="w-4 h-4" />
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <AnnouncementBanner />

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Sales Dashboard</h1>
          <p className="text-gray-500 dark:text-gray-400">Overview of tickets, clients, and products</p>
        </div>
        <button
          onClick={() => navigate('/sales/create-ticket')}
          className="flex items-center gap-2 px-4 py-2 bg-[#3BC25B] text-white rounded-lg hover:bg-[#33a34d] transition-colors"
        >
          <PlusCircle className="w-4 h-4" />
          Create Ticket
        </button>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
        <StatCard
          title="Total Tickets"
          value={stats.totalTickets}
          icon={Ticket}
          trend={null}
        />
        <StatCard
          title="Pending"
          value={stats.pendingTickets}
          icon={Clock}
          trend={null}
        />
        <StatCard
          title="Resolved"
          value={stats.resolvedTickets}
          icon={CheckCircle2}
          trend={null}
        />
        <StatCard
          title="Escalated"
          value={stats.escalatedTickets}
          icon={AlertTriangle}
          trend={null}
        />
        <StatCard
          title="Clients"
          value={stats.totalClients}
          icon={Users}
          trend={null}
        />
        <StatCard
          title="Products"
          value={stats.totalProducts}
          icon={Package}
          trend={null}
        />
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card
          className="cursor-pointer hover:border-[#3BC25B] transition-colors"
          onClick={() => navigate('/sales/tickets')}
        >
          <div className="flex items-center justify-between p-4">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center">
                <Ticket className="w-5 h-5 text-blue-600 dark:text-blue-400" />
              </div>
              <div>
                <p className="font-medium text-gray-900 dark:text-white">View All Tickets</p>
                <p className="text-sm text-gray-500 dark:text-gray-400">Browse and manage tickets</p>
              </div>
            </div>
            <ChevronRight className="w-5 h-5 text-gray-400" />
          </div>
        </Card>

        <Card
          className="cursor-pointer hover:border-[#3BC25B] transition-colors"
          onClick={() => navigate('/sales/clients')}
        >
          <div className="flex items-center justify-between p-4">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-green-100 dark:bg-green-900/30 flex items-center justify-center">
                <Users className="w-5 h-5 text-green-600 dark:text-green-400" />
              </div>
              <div>
                <p className="font-medium text-gray-900 dark:text-white">Manage Clients</p>
                <p className="text-sm text-gray-500 dark:text-gray-400">View and edit client info</p>
              </div>
            </div>
            <ChevronRight className="w-5 h-5 text-gray-400" />
          </div>
        </Card>

        <Card
          className="cursor-pointer hover:border-[#3BC25B] transition-colors"
          onClick={() => navigate('/sales/products')}
        >
          <div className="flex items-center justify-between p-4">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-purple-100 dark:bg-purple-900/30 flex items-center justify-center">
                <Package className="w-5 h-5 text-purple-600 dark:text-purple-400" />
              </div>
              <div>
                <p className="font-medium text-gray-900 dark:text-white">Product Catalog</p>
                <p className="text-sm text-gray-500 dark:text-gray-400">Browse products</p>
              </div>
            </div>
            <ChevronRight className="w-5 h-5 text-gray-400" />
          </div>
        </Card>
      </div>

      {/* Recent Tickets */}
      <Card>
        <div className="p-4 border-b border-gray-200 dark:border-gray-700">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Recent Tickets</h2>
            <div className="flex items-center gap-2">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search tickets..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-9 pr-4 py-2 text-sm border border-gray-200 dark:border-gray-700 rounded-lg bg-white dark:bg-gray-800 text-gray-900 dark:text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#3BC25B]"
                />
              </div>
              <button
                onClick={() => navigate('/sales/tickets')}
                className="text-sm text-[#3BC25B] hover:text-[#33a34d] font-medium"
              >
                View All
              </button>
            </div>
          </div>
        </div>

        {recentTickets.length === 0 ? (
          <div className="p-8 text-center">
            <Ticket className="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-3" />
            <p className="text-gray-500 dark:text-gray-400">
              {searchQuery ? 'No tickets match your search' : 'No tickets yet'}
            </p>
            <button
              onClick={() => navigate('/sales/create-ticket')}
              className="mt-4 text-sm text-[#3BC25B] hover:text-[#33a34d] font-medium"
            >
              Create your first ticket
            </button>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full min-w-[640px]">
              <thead>
                <tr className="bg-gray-50 dark:bg-gray-800/50">
                  <th scope="col" className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase">
                    Ticket ID
                  </th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase">
                    Client
                  </th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase">
                    Subject
                  </th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase">
                    Status
                  </th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase">
                    Priority
                  </th>
                  <th scope="col" className="px-4 py-3 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase">
                    Created
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                {recentTickets.map((ticket) => (
                  <tr
                    key={ticket.id}
                    className="hover:bg-gray-50 dark:hover:bg-gray-800/50 cursor-pointer transition-colors"
                    onClick={() => navigate(`/sales/ticket-details?stf=${encodeURIComponent(ticket.id)}`)}
                  >
                    <td className="px-4 py-3">
                      <span className="font-medium text-gray-900 dark:text-white">{ticket.id}</span>
                    </td>
                    <td className="px-4 py-3 text-gray-600 dark:text-gray-300">
                      {truncateText(ticket.client, 20)}
                    </td>
                    <td className="px-4 py-3 text-gray-600 dark:text-gray-300">
                      {truncateText(ticket.subject, 30)}
                    </td>
                    <td className="px-4 py-3">
                      <StatusBadge status={ticket.status} />
                    </td>
                    <td className="px-4 py-3">
                      <PriorityBadge priority={ticket.priority} />
                    </td>
                    <td className="px-4 py-3 text-sm text-gray-500 dark:text-gray-400">
                      {new Date(ticket.created).toLocaleDateString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Card>
    </div>
  );
}

