  const [activeTicketCall, setActiveTicketCall] = useState<CallLog | null>(null);

  // Show reassign when: ticket is Escalated (admin handles escalation),
  // OR the employee hasn't clicked Start Work yet (time_in is null),
  // OR the admin themselves is currently assigned (admin started work and wants to hand off).
  const canAdminReassign = isAdmin &&
    !['Resolved', 'Closed', 'Unresolved'].includes(ticket.status) && (
      ticket.status === 'Escalated' ||
      !btData?.time_in ||
      btData?.assigned_to?.id === user?.id
    );
  const needsCallPriorityWorkflow = isAdmin && !!btData && !btData.confirmed_by_admin && !btData.priority && ticket.status !== 'Closed';
  const canSalesCallWorkflow = isSales && !!btData && !btData.confirmed_by_admin && !btData.priority && btData.created_by?.id === user?.id && ticket.status !== 'Closed';
  const hasCallPriorityWorkflow = needsCallPriorityWorkflow || canSalesCallWorkflow;
  const canSetPriorityInCallWorkflow = isAdmin || canSalesCallWorkflow;

  const filteredEmployees = [...employees]
    .sort((a, b) => a.active_ticket_count - b.active_ticket_count)
    .filter((emp) => {
      const query = reassignSearch.trim().toLowerCase();
      if (!query) return true;
      const fullName = `${emp.first_name} ${emp.last_name}`.trim().toLowerCase();
      const reverseFullName = `${emp.last_name} ${emp.first_name}`.trim().toLowerCase();
      const username = emp.username.toLowerCase();
      return fullName.includes(query) || reverseFullName.includes(query) || username.includes(query);
    });

  useEffect(() => {
    if (!callStartTime || callCompleted || callOnHold) return;
    const interval = setInterval(() => {
      const elapsed = Date.now() - callStartTime.getTime() - holdOffset;
      setCallTimer(Math.max(0, Math.floor(elapsed / 1000)));
    }, 1000);
    return () => clearInterval(interval);
  }, [callStartTime, callCompleted, callOnHold, holdOffset]);

  const formatCallDuration = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
  };

  const resetCallAndPriorityState = () => {
    setPriorityLevel('');
    setCallLogId(null);
    setCallStartTime(null);
    setCallTimer(0);
    setCallCompleted(false);
    setCallOnHold(false);
    setHoldStartTime(null);
    setHoldOffset(0);
    setReassignModalStep('assign');
  };

  const openReassignModal = () => {
    setShowReassignModal(true);
    setReassignSearch('');
    setReassignEmployeeId('');
    if (hasCallPriorityWorkflow) {
      resetCallAndPriorityState();
      setReassignModalStep('stf-details');
    } else {
      setReassignModalStep('assign');
    }
  };

  const refreshActiveCallStatus = useCallback(async () => {
    if (!backendTicketId || !showReassignModal || !hasCallPriorityWorkflow) return;
    try {
      const activeCalls = await fetchCallLogs({ ticketId: backendTicketId, activeOnly: true });
      setActiveTicketCall(activeCalls[0] || null);
    } catch {
      setActiveTicketCall(null);
    }
  }, [backendTicketId, showReassignModal, hasCallPriorityWorkflow]);

  useEffect(() => {
    if (!showReassignModal || !hasCallPriorityWorkflow) {
      setActiveTicketCall(null);
      return;
    }
    void refreshActiveCallStatus();
    const timer = setInterval(() => {
      void refreshActiveCallStatus();
    }, 5000);
    return () => clearInterval(timer);
  }, [showReassignModal, hasCallPriorityWorkflow, refreshActiveCallStatus]);

  const handleStartCall = async () => {
    if (!backendTicketId || !btData) return;
    if (activeTicketCall && activeTicketCall.admin !== user?.id) {
      toast.error(`Call already in progress by ${activeTicketCall.admin_name || 'another user'}.`);
      return;
    }
    setCallCompleted(false);
    setCallTimer(0);
    setCallOnHold(false);
    setHoldStartTime(null);
    setHoldOffset(0);
    try {
      const log = await createCallLog({
        ticket: backendTicketId,
        client_name: btData.client || ticket.client || 'Client',
        phone_number: btData.mobile_no || btData.landline || '',
        call_start: new Date().toISOString(),
      });
      setCallLogId(log.id);
      setCallStartTime(new Date(log.call_start));
      setActiveTicketCall(log);
      setReassignModalStep('ongoing');
    } catch (err: any) {
      toast.error(err?.message || 'Failed to start call log.');
    }
  };

  const handleEndCall = async () => {
    if (callLogId) {
      try {
        await endCallLog(callLogId, { call_end: new Date().toISOString() });
      } catch {
        // Keep UI flow moving even if logging fails.
      }
    }
    if (callOnHold && holdStartTime) {
      setHoldOffset((prev) => prev + (Date.now() - holdStartTime));
      setHoldStartTime(null);
      setCallOnHold(false);
    }
    setCallStartTime(null);
    setCallCompleted(true);
    setActiveTicketCall(null);
    setReassignModalStep('stf-details');
  };

  const handleConfirmPriority = () => {
    if (!callCompleted) {
      toast.error('Please complete the client call before assigning an employee.');
      return;
    }
    if (!priorityLevel) {
      toast.error('Please select a priority level before assigning an employee.');
      return;
    }
    setReassignModalStep('assign');
  };

  const handleSubmitSalesCallStatus = async () => {
    if (!backendTicketId) return;
    if (!callCompleted) {
      toast.error('Please complete the client call before saving priority.');
      return;
    }
    if (!priorityLevel) {
      toast.error('Please select a priority level before saving call status.');
      return;
    }

    setSubmittingSalesCallStatus(true);
    try {
      await reviewTicket(backendTicketId, {
        priority: reverseMapPriority(priorityLevel),
      });
      const updated = await confirmTicket(backendTicketId);
      setBtData(updated);

      toast.success('Call status saved. Ticket is now ready for supervisor assignment.');
      setShowReassignModal(false);
      setReassignSearch('');
      setReassignEmployeeId('');
      resetCallAndPriorityState();
    } catch (err: any) {
      toast.error(err?.message || 'Failed to save call status.');
    } finally {
      setSubmittingSalesCallStatus(false);
    }
  };

  useEffect(() => {
    if (!canAdminReassign) return;
    let cancelled = false;

    (async () => {
      try {
        const [employeeData, allTickets] = await Promise.all([fetchEmployees(), fetchTickets()]);
        if (cancelled) return;
        setEmployees(employeeData);

        const activeByEmployee: Record<number, BackendTicket[]> = {};
        for (const t of allTickets) {
          const assigneeId = t.assigned_to?.id;
          if (!assigneeId) continue;
          const status = String(t.status || '').toLowerCase();
          if (['resolved', 'closed', 'unresolved'].includes(status)) continue;
          if (!activeByEmployee[assigneeId]) activeByEmployee[assigneeId] = [];
          activeByEmployee[assigneeId].push(t);
        }
        setEmployeeTickets(activeByEmployee);
      } catch {
        if (!cancelled) {
          setEmployees([]);
          setEmployeeTickets({});
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [canAdminReassign]);

  // ── Escalation modal state ──
  const [showEscalateModal, setShowEscalateModal] = useState(false);
  const [escalateType, setEscalateType] = useState<'internal' | 'external'>('internal');
  const [escalateNotes, setEscalateNotes] = useState('');
  const [escalateTo, setEscalateTo] = useState('');
  const [escalateNotesErr, setEscalateNotesErr] = useState('');
  const [escalateToErr, setEscalateToErr] = useState('');
  const [submittingEscalation, setSubmittingEscalation] = useState(false);

