      const jobStatusValue = ticket.jobStatus || 'N/A';
      const signatureValue = ticket.signature ? 'Attached' : 'N/A';
      const signedByValue = ticket.signedByName || 'N/A';

      // Color palette
      const C = {
        GREEN_DARK: '154734', GREEN_MID: '2FAD52', GREEN_PALE: 'E8FAF0',
        GREEN_TEXT: '065F46', WHITE: 'FFFFFF', ALT_ROW: 'F0FDF4', BORDER_CLR: 'D1FAE5',
      };

      const STATUS_COLORS: Record<string, [string, string]> = {
        New: ['DBEAFE', '1D4ED8'], Pending: ['FEF9C3', 'A16207'], Assigned: ['EDE9FE', '6D28D9'],
        'In Progress': ['CCFBF1', '0F766E'], Escalated: ['FFEDD5', 'C2410C'],
        Resolved: ['DCFCE7', '166534'], Closed: ['F3F4F6', '000000'],
        'For Observation': ['E0F2FE', '0369A1'], Unresolved: ['FEE2E2', 'DC2626'],
      };

      const PRIORITY_COLORS: Record<string, [string, string]> = {
        Critical: ['FEE2E2', 'DC2626'], High: ['FFEDD5', 'C2410C'],
        Medium: ['FEF9C3', 'A16207'], Low: ['DCFCE7', '166534'],
      };

      // Style helpers
      const THIN = (clr = C.BORDER_CLR) => ({ style: 'thin' as const, color: { rgb: clr } });
      const allBorders = (clr = C.BORDER_CLR) => ({ top: THIN(clr), bottom: THIN(clr), left: THIN(clr), right: THIN(clr) });

      type CellOpts = { bold?: boolean; italic?: boolean; sz?: number; center?: boolean; wrap?: boolean; border?: boolean };
      const cellStyle = (bg: string, fg: string, opts?: CellOpts) => ({
        fill: { fgColor: { rgb: bg } },
        font: { name: 'Calibri', sz: opts?.sz ?? 11, color: { rgb: fg }, bold: !!opts?.bold, italic: !!opts?.italic },
        alignment: { horizontal: opts?.center ? 'center' : 'left', vertical: 'center', wrapText: !!opts?.wrap },
        ...(opts?.border !== false ? { border: allBorders() } : {}),
      });

      type XCell = { v: string | number; t: 's' | 'n'; s: object };
      const sc = (v: string | number, bg: string, fg: string, opts?: CellOpts): XCell =>
        ({ v, t: typeof v === 'number' ? 'n' : 's', s: cellStyle(bg, fg, opts) });

      const ws: Record<string, unknown> = {};
      const merges: { s: { r: number; c: number }; e: { r: number; c: number } }[] = [];
      const COLS = 6;
      const colWidths = [{ wch: 22 }, { wch: 36 }, { wch: 4 }, { wch: 22 }, { wch: 36 }, { wch: 4 }];
      const rowHeights: { hpt: number }[] = [];
      let R = 0;

      const setCell = (r: number, c: number, cell: XCell) => {
        ws[XLSXStyle.utils.encode_cell({ r, c })] = cell;
      };

      const mergeAll = (r: number, v: string, bg: string, fg: string, opts?: CellOpts) => {
        setCell(r, 0, sc(v, bg, fg, { ...opts, border: false }));
        for (let c = 1; c < COLS; c++) setCell(r, c, sc('', bg, fg, { ...opts, border: false }));
        merges.push({ s: { r, c: 0 }, e: { r, c: COLS - 1 } });
      };

      // Two-column detail row: label in cols 0, value in col 1 (left side)
      // OR label in col 3, value in col 4 (right side)
      const detailRow = (
        r: number,
        lbl1: string, val1: string,
        lbl2?: string, val2?: string,
      ) => {
        setCell(r, 0, sc(lbl1, C.GREEN_PALE, C.GREEN_TEXT, { bold: true, sz: 10, border: false }));
        setCell(r, 1, sc(val1, C.WHITE, '000000', { sz: 10, wrap: true, border: false }));
        setCell(r, 2, sc('', C.WHITE, C.WHITE, { border: false }));
        if (lbl2) {
          setCell(r, 3, sc(lbl2, C.GREEN_PALE, C.GREEN_TEXT, { bold: true, sz: 10, border: false }));
          setCell(r, 4, sc(val2 ?? '', C.WHITE, '000000', { sz: 10, wrap: true, border: false }));
        } else {
          setCell(r, 3, sc('', C.WHITE, C.WHITE, { border: false }));
          setCell(r, 4, sc('', C.WHITE, C.WHITE, { border: false }));
        }
        setCell(r, 5, sc('', C.WHITE, C.WHITE, { border: false }));
      };

      const sectionHeader = (r: number, title: string) => {
        mergeAll(r, `    ${title}`, C.GREEN_DARK, C.WHITE, { bold: true, sz: 12, border: false });
        rowHeights[r] = { hpt: 30 };
      };

      // ─── Title ───
      mergeAll(R, 'MAPTECH TICKETING SYSTEM  —  TICKET DETAIL REPORT', C.GREEN_DARK, C.WHITE, { bold: true, sz: 18, center: true });
      rowHeights[R] = { hpt: 52 }; R++;
      mergeAll(R, `Service Ticket Form — ${ticket.id}`, C.GREEN_MID, '000000', { italic: true, sz: 11, center: true });
      rowHeights[R] = { hpt: 28 }; R++;

      // Info rows
      const [sBg, sFg] = STATUS_COLORS[ticket.status] ?? ['F3F4F6', '000000'];
      const [pBg, pFg] = PRIORITY_COLORS[ticket.priority] ?? ['F3F4F6', '000000'];

      // Status + Priority row
      setCell(R, 0, sc('Status', C.GREEN_PALE, C.GREEN_TEXT, { bold: true, sz: 10, border: false }));
      setCell(R, 1, sc(ticket.status, sBg, sFg, { bold: true, sz: 11, center: true, border: false }));
      setCell(R, 2, sc('', C.WHITE, C.WHITE, { border: false }));
      setCell(R, 3, sc('Priority', C.GREEN_PALE, C.GREEN_TEXT, { bold: true, sz: 10, border: false }));
      setCell(R, 4, sc(ticket.priority, pBg, pFg, { bold: true, sz: 11, center: true, border: false }));
      setCell(R, 5, sc('', C.WHITE, C.WHITE, { border: false }));
      rowHeights[R] = { hpt: 24 }; R++;

      detailRow(R, 'Ticket ID', ticketIdValue, 'Ticket Created by', ticket.createdBy || 'N/A');
      rowHeights[R] = { hpt: 22 }; R++;
      detailRow(R, 'Generated', `${dateStr}  ${timeStr}`, 'Date Created', ticket.created);
      rowHeights[R] = { hpt: 22 }; R++;
      detailRow(R, 'Assigned To', ticket.assignedTo, 'Type of Service', ticket.typeOfService);
      rowHeights[R] = { hpt: 22 }; R++;
      detailRow(R, 'Support Type', ticket.preferredSupport);
      rowHeights[R] = { hpt: 22 }; R++;

      // Spacer
      mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 14 }; R++;

      // ─── CLIENT INFORMATION ───
      sectionHeader(R, 'CLIENT INFORMATION'); R++;
      detailRow(R, 'Client', ticket.client, 'Contact Person', ticket.contact); rowHeights[R] = { hpt: 22 }; R++;
      detailRow(R, 'Email', ticket.emailAddress, 'Department', ticket.department); rowHeights[R] = { hpt: 22 }; R++;
      detailRow(R, 'Mobile', ticket.mobile, 'Landline', ticket.landline); rowHeights[R] = { hpt: 22 }; R++;
      detailRow(R, 'Designation', ticket.designation, 'Address', ticket.fullAddress); rowHeights[R] = { hpt: 22 }; R++;

      mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 14 }; R++;

      // ─── ISSUE DESCRIPTION ───
      sectionHeader(R, 'ISSUE DESCRIPTION'); R++;
      mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 4 }; R++;
      setCell(R, 0, sc(ticket.description, C.WHITE, '000000', { sz: 10, wrap: true, border: false }));
      for (let c = 1; c < COLS; c++) setCell(R, c, sc('', C.WHITE, '000000', { border: false }));
      merges.push({ s: { r: R, c: 0 }, e: { r: R, c: COLS - 1 } });
      const descLen = (ticket.description || '').length;
      rowHeights[R] = { hpt: descLen > 200 ? 80 : descLen > 100 ? 60 : 40 }; R++;

      mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 14 }; R++;

      // ─── PRODUCT DETAILS (if any) ───
      if (ticket.productDetails) {
        sectionHeader(R, 'PRODUCT DETAILS'); R++;
        const pd = ticket.productDetails;
        detailRow(R, 'Project Title', ticket.projectTitle || 'N/A', 'Device/Equipment (Category)', pd.deviceEquipment); rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Product', pd.product ?? '', 'Brand', pd.brand ?? ''); rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Model', pd.model ?? '', 'Serial No', pd.serialNo); rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Version No', pd.versionNo, 'Sales / Invoice No', pd.salesNo || 'N/A'); rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Date Purchased', pd.datePurchased, 'Warranty', pd.warranty); rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Client Purchase No', pd.clientPurchaseNo || 'N/A', 'Maptech Delivery Receipt', pd.maptechDr || 'N/A'); rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Maptech Sales Invoice', pd.maptechSalesInvoice || 'N/A', 'Maptech Sales Order No', pd.maptechSalesOrderNo || 'N/A'); rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Supplier Purchase No', pd.supplierPurchaseNo || 'N/A', 'Supplier Sales Invoice', pd.supplierSalesInvoice || 'N/A'); rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Supplier Delivery Receipt', pd.supplierDeliveryReceipt || 'N/A', 'Others', pd.others || 'N/A');
        rowHeights[R] = { hpt: Math.max(22, Math.ceil((pd.others || '').length / 40) * 14) }; R++;
        mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 14 }; R++;
      }

      // ─── WORK DETAILS ───
      sectionHeader(R, 'WORK DETAILS'); R++;
      detailRow(R, 'Job Status', jobStatusValue, 'Progress', `${ticket.progressPercentage}%`); rowHeights[R] = { hpt: 22 }; R++;
      detailRow(R, 'Time In', ticket.timeIn, 'Time Out', ticket.timeOut); rowHeights[R] = { hpt: 22 }; R++;
      if (ticket.actionTaken) {
        detailRow(R, 'Action Taken', ticket.actionTaken); rowHeights[R] = { hpt: Math.max(22, Math.ceil(ticket.actionTaken.length / 40) * 14) }; R++;
      }
      if (ticket.remarks) {
        detailRow(R, 'Remarks', ticket.remarks); rowHeights[R] = { hpt: Math.max(22, Math.ceil(ticket.remarks.length / 40) * 14) }; R++;
      }
      if (ticket.observation) {
        detailRow(R, 'Observation', ticket.observation); rowHeights[R] = { hpt: Math.max(22, Math.ceil(ticket.observation.length / 40) * 14) }; R++;
      }
      detailRow(R, 'Signed By', signedByValue, 'Signature', signatureValue); rowHeights[R] = { hpt: 22 }; R++;
      mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 14 }; R++;

      // ─── ESCALATION (if any) ───
      if (btData.escalation_logs && btData.escalation_logs.length > 0) {
        sectionHeader(R, 'ESCALATION HISTORY'); R++;
        // Column headers
        const escHeaders = ['Date', 'From', 'To', 'Type', 'Notes', ''];
        escHeaders.forEach((h, c) => setCell(R, c, sc(h, C.GREEN_DARK, C.WHITE, { bold: true, sz: 10, center: true })));
        rowHeights[R] = { hpt: 24 }; R++;
        btData.escalation_logs.forEach((esc: any, i: number) => {
          const bg = i % 2 === 0 ? C.WHITE : C.ALT_ROW;
          setCell(R, 0, sc(esc.created_at ? new Date(esc.created_at).toLocaleString() : '', bg, '000000', { sz: 9 }));
          setCell(R, 1, sc(esc.from_user_name || '', bg, '000000', { sz: 9 }));
          setCell(R, 2, sc(esc.to_user_name || esc.external_escalated_to || '', bg, '000000', { sz: 9 }));
          setCell(R, 3, sc(esc.cascade_type || '', bg, '6B7280', { sz: 9, center: true }));
          setCell(R, 4, sc(esc.notes || '', bg, '000000', { sz: 9, wrap: true }));
          setCell(R, 5, sc('', bg, bg, { border: false }));
          rowHeights[R] = { hpt: 22 }; R++;
        });
        mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 14 }; R++;
      }

      // ─── ATTACHMENTS ───
      const atts = btData.attachments || [];
      if (atts.length > 0) {
        sectionHeader(R, 'ATTACHMENTS'); R++;
        const attHeaders = ['#', 'File Name', '', 'Type', 'Uploaded', ''];
        attHeaders.forEach((h, c) => setCell(R, c, sc(h, C.GREEN_DARK, C.WHITE, { bold: true, sz: 10, center: true })));
        rowHeights[R] = { hpt: 24 }; R++;
        atts.forEach((att: any, i: number) => {
          const bg = i % 2 === 0 ? C.WHITE : C.ALT_ROW;
          const fname = att.file?.split('/').pop() || 'file';
          const ftype = fname.match(/\.(mp4|webm)$/i) ? 'Recording' : fname.match(/\.(jpg|jpeg|png|gif)$/i) ? 'Screenshot' : 'Document';
          setCell(R, 0, sc(i + 1, bg, '000000', { center: true, sz: 10 }));
          setCell(R, 1, sc(fname, bg, '1D4ED8', { sz: 10 }));
          merges.push({ s: { r: R, c: 1 }, e: { r: R, c: 2 } });
          setCell(R, 2, sc('', bg, bg, { border: false }));
          setCell(R, 3, sc(ftype, bg, '6B7280', { sz: 10, center: true }));
          setCell(R, 4, sc(att.uploaded_at ? new Date(att.uploaded_at).toLocaleString() : '', bg, '6B7280', { sz: 9 }));
          setCell(R, 5, sc('', bg, bg, { border: false }));
          rowHeights[R] = { hpt: 22 }; R++;
        });
        mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 14 }; R++;
      }

      // ─── Feedback Ratings ───
      if (ticket.feedbackRating) {
        sectionHeader(R, 'FEEDBACK RATINGS'); R++;
        detailRow(R, 'Assignee', ticket.assignedTo || 'Unassigned');
        rowHeights[R] = { hpt: 22 }; R++;
        detailRow(R, 'Rating', `${ticket.feedbackRating.rating} / 5`, 'Date', ticket.feedbackRating.created_at ? new Date(ticket.feedbackRating.created_at).toLocaleString() : '');
        rowHeights[R] = { hpt: 22 }; R++;
        if (ticket.feedbackRating.comments) {
          detailRow(R, 'Comments', ticket.feedbackRating.comments);
          rowHeights[R] = { hpt: Math.max(22, Math.ceil((ticket.feedbackRating.comments || '').length / 40) * 14) }; R++;
        }
        mergeAll(R, '', C.WHITE, C.WHITE, { border: false }); rowHeights[R] = { hpt: 14 }; R++;
      }

      // ─── Footer ───
      mergeAll(R, `   End of Ticket Report  •  ${ticket.id}  •  Generated ${dateStr} ${timeStr}`, C.GREEN_DARK, C.WHITE, { italic: true, sz: 9, center: true, border: false });
      rowHeights[R] = { hpt: 26 }; R++;

      // Sheet metadata
      ws['!ref'] = XLSXStyle.utils.encode_range({ s: { r: 0, c: 0 }, e: { r: R - 1, c: COLS - 1 } });
      ws['!cols'] = colWidths;
      ws['!rows'] = rowHeights;
      ws['!merges'] = merges;

      const wb = XLSXStyle.utils.book_new();
      XLSXStyle.utils.book_append_sheet(wb, ws, 'Ticket Detail');
      XLSXStyle.writeFile(wb, `ticket_${ticket.id}_${dateStr}.xlsx`);

      toast.success(`Exported ticket ${ticket.id} to Excel.`);
    } catch (err) {
      console.error('Export error:', err);
      toast.error('Export failed.');
    }
  };

  return (
    <div className="space-y-6">
      {btLoading ? (
        <div className="flex items-center justify-center py-32">
          <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-[#0E8F79]" />
        </div>
      ) : (
      <>
      {/* Back + Messages */}
      <div className="mb-4 flex flex-col sm:flex-row sm:items-center justify-between gap-3 sticky top-0 z-30 bg-gray-50 dark:bg-gray-950 py-2 -mx-1 px-1">
        <div>
          <GreenButton variant="ghost" className="px-2 py-2" onClick={() => navigate(-1)}>
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back
          </GreenButton>
        </div>
        <div className="flex flex-wrap items-center gap-2 w-full sm:w-auto sm:justify-end">
          {/* Employee or admin: escalate (internal or external) when not already escalated/closed/resolved */}
          {canProcessTicket && ticket.status !== 'Closed' && ticket.status !== 'Escalated' && ticket.status !== 'Resolved' && (
            <button
              onClick={() => { setEscalateType(isAdmin ? 'external' : 'internal'); setShowEscalateModal(true); }}
              title="Escalate Ticket"
              aria-label="Escalate ticket"
              className="inline-flex items-center gap-2 px-3 py-2 rounded-md bg-orange-500 hover:bg-orange-600 text-white text-sm font-medium transition-colors"
            >
              <ArrowUpRight className="w-4 h-4" />
              Escalate
            </button>
          )}
          <div className="relative">
            <button
              onClick={() => setShowExportMenu((v) => !v)}
              title="Export Ticket"
              aria-label="Export ticket"
              className="inline-flex items-center gap-2 px-3 py-2 rounded-md bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 text-sm text-gray-700 dark:text-gray-300"
            >
              <Download className="w-4 h-4 text-[#0E8F79]" />
              Export
              <ChevronDown className="w-3 h-3 ml-0.5" />
            </button>
            {showExportMenu && (
              <>
                <div className="fixed inset-0 z-40" onClick={() => setShowExportMenu(false)} />
                <div className="absolute right-0 mt-2 w-48 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 z-50 overflow-hidden">
                  <button
                    onClick={handleExportPDF}
                    className="w-full flex items-center gap-3 px-4 py-3 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                  >
                    <FileDown className="w-4 h-4 text-red-500" />
                    Export as PDF
                  </button>
                  <button
                    onClick={() => { setShowExportMenu(false); handleExportTicket(); }}
                    className="w-full flex items-center gap-3 px-4 py-3 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                  >
                    <FileSpreadsheet className="w-4 h-4 text-[#0E8F79]" />
                    Export as XLSX
                  </button>
                </div>
              </>
            )}
          </div>
          <button
            onClick={() => setShowChat(true)}
            title="Messages"
            aria-label="Open messages"
            className="inline-flex items-center gap-2 px-3 py-2 rounded-md bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 text-sm text-gray-700 dark:text-gray-300"
          >
            <MessageSquare className="w-4 h-4 text-[#0E8F79]" />
            Messages
          </button>
          {isAdmin && (
            <>
              <button onClick={handleAdminDelete} title="Delete Ticket" className="inline-flex items-center gap-2 px-3 py-2 rounded-md bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-700 hover:bg-red-100 dark:hover:bg-red-800 text-sm text-red-700 dark:text-red-400">
                <Trash2 className="w-4 h-4" /> Delete
              </button>
            </>
          )}
        </div>
      </div>

      {/* Two-Column Layout */}
      <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">
        {/* Left Column - Ticket Information */}
        <div className="lg:col-span-3">
          <Card>
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 pb-4 mb-4 border-b border-gray-200 dark:border-gray-700">
              <div className="flex items-center gap-3">
                <PriorityBadge priority={ticket.priority} />
                <h2 className="text-lg font-bold text-gray-900 dark:text-white">{ticket.id}</h2>
              </div>
              <StatusBadge status={ticket.status} />
            </div>

            {/* Date Meta */}
            <div className="flex flex-wrap gap-6 text-sm mb-5">
              <div className="text-gray-500 dark:text-gray-400">
                Ticket Created by <span className="ml-1 font-medium text-gray-800 dark:text-gray-200">{ticket.createdBy}</span>
              </div>
              <div className="text-gray-500 dark:text-gray-400">
                Date Created <span className="ml-1 font-medium text-gray-800 dark:text-gray-200">{ticket.created}</span>
              </div>
              <div className="text-gray-500 dark:text-gray-400">
                Time In <span className="ml-1 font-medium text-gray-800 dark:text-gray-200">{ticket.timeIn}</span>
              </div>
              <div className="text-gray-500 dark:text-gray-400">
                Time Out <span className="ml-1 font-medium text-gray-800 dark:text-gray-200">{ticket.timeOut}</span>
              </div>
            </div>

            {/* Progress Tracker */}
            <div className="mb-5">
              <span className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-3 block">Progress Tracker</span>
              <TicketProgressTracker
                backendStatus={btData?.status || 'open'}
                timeIn={btData?.time_in || null}
                wasObserved={!!btData?.was_for_observation}
                wasEscalatedInternal={!!btData?.escalation_logs?.some((l: any) => l.escalation_type === 'internal')}
                wasEscalatedExternal={!!btData?.external_escalated_to}
              />
              {ticket.slaEstimatedDays ? (
                <p className="text-xs text-gray-400 dark:text-gray-500 mt-3">
                  SLA Estimated Resolution: <span className="font-medium">{ticket.slaEstimatedDays} day{ticket.slaEstimatedDays !== 1 ? 's' : ''}</span>
                </p>
              ) : null}
            </div>

            {/* Cascade Type Badge */}
            {ticket.cascadeType && (
              <div className="mb-5">
                <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold ${
                  ticket.cascadeType === 'internal'
                    ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400'
                    : 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400'
                }`}>
                  {ticket.cascadeType === 'internal' ? <Shield className="w-3 h-3" /> : <Share2 className="w-3 h-3" />}
                  {ticket.cascadeType === 'internal' ? 'Internal Cascade' : 'External Cascade'}
                </span>
              </div>
            )}

            {/* External Escalation Tag */}
            {btData?.external_escalated_to && (
              <div className="mb-5 p-3 bg-purple-50 dark:bg-purple-900/20 border border-purple-200 dark:border-purple-500/30 rounded-xl">
                <div className="flex items-center gap-2 mb-1">
                  <Share2 className="w-3.5 h-3.5 text-purple-600 dark:text-purple-400" />
                  <span className="text-xs font-bold uppercase tracking-wider text-purple-700 dark:text-purple-400">Escalated to External</span>
                </div>
                <p className="text-sm font-medium text-purple-800 dark:text-purple-300">{btData.external_escalated_to}</p>
                {btData.external_escalation_notes && (
                  <p className="text-xs text-purple-600 dark:text-purple-400 mt-1">{btData.external_escalation_notes}</p>
                )}
              </div>
            )}

            {/* Linked Tickets */}
            {btData?.linked_ticket_stfs && btData.linked_ticket_stfs.length > 0 && (
              <div className="mb-5">
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-2">Linked Tickets</div>
                <div className="flex flex-wrap gap-2">
                  {btData.linked_ticket_stfs.map((stf: string, idx: number) => (
                    <span
                      key={idx}
                      className="inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-medium bg-blue-50 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400 border border-blue-200 dark:border-blue-500/30"
                    >
                      <Link2 className="w-3 h-3" />
                      {stf}
                    </span>
                  ))}
                </div>
              </div>
            )}

            {/* Details Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-6 gap-y-4 text-sm">
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Client</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.client}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Contact Person</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.contact}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Landline No.</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.landline}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Mobile No.</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.mobile}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Email Address</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.emailAddress}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Designation</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.designation}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Department/Organization</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.department}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Full Address</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.fullAddress}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Type of Service</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.typeOfService}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Preferred Type of Support</div>
                <div className="text-gray-900 dark:text-gray-100">{ticket.preferredSupport}</div>
              </div>
              {/* Description - Full Width */}
              <div className="sm:col-span-2 mt-2">
                <div className="text-xs font-semibold uppercase tracking-wider text-[#0E8F79] mb-1">Description</div>
                <p className="text-gray-700 dark:text-gray-300 text-sm leading-relaxed whitespace-pre-wrap [overflow-wrap:anywhere] p-3 bg-gray-50 dark:bg-gray-800/50 rounded-lg border-l-4 border-[#0E8F79]">
                  {ticket.description}
                </p>
              </div>
              {/* External Escalation Info — shown when ticket is tagged as externally escalated */}
              {btData?.external_escalated_to && (
                <>
                  <div>
                    <div className="text-xs font-semibold uppercase tracking-wider text-purple-600 dark:text-purple-400 mb-1">Escalated To (External)</div>
                    <div className="text-gray-900 dark:text-gray-100">{btData.external_escalated_to}</div>
                  </div>
                  <div>
                    <div className="text-xs font-semibold uppercase tracking-wider text-purple-600 dark:text-purple-400 mb-1">Escalation Notes</div>
                    <div className="text-gray-900 dark:text-gray-100">{btData.external_escalation_notes || 'N/A'}</div>
                  </div>
                </>
              )}
            </div>

            {/* Product Details & Digital Signature — hidden for employee until Start Work is clicked; always shown for admin processing escalated */}
            {(!isAssignedEmployee || !!btData?.time_in || isAdminProcessingEscalated) && <>
            {/* Product Details Section — editable by assigned employee, read-only for others */}
            <div className="mt-6 pt-5 border-t border-gray-200 dark:border-gray-700">
              <h3 className="text-xs font-bold uppercase tracking-wider text-[#0E8F79] mb-4 flex items-center gap-2">
                <Package className="w-4 h-4" /> Product Details
                {canEdit && <span className="text-[10px] font-normal normal-case text-gray-400">(fill in after assignment)</span>}
              </h3>
              {showProductEditor && (
                <div className="mb-4">
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Select Product</div>
                  <select
                    value={selectedProductId}
                    onChange={(e) => handleProductSelect(e.target.value)}
                    className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]"
                  >
                    <option value="">-- Select a registered product --</option>
                    {productCatalog.map(p => (
                      <option key={p.id} value={p.id}>
                        {[p.product_name, p.brand, p.model_name, p.serial_no].filter(Boolean).join(' / ') || `Product #${p.id}`}
                      </option>
                    ))}
                  </select>
                </div>
              )}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-6 gap-y-4 text-sm">
                {/* Project Title */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Project Title</div>
                  <div className="text-gray-900 dark:text-gray-100">{ticket.projectTitle || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                </div>
                {/* Device / Equipment */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Device / Equipment</div>
                  {showProductEditor ? (
                    <input value={pdDeviceEquipment} onChange={(e) => setPdDeviceEquipment(e.target.value)} placeholder="e.g. Laptop, Printer" className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdDeviceEquipment || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>
                {/* Product */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Product</div>
                  {showProductEditor ? (
                    <input value={pdProduct} onChange={(e) => setPdProduct(e.target.value)} placeholder="Product name" className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdProduct || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>
                {/* Brand */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Brand</div>
                  {showProductEditor ? (
                    <input value={pdBrand} onChange={(e) => setPdBrand(e.target.value)} placeholder="Brand name" className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdBrand || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>
                {/* Model */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Model</div>
                  {showProductEditor ? (
                    <input value={pdModel} onChange={(e) => setPdModel(e.target.value)} placeholder="Model name" className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdModel || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>
                {/* Version No. */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Version No.</div>
                  {showProductEditor ? (
                    <input value={pdVersionNo} onChange={(e) => setPdVersionNo(e.target.value)} placeholder="Version number" className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdVersionNo || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>
                {/* Serial No. */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Serial No.</div>
                  {showProductEditor ? (
                    <input value={pdSerialNo} onChange={(e) => setPdSerialNo(e.target.value)} placeholder="Serial number" className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdSerialNo || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>
                {/* Sales / Invoice No. */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Sales / Invoice No.</div>
                  {showProductEditor ? (
                    <input value={pdSalesNo} onChange={(e) => setPdSalesNo(e.target.value)} placeholder="Sales / Invoice number" className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdSalesNo || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>
                {/* Date Purchased */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Date Purchased</div>
                  {showProductEditor ? (
                    <input type="date" value={pdDatePurchased} onChange={(e) => setPdDatePurchased(e.target.value)} className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdDatePurchased || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>
                {/* Warranty */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Warranty</div>
                  {showProductEditor ? (
                    <div className="flex items-center gap-3">
                      <button
                        type="button"
                        onClick={() => setPdHasWarranty(true)}
                        className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${
                          pdHasWarranty
                            ? 'bg-[#0E8F79] text-white border-[#0E8F79] shadow-sm'
                            : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-300 border-gray-200 dark:border-gray-600 hover:border-[#0E8F79]/50'
                        }`}
                      >
                        With Warranty
                      </button>
                      <button
                        type="button"
                        onClick={() => setPdHasWarranty(false)}
                        className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${
                          !pdHasWarranty
                            ? 'bg-gray-500 text-white border-gray-500 shadow-sm'
                            : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-300 border-gray-200 dark:border-gray-600 hover:border-gray-400'
                        }`}
                      >
                        Without Warranty
                      </button>
                    </div>
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdHasWarranty ? 'With Warranty' : 'Without Warranty'}</div>
                  )}
                </div>
                {/* Client Purchase No. */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Client Purchase No.</div>
                  <div className="text-gray-900 dark:text-gray-100">{btData?.client_purchase_no || btData?.product_record_detail?.client_purchase_no || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                </div>
                {/* Others */}
                <div className="col-span-2">
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Others</div>
                  {showProductEditor ? (
                    <textarea value={pdOthers} onChange={(e) => setPdOthers(e.target.value)} placeholder="Additional product details" rows={2} className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79] resize-vertical" />
                  ) : (
                    <div className="text-gray-900 dark:text-gray-100">{pdOthers || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                  )}
                </div>

                {/* Additional product detail fields */}
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Maptech Delivery Receipt</div>
                  <div className="text-gray-900 dark:text-gray-100">{btData?.maptech_dr || btData?.product_record_detail?.maptech_dr || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                </div>
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Maptech Sales Invoice</div>
                  <div className="text-gray-900 dark:text-gray-100">{btData?.maptech_sales_invoice || btData?.product_record_detail?.maptech_sales_invoice || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                </div>
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Maptech Sales Order No.</div>
                  <div className="text-gray-900 dark:text-gray-100">{btData?.maptech_sales_order_no || btData?.product_record_detail?.maptech_sales_order_no || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                </div>
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Supplier Purchase No.</div>
                  <div className="text-gray-900 dark:text-gray-100">{btData?.supplier_purchase_no || btData?.product_record_detail?.supplier_purchase_no || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                </div>
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Supplier Sales Invoice</div>
                  <div className="text-gray-900 dark:text-gray-100">{btData?.supplier_sales_invoice || btData?.product_record_detail?.supplier_sales_invoice || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                </div>
                <div className="sm:col-span-2">
                  <div className="text-xs font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400 mb-1">Supplier Delivery Receipt</div>
                  <div className="text-gray-900 dark:text-gray-100">{btData?.supplier_delivery_receipt || btData?.product_record_detail?.supplier_delivery_receipt || <span className="text-gray-400 italic">Not yet filled</span>}</div>
                </div>
              </div>
              {/* Save Product Details button (employee only) */}
              {canEdit && needsManualProductEntry && hasManualProductDetails && (
                <button
                  type="button"
                  disabled={isEditingProductDetails && savingProductDetails}
                  onClick={() => {
                    if (isEditingProductDetails) {
                      void handleSaveProductDetails();
                      return;
                    }
                    setIsEditingProductDetails(true);
                  }}
                  className="mt-4 w-full py-2.5 rounded-xl font-semibold text-white bg-gradient-to-r from-[#63D44A] to-[#0E8F79] hover:shadow-lg hover:shadow-[#3BC25B]/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all text-sm"
                >
                  {isEditingProductDetails ? (
                    savingProductDetails
                      ? <><Loader2 className="w-4 h-4 animate-spin" /> Saving...</>
                      : <><CheckCircle className="w-4 h-4" /> Save Product Details</>
                  ) : (
                    <><PenLine className="w-4 h-4" /> Edit Product Details</>
                  )}
                </button>
              )}
              {showProductEditor && !(needsManualProductEntry && hasManualProductDetails) && (
                <button
                  type="button"
                  disabled={savingProductDetails}
                  onClick={handleSaveProductDetails}
                  className="mt-4 w-full py-2.5 rounded-xl font-semibold text-white bg-gradient-to-r from-[#63D44A] to-[#0E8F79] hover:shadow-lg hover:shadow-[#3BC25B]/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all text-sm"
                >
                  {savingProductDetails ? (
                    <><Loader2 className="w-4 h-4 animate-spin" /> Saving...</>
                  ) : (
                    <><CheckCircle className="w-4 h-4" /> Save Product Details</>
                  )}
                </button>
              )}
            </div>

            {/* ── Digital Signature Section ── */}
            <div className="mt-6 pt-5 border-t border-gray-200 dark:border-gray-700">
              <h3 className="text-xs font-bold uppercase tracking-wider text-[#0E8F79] mb-3 flex items-center gap-2">
                <PenLine className="w-4 h-4" /> Digital Signature
              </h3>
              {signatureData ? (
                <div className="space-y-2">
                  <div className="p-3 bg-gray-50 dark:bg-gray-800/50 rounded-lg border border-gray-200 dark:border-gray-700">
                    <img src={signatureData} alt="Digital Signature" className="max-h-24 mx-auto" />
                  </div>
                  {signedByName && (
                    <p className="text-xs text-gray-500 dark:text-gray-400 text-center">Signed by: <span className="font-medium text-gray-700 dark:text-gray-300">{signedByName}</span></p>
                  )}
                </div>
              ) : canEdit ? (
                <div className="space-y-3">
                  <div>
                    <label className="block text-xs text-gray-500 dark:text-gray-400 mb-1">Your Name</label>
                    <input
                      value={signedByName}
                      onChange={(e) => setSignedByName(e.target.value)}
                      placeholder="Enter your full name"
                      className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-sm text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]"
                    />
                  </div>
                  <SignaturePad onSave={(data) => setSignatureData(data)} />
                </div>
              ) : (
                <p className="text-sm text-gray-400 italic p-3 bg-gray-50 dark:bg-gray-800/50 rounded-lg">No signature captured yet</p>
              )}
            </div>
            </>}

          </Card>
        </div>

        {/* Right Column */}
        <div className="lg:col-span-2 space-y-4">
          {/* Action Taken, Remarks, Required Attachment, Status of Job – hidden for employee until Start Work is clicked; always shown for admin processing escalated */}
          {(!isAssignedEmployee || !!btData?.time_in || isAdminProcessingEscalated) && <>
          <Card>
            <h3 className="text-xs font-bold uppercase tracking-wider text-[#0E8F79] mb-3 flex items-center gap-2">
              <FileText className="w-4 h-4" /> Action Taken <span className="text-red-500">*</span>
            </h3>
            <textarea
              value={actionTaken}
              onChange={(e) => canEdit && setActionTaken(e.target.value)}
              disabled={!canEdit}
              placeholder="Describe the actions taken to resolve the issue..."
              className={`w-full min-h-[100px] p-3 rounded-lg border text-sm resize-y outline-none transition-colors ${
                canEdit
                  ? 'border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-gray-700 dark:text-gray-300 focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]'
                  : 'border-gray-100 dark:border-gray-700 bg-gray-100 dark:bg-gray-800/50 text-gray-500 dark:text-gray-400 cursor-not-allowed opacity-60'
              }`}
            />
          </Card>

          {/* Remarks */}
          <Card>
            <h3 className="text-xs font-bold uppercase tracking-wider text-[#0E8F79] mb-3 flex items-center gap-2">
              <FileText className="w-4 h-4" /> Remarks <span className="text-red-500">*</span>
            </h3>
            <textarea
              value={remarksText}
              onChange={(e) => canEdit && setRemarksText(e.target.value)}
              disabled={!canEdit}
              placeholder="Additional remarks or notes..."
              className={`w-full min-h-[80px] p-3 rounded-lg border text-sm resize-y outline-none transition-colors ${
                canEdit
                  ? 'border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 text-gray-700 dark:text-gray-300 focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79]'
                  : 'border-gray-100 dark:border-gray-700 bg-gray-100 dark:bg-gray-800/50 text-gray-500 dark:text-gray-400 cursor-not-allowed opacity-60'
              }`}
            />
          </Card>

          {/* Required Attachment */}
          <Card>
            <h3 className="text-xs font-bold uppercase tracking-wider text-[#0E8F79] mb-3 flex items-center gap-2">
              <Paperclip className="w-4 h-4" /> Required Attachment <span className="text-red-500">*</span>
            </h3>

            {/* Hidden file inputs */}
            <input
              ref={screenshotInputRef}
              type="file"
              accept="image/png,image/jpeg,image/jpg"
              multiple
              className="hidden"
              onChange={handleScreenshotSelect}
            />
            <input
              ref={recordingInputRef}
              type="file"
              accept="video/mp4,video/webm"
              multiple
              className="hidden"
              onChange={handleRecordingSelect}
            />

            <div className="space-y-3">
              {/* Screenshot / Picture trigger */}
              <button
                type="button"
                onClick={() => canEdit && screenshotInputRef.current?.click()}
                disabled={!canEdit}
                className={`w-full flex items-center gap-3 p-3 rounded-lg border border-dashed transition-colors text-left ${
                  canEdit
                    ? 'border-gray-300 dark:border-gray-600 bg-gray-50 dark:bg-gray-800/50 hover:border-[#0E8F79] hover:bg-[#0E8F79]/5 cursor-pointer'
                    : 'border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 opacity-60 cursor-not-allowed'
                }`}
              >
                <Camera className="w-5 h-5 text-[#0E8F79]" />
                <div className="flex-1">
                  <div className="text-sm font-medium text-gray-700 dark:text-gray-300">Screenshot / Picture</div>
                  <div className="text-xs text-gray-400">PNG, JPG up to 10MB</div>
                </div>
                <Upload className="w-4 h-4 text-gray-400" />
              </button>

              {/* Selected screenshot files */}
              {screenshotFiles.length > 0 && (
                <div className="space-y-1.5 ml-8">
                  {screenshotFiles.map((f, i) => (
                    <div key={i} className="flex items-center gap-2 p-2 rounded-lg bg-blue-50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-800">
                      <Camera className="w-3.5 h-3.5 text-blue-500 flex-shrink-0" />
                      <span className="text-xs text-blue-700 dark:text-blue-400 flex-1 truncate">{f.name}</span>
                      <span className="text-[10px] text-blue-400 flex-shrink-0">{formatFileSize(f.size)}</span>
                      <button type="button" onClick={() => removeScreenshot(i)} className="p-0.5 rounded hover:bg-blue-100 dark:hover:bg-blue-800 transition-colors">
                        <X className="w-3.5 h-3.5 text-blue-400 hover:text-red-500" />
                      </button>
                    </div>
                  ))}
                </div>
              )}

              {/* Recording trigger */}
              <button
                type="button"
                onClick={() => canEdit && recordingInputRef.current?.click()}
                disabled={!canEdit}
                className={`w-full flex items-center gap-3 p-3 rounded-lg border border-dashed transition-colors text-left ${
                  canEdit
                    ? 'border-gray-300 dark:border-gray-600 bg-gray-50 dark:bg-gray-800/50 hover:border-[#0E8F79] hover:bg-[#0E8F79]/5 cursor-pointer'
                    : 'border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 opacity-60 cursor-not-allowed'
                }`}
              >
                <Video className="w-5 h-5 text-[#0E8F79]" />
                <div className="flex-1">
                  <div className="text-sm font-medium text-gray-700 dark:text-gray-300">Recording</div>
                  <div className="text-xs text-gray-400">MP4, WebM up to 50MB</div>
                </div>
                <Upload className="w-4 h-4 text-gray-400" />
              </button>

              {/* Selected recording files */}
              {recordingFiles.length > 0 && (
                <div className="space-y-1.5 ml-8">
                  {recordingFiles.map((f, i) => (
                    <div key={i} className="flex items-center gap-2 p-2 rounded-lg bg-purple-50 dark:bg-purple-900/10 border border-purple-100 dark:border-purple-800">
                      <Video className="w-3.5 h-3.5 text-purple-500 flex-shrink-0" />
                      <span className="text-xs text-purple-700 dark:text-purple-400 flex-1 truncate">{f.name}</span>
                      <span className="text-[10px] text-purple-400 flex-shrink-0">{formatFileSize(f.size)}</span>
                      <button type="button" onClick={() => removeRecording(i)} className="p-0.5 rounded hover:bg-purple-100 dark:hover:bg-purple-800 transition-colors">
                        <X className="w-3.5 h-3.5 text-purple-400 hover:text-red-500" />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Upload button (appears when files are selected) */}
            {canEdit && (screenshotFiles.length > 0 || recordingFiles.length > 0) && (
              <button
                type="button"
                disabled={uploadingAttachments}
                onClick={handleUploadAttachments}
                className="mt-3 w-full py-2.5 rounded-xl font-semibold text-white bg-gradient-to-r from-[#63D44A] to-[#0E8F79] hover:shadow-lg hover:shadow-[#3BC25B]/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all text-sm"
              >
                {uploadingAttachments ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Uploading...
                  </>
                ) : (
                  <>
                    <Upload className="w-4 h-4" />
                    Upload {screenshotFiles.length + recordingFiles.length} file{screenshotFiles.length + recordingFiles.length > 1 ? 's' : ''}
                  </>
                )}
              </button>
            )}

            {/* Already uploaded attachments (from backend or just uploaded) */}
            {uploadedAttachments.length > 0 && (
              <div className="mt-3 space-y-2">
                <div className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Uploaded Files</div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  {uploadedAttachments.map((att) => (
                    <div key={att.id} className="relative group rounded-lg overflow-hidden border border-green-100 dark:border-green-800 bg-green-50 dark:bg-green-900/10">
                      {att.type === 'screenshot' && att.url ? (
                        <button
                          type="button"
                          onClick={() => setLightboxUrl(att.url!)}
                          className="block w-full cursor-pointer hover:opacity-90 transition-opacity"
                        >
                          <img
                            src={att.url}
                            alt={att.name}
                            className="w-full h-32 object-cover"
                          />
                        </button>
                      ) : att.type === 'recording' && att.url ? (
                        <button
                          type="button"
                          onClick={() => setVideoLightboxUrl(att.url!)}
                          className="relative block w-full cursor-pointer hover:opacity-90 transition-opacity bg-gray-900"
                        >
                          <video src={att.url} className="w-full h-32 object-cover" muted playsInline preload="metadata" />
                          <div className="absolute inset-0 flex items-center justify-center">
                            <div className="w-10 h-10 rounded-full bg-black/50 flex items-center justify-center">
                              <Play className="w-5 h-5 text-white ml-0.5" />
                            </div>
                          </div>
                        </button>
                      ) : (
                        <div className="flex items-center justify-center h-32 bg-gray-100 dark:bg-gray-800">
                          <File className="w-8 h-8 text-gray-400" />
                        </div>
                      )}
                      <div className="flex items-center gap-2 px-2 py-1.5">
                        {att.type === 'screenshot' ? <Camera className="w-3.5 h-3.5 text-green-600 flex-shrink-0" /> : <Video className="w-3.5 h-3.5 text-green-600 flex-shrink-0" />}
                        <span className="text-xs text-green-700 dark:text-green-400 flex-1 truncate">{att.name}</span>
                        {att.url && (
                          <a href={att.url} download onClick={(e) => e.stopPropagation()} className="p-0.5 rounded hover:bg-green-100 dark:hover:bg-green-800 transition-colors">
                            <Download className="w-3 h-3 text-green-500" />
                          </a>
                        )}
                        {canEdit && (
                          <button type="button" onClick={() => handleRemoveUploaded(att)} className="p-0.5 rounded hover:bg-red-100 dark:hover:bg-red-900/20 transition-colors opacity-0 group-hover:opacity-100">
                            <Trash2 className="w-3 h-3 text-red-400" />
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </Card>

          {/* Status of Job */}
          <Card>
            <h3 className="text-xs font-bold uppercase tracking-wider text-[#0E8F79] mb-3 flex items-center gap-2">
              <ClipboardList className="w-4 h-4" /> Status of Job <span className="text-red-500">*</span>
            </h3>
            <div className="flex flex-wrap gap-2">
              {JOB_STATUSES.map((s) => (
                <button
                  key={s}
                  disabled={!canEdit}
                  onClick={() => { if (canEdit) setJobStatus(s === jobStatus ? '' : s); }}
                  className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${
                    jobStatus === s
                      ? 'bg-[#0E8F79] text-white border-[#0E8F79] shadow-sm'
                      : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-300 border-gray-200 dark:border-gray-600 hover:border-[#0E8F79]/50'
                  } ${!canEdit ? 'cursor-not-allowed opacity-60' : 'cursor-pointer'}`}
                >
                  {s}
                </button>
              ))}
            </div>
          </Card>
          </>}

          {/* Feedback Ratings (visible to admin only, hidden when admin is processing their own escalated ticket) */}
          {isAdmin && !isAdminProcessingEscalated && <Card>
            <h3 className="text-xs font-bold uppercase tracking-wider text-[#0E8F79] mb-3 flex items-center gap-2">
              <Star className="w-4 h-4" /> Feedback Ratings
            </h3>
            {ticket.feedbackRating ? (
              <div className="space-y-3">
                <div className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-800/50 rounded-xl">
                  <div className="w-10 h-10 rounded-full bg-[#0E8F79] flex items-center justify-center text-white font-bold text-sm shrink-0">
                    {ticket.assignedTo?.charAt(0)?.toUpperCase() || '?'}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-900 dark:text-white truncate">{ticket.assignedTo || 'Technical'}</p>
                    <p className="text-xs text-gray-400">Assigned Technical</p>
                  </div>
                </div>
                <div className="flex items-center gap-1">
                  {[1, 2, 3, 4, 5].map((s) => (
                    <Star key={s} className={`w-5 h-5 ${s <= ticket.feedbackRating.rating ? 'text-yellow-400 fill-yellow-400' : 'text-gray-300 dark:text-gray-600'}`} />
                  ))}
                  <span className="ml-2 text-sm font-bold text-gray-700 dark:text-gray-300">{ticket.feedbackRating.rating}/5</span>
                  <span className="ml-1 text-xs text-gray-400">
                    {ticket.feedbackRating.rating <= 2 ? 'Needs Improvement' : ticket.feedbackRating.rating <= 3 ? 'Satisfactory' : ticket.feedbackRating.rating <= 4 ? 'Good' : 'Excellent'}
                  </span>
                </div>
                {ticket.feedbackRating.comments && (
                  <div className="p-3 bg-gray-50 dark:bg-gray-800/50 rounded-lg border-l-4 border-yellow-400">
                    <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Comments</p>
                    <p className="text-sm text-gray-700 dark:text-gray-300">{ticket.feedbackRating.comments}</p>
                  </div>
                )}
              </div>
            ) : (
              <div className="space-y-3">
                <div className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-800/50 rounded-xl">
                  <div className="w-10 h-10 rounded-full bg-gray-300 dark:bg-gray-600 flex items-center justify-center text-white font-bold text-sm shrink-0">
                    {ticket.assignedTo && ticket.assignedTo !== 'unassigned' ? ticket.assignedTo.charAt(0).toUpperCase() : '?'}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-900 dark:text-white truncate">{ticket.assignedTo && ticket.assignedTo !== 'unassigned' ? ticket.assignedTo : 'Unassigned'}</p>
                    <p className="text-xs text-gray-400">Assigned Technical</p>
                  </div>
                </div>
                <div className="flex items-center gap-1">
                  {[1, 2, 3, 4, 5].map((s) => (
                    <Star key={s} className="w-5 h-5 text-gray-300 dark:text-gray-600" />
                  ))}
                  <span className="ml-2 text-sm text-gray-400 dark:text-gray-500">—/5</span>
                </div>
                <div className="p-3 bg-gray-50 dark:bg-gray-800/50 rounded-lg border-l-4 border-gray-200 dark:border-gray-700">
                  <p className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-1">Comments</p>
                  <p className="text-sm text-gray-300 dark:text-gray-600 italic">Will be provided upon ticket closure</p>
                </div>
              </div>
            )}
          </Card>}

          {/* ── Action Buttons ── */}
          {ticket.status !== 'Closed' && (
            <div className="space-y-3">
              {/* Admin: Reassign ticket via modal picker */}
              {canAdminReassign && (
                <>
                  <button
                    type="button"
                    onClick={openReassignModal}
                    className="w-full py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-orange-500 to-orange-600 hover:shadow-lg hover:shadow-orange-500/20 flex items-center justify-center gap-2 transition-all text-sm"
                  >
                    <UserCheck className="w-4 h-4" /> {needsCallPriorityWorkflow ? 'Call & Set Priority' : 'Reassign to Employee'}
                  </button>
                  {showHandleYourselfDivider && (
                    <div className="flex items-center gap-2 pt-1">
                      <div className="flex-1 h-px bg-gray-200 dark:bg-gray-700" />
                      <span className="text-xs text-gray-400">or handle yourself</span>
                      <div className="flex-1 h-px bg-gray-200 dark:bg-gray-700" />
                    </div>
                  )}
                </>
              )}
              {canSalesCallWorkflow && !canAdminReassign && (
                <button
                  type="button"
                  onClick={openReassignModal}
                  className="w-full py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-orange-500 to-orange-600 hover:shadow-lg hover:shadow-orange-500/20 flex items-center justify-center gap-2 transition-all text-sm"
                >
                  <Phone className="w-4 h-4" /> Open Call Status
                </button>
              )}
              {/* Start Work — only shown when no time_in yet (work has not begun) */}
              {canStartWorkAction && (
                <button
                  type="button"
                  disabled={startingWork}
                  onClick={() => setShowStartWorkConfirm(true)}
                  className="w-full py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-blue-500 to-blue-600 hover:shadow-lg hover:shadow-blue-500/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all text-sm"
                >
                  {startingWork ? (
                    <><Loader2 className="w-4 h-4 animate-spin" /> Starting...</>
                  ) : (
                    <><PlayCircle className="w-4 h-4" /> Start Work</>
                  )}
                </button>
              )}
              {/* Submit for Observation — work started (time_in set), not yet observed */}
              {canSubmitObservationAction && (
                <button
                  type="button"
                  disabled={submittingObservation}
                  onClick={() => setShowObservationConfirm(true)}
                  className="w-full py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-indigo-500 to-indigo-600 hover:shadow-lg hover:shadow-indigo-500/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all text-sm"
                >
                  {submittingObservation ? (
                    <><Loader2 className="w-4 h-4 animate-spin" /> Submitting...</>
                  ) : (
                    <><Eye className="w-4 h-4" /> Submit &amp; For Observation</>
                  )}
                </button>
              )}
              {/* Resolve Ticket — observation already submitted; shown at For Observation, or after reassignment with time_in preserved */}
              {canResolveAction && (
                <button
                  type="button"
                  disabled={savingFields || !canResolveTicket}
                  onClick={() => setShowResolveConfirm(true)}
                  className="w-full py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-[#0E8F79] to-[#0b7a67] hover:shadow-lg hover:shadow-[#0E8F79]/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all text-sm"
                >
                  {savingFields ? (
                    <><Loader2 className="w-4 h-4 animate-spin" /> Resolving...</>
                  ) : (
                    <><CheckCircle className="w-4 h-4" /> Resolve</>
                  )}
                </button>
              )}

              {/* Admin: Close Ticket */}
              {isAdmin && ticket.status === 'Resolved' && (
                <button
                  type="button"
                  onClick={() => {
                    if (btData?.assigned_to?.id) {
                      setShowFeedbackRatingModal(true);
                      return;
                    }
                    setShowCloseConfirmModal(true);
                  }}
                  className="w-full py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-red-500 to-red-600 hover:shadow-lg hover:shadow-red-500/20 flex items-center justify-center gap-2 transition-all text-sm"
                >
                  <X className="w-4 h-4" /> Close Ticket
                </button>
              )}
            </div>
          )}
          {/* Admin: Link Ticket — navigate to create-ticket with linked context */}
          {isAdmin && ticket.status === 'Closed' && (
            <div className="space-y-3">
              <button
                type="button"
                onClick={() => navigate(`${routeBase}/create-ticket?linkedTicketId=${btData?.id}&linkedStf=${encodeURIComponent(btData?.stf_no || '')}`)}
                className="w-full py-3 rounded-xl font-semibold text-gray-700 dark:text-gray-200 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center justify-center gap-2 transition-all text-sm"
              >
                <Link2 className="w-4 h-4" /> Link Ticket / Same Problem
              </button>
            </div>
          )}
        </div>
      </div>

      {/* ═══════════════════════════════════════════════════════════
           ENHANCED CHAT PANEL
           ═══════════════════════════════════════════════════════════ */}
      {showChat && (
        <div
          className={`fixed z-50 flex flex-col bg-white dark:bg-gray-900 rounded-2xl shadow-2xl border border-gray-200 dark:border-gray-700 overflow-hidden transition-all duration-300 ease-in-out ${
            chatExpanded
              ? 'right-4 bottom-4 top-4 left-4 lg:left-[calc(50%-24rem)] lg:right-4 lg:top-4 lg:bottom-4'
              : 'right-2 sm:right-6 bottom-2 sm:bottom-6 w-[calc(100vw-1rem)] sm:w-[420px] max-w-[calc(100vw-1rem)] sm:max-w-[calc(100vw-3rem)] h-[70vh] sm:h-[600px] max-h-[calc(100vh-1rem)] sm:max-h-[calc(100vh-6rem)]'
          }`}
        >
          {/* ── Chat Header ── */}
          <div className="flex-shrink-0 flex items-center justify-between px-4 py-3 border-b border-gray-200 dark:border-gray-700 bg-gradient-to-r from-[#0E8F79] to-[#0b7a67]">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-full bg-white/20 flex items-center justify-center">
                <MessageSquare className="w-4 h-4 text-white" />
              </div>
              <div>
                <div className="text-sm font-semibold text-white">
                  {isAdmin ? 'Supervisor ↔ Technical' : 'Technical ↔ Supervisor'}
                </div>
                <div className="flex items-center gap-1.5">
                  {wsConnected ? (
                    <span className="flex items-center gap-1 text-[10px] text-green-200">
                      <span className="w-1.5 h-1.5 rounded-full bg-green-300 animate-pulse" /> Connected
                    </span>
                  ) : backendTicketId ? (
                    <span className="flex items-center gap-1 text-[10px] text-yellow-200">
                      <WifiOff className="w-2.5 h-2.5" /> Reconnecting…
                    </span>
                  ) : (
                    <span className="text-[10px] text-white/60">Offline mode</span>
                  )}
                </div>
              </div>
            </div>
            <div className="flex items-center gap-1">
              {/* Search toggle */}
              <button
                onClick={() => { setShowChatSearch(!showChatSearch); setChatSearch(''); }}
                className="p-1.5 rounded-lg text-white/70 hover:text-white hover:bg-white/10 transition-colors"
                title="Search messages"
              >
                <SearchIcon className="w-4 h-4" />
              </button>
              {/* Expand/Collapse */}
              <button
                onClick={() => setChatExpanded(!chatExpanded)}
                className="p-1.5 rounded-lg text-white/70 hover:text-white hover:bg-white/10 transition-colors"
                title={chatExpanded ? 'Minimize' : 'Maximize'}
              >
                {chatExpanded ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
              </button>
              {/* Close */}
              <button
                onClick={() => setShowChat(false)}
                className="p-1.5 rounded-lg text-white/70 hover:text-white hover:bg-white/10 transition-colors"
                aria-label="Close chat"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          </div>

          {/* ── Search Bar (conditional) ── */}
          {showChatSearch && (
            <div className="flex-shrink-0 px-3 py-2 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800">
              <div className="relative">
                <SearchIcon className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-400" />
                <input
                  autoFocus
                  value={chatSearch}
                  onChange={(e) => setChatSearch(e.target.value)}
                  placeholder="Search messages..."
                  className="w-full pl-8 pr-3 py-1.5 rounded-lg border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-900 text-xs text-gray-900 dark:text-gray-100 outline-none focus:ring-2 focus:ring-[#0E8F79]/30"
                />
                {chatSearch && (
                  <span className="absolute right-2.5 top-1/2 -translate-y-1/2 text-[10px] text-gray-400">
                    {filteredMessages.length} result{filteredMessages.length !== 1 ? 's' : ''}
                  </span>
                )}
              </div>
            </div>
          )}

          {/* ── Messages Area ── */}
          <div className="flex-1 relative overflow-hidden">
            {/* Persistent watermark logo */}
            <div className="pointer-events-none absolute inset-0 flex items-center justify-center z-0">
              <img
                src="/Maptech Official Logo version2 (1).png"
                alt=""
                className="w-40 h-auto opacity-40 dark:opacity-40 dark:brightness-150 dark:contrast-125 select-none"
                draggable={false}
              />
            </div>

            <div
              ref={chatScrollRef}
              onScroll={handleChatScroll}
              className="h-full overflow-y-auto overflow-x-hidden px-4 py-3 space-y-1 scroll-smooth relative z-[1]"
              style={{ scrollbarWidth: 'thin', scrollbarColor: '#d1d5db transparent' }}
            >
            {chatMessages.length === 0 && (
              <div className="flex flex-col items-center text-center pt-4">
                <p className="text-sm font-medium text-gray-500 dark:text-gray-400">No messages yet</p>
                <p className="text-xs text-gray-400 dark:text-gray-500 mt-1 max-w-[240px] sm:max-w-[200px]">Start the conversation between supervisor and technical here.</p>
              </div>
            )}

            {messageGroups.map((group) => (
              <React.Fragment key={group.date}>
                {/* ── Date Separator ── */}
                <div className="flex items-center gap-3 py-3">
                  <div className="flex-1 h-px bg-gray-200 dark:bg-gray-700" />
                  <span className="text-[10px] font-medium text-gray-400 dark:text-gray-500 uppercase tracking-wider whitespace-nowrap">
                    {group.date}
                  </span>
                  <div className="flex-1 h-px bg-gray-200 dark:bg-gray-700" />
                </div>

                {group.messages.map((m, i) => {
                  const mine = isMine(m);
                  const prevMsg = i > 0 ? group.messages[i - 1] : null;
                  const isConsecutive = prevMsg && prevMsg.sender_id === m.sender_id && !m.is_system_message && !prevMsg.is_system_message;
                  const RoleIcon = getRoleIcon(m.sender_role);

                  // System message
                  if (m.is_system_message) {
                    return (
                      <div key={m.id ?? `sys-${i}`} className="flex justify-center py-2">
                        <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-amber-50 dark:bg-amber-900/20 border border-amber-200/50 dark:border-amber-700/30">
                          <span className="text-[10px] text-amber-600 dark:text-amber-400 font-medium">{m.content}</span>
                        </div>
                      </div>
                    );
                  }

                  const msgKey = m.id != null ? `id-${m.id}` : `idx-${i}`;

                  return (
                    <div
                      key={msgKey}
                      className={`group flex items-end gap-2 ${mine ? 'flex-row-reverse' : 'flex-row'} ${isConsecutive ? 'mt-0.5' : 'mt-3'}`}
                      onMouseEnter={() => setHoveredMsgKey(msgKey)}
                      onMouseLeave={() => { setHoveredMsgKey(null); setShowEmojiPicker(null); }}
                    >
                      {/* Avatar */}
                      {!isConsecutive ? (
                        <div className={`flex-shrink-0 w-8 h-8 rounded-full ${getAvatarColor(m.sender_role)} flex items-center justify-center shadow-sm`}>
                          <span className="text-[10px] font-bold text-white">{getInitials(m.sender_username)}</span>
                        </div>
                      ) : (
                        <div className="w-8 flex-shrink-0" />
                      )}

                      {/* Message Content */}
                      <div className={`relative max-w-[75%] min-w-0 ${mine ? 'items-end' : 'items-start'} flex flex-col`}>
                        {/* Sender Name + Role badge (first in group) */}
                        {!isConsecutive && !mine && (
                          <div className="flex items-center gap-1.5 mb-1 ml-1">
                            <span className="text-[11px] font-semibold text-gray-600 dark:text-gray-300">{m.sender_username}</span>
                            <span className={`inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded-full text-[9px] font-medium uppercase tracking-wider ${
                              m.sender_role === 'admin' || m.sender_role === 'superadmin'
                                ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400'
                                : 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400'
                            }`}>
                              <RoleIcon className="w-2.5 h-2.5" />
                              {m.sender_role}
                            </span>
                          </div>
                        )}

                        {/* Reply preview */}
                        {m.reply_to && (
                          <div className={`mb-1 px-2.5 py-1.5 rounded-lg text-[11px] border-l-2 border-[#0E8F79] overflow-hidden max-w-full min-w-0 ${
                            mine
                              ? 'bg-[#0E8F79]/20 text-white/80 self-end'
                              : 'bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400'
                          }`}>
                            <div className="flex items-center gap-1 mb-0.5">
                              <CornerDownRight className="w-2.5 h-2.5 flex-shrink-0" />
                              <span className="font-semibold truncate">{m.reply_to.sender_username}</span>
                            </div>
                            <p className="truncate opacity-80">{m.reply_to.content}</p>
                          </div>
                        )}

                        {/* Bubble + hover actions row */}
                        <div className="relative">
                          {/* Emoji picker popover – FB Messenger style floating bar above bubble */}
                          {showEmojiPicker === msgKey && (
                            <div className={`absolute bottom-full mb-1 ${mine ? 'right-0' : 'left-0'} bg-white dark:bg-gray-800 rounded-full shadow-xl border border-gray-200 dark:border-gray-600 px-2 py-1.5 z-20 flex gap-0.5`}>
                              {QUICK_EMOJIS.map((emoji) => (
                                <button
                                  key={emoji}
                                  onClick={() => { chatSocketRef.current?.react(m.id!, emoji); setShowEmojiPicker(null); }}
                                  className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 text-base transition-all hover:scale-125 active:scale-90"
                                >
                                  {emoji}
                                </button>
                              ))}
                            </div>
                          )}

                          <div className={`flex items-center gap-1 ${mine ? 'flex-row-reverse' : 'flex-row'}`}>
                            {/* Bubble */}
                            <div
                              className={`overflow-hidden text-[13px] leading-relaxed ${
                                mine
                                  ? 'bg-[#0E8F79] text-white rounded-2xl rounded-br-md shadow-sm'
                                  : 'bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-gray-100 rounded-2xl rounded-bl-md shadow-sm'
                              }`}
                            >
                              {/* Attachments inside bubble */}
                              {m.attachments && m.attachments.length > 0 && (
                                <div className={`${m.content ? '' : ''} ${m.attachments.length > 1 ? 'grid grid-cols-1 sm:grid-cols-2 gap-0.5' : ''}`}>
                                  {m.attachments.map((att, ai) => {
                                    const attType = att.file_type?.startsWith('image') ? 'image' : att.file_type?.startsWith('video') ? 'video' : (att.file_type as string);
                                    if (attType === 'image') {
                                      return (
                                        <button
                                          key={ai}
                                          onClick={() => setLightboxUrl(att.file_url)}
                                          className="block w-full cursor-pointer hover:opacity-90 transition-opacity"
                                        >
                                          <img
                                            src={att.file_url}
                                            alt={att.file_name}
                                            className="w-full max-h-52 object-cover"
                                            loading="lazy"
                                          />
                                        </button>
                                      );
                                    }
                                    if (attType === 'video') {
                                      return (
                                        <div key={ai} className="relative">
                                          <video
                                            src={att.file_url}
                                            className="w-full max-h-52 object-cover"
                                            controls
                                            preload="metadata"
                                            playsInline
                                          />
                                        </div>
                                      );
                                    }
                                    // Generic file
                                    const FileIcon = getFileIcon(attType);
                                    return (
                                      <a
                                        key={ai}
                                        href={att.file_url}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className={`flex items-center gap-2 px-3 py-2 m-1 rounded-lg transition-colors ${
                                          mine
                                            ? 'bg-white/10 hover:bg-white/20'
                                            : 'bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600'
                                        }`}
                                      >
                                        <div className={`w-9 h-9 rounded-lg flex items-center justify-center flex-shrink-0 ${
                                          mine ? 'bg-white/20' : 'bg-[#0E8F79]/10'
                                        }`}>
                                          <FileIcon className={`w-4 h-4 ${mine ? 'text-white' : 'text-[#0E8F79]'}`} />
                                        </div>
                                        <div className="min-w-0 flex-1">
                                          <div className={`text-xs font-medium truncate ${mine ? 'text-white' : 'text-gray-700 dark:text-gray-200'}`}>{att.file_name}</div>
                                          {att.file_size && (
                                            <div className={`text-[10px] ${mine ? 'text-white/60' : 'text-gray-400'}`}>{formatFileSize(att.file_size)}</div>
                                          )}
                                        </div>
                                        <Download className={`w-3.5 h-3.5 flex-shrink-0 ${mine ? 'text-white/60' : 'text-gray-400'}`} />
                                      </a>
                                    );
                                  })}
                                </div>
                              )}
                              {/* Text content */}
                              {m.content && <div className="px-3.5 py-2 break-words overflow-hidden" style={{ overflowWrap: 'anywhere' }}>{m.content}</div>}
                            </div>

                            {/* Hover actions – side of bubble */}
                            {hoveredMsgKey === msgKey && (
                              <div className="flex items-center gap-0.5">
                                <button
                                  onClick={() => { setReplyTo(m); inputRef.current?.focus(); }}
                                  className="p-1 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
                                  title="Reply"
                                >
                                  <Reply className="w-3.5 h-3.5" />
                                </button>
                                <button
                                  onClick={() => setShowEmojiPicker(showEmojiPicker === msgKey ? null : msgKey)}
                                  className="p-1 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
                                  title="React"
                                >
                                  <Smile className="w-3.5 h-3.5" />
                                </button>
                              </div>
                            )}
                          </div>

                          {/* FB Messenger-style reaction pills – floating at bottom of bubble */}
                          {Object.keys(m.reactions).length > 0 && (
                            <div className={`flex items-center -mt-2 mb-1 ${mine ? 'justify-end pr-2' : 'justify-start pl-2'}`}>
                              <div className="inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded-full bg-white dark:bg-gray-800 shadow-md border border-gray-100 dark:border-gray-600">
                                {Object.entries(m.reactions).map(([emoji, users]) => {
                                  const iReacted = users.some((u) => u.user_id === (user?.id ?? 0));
                                  return (
                                    <button
                                      key={emoji}
                                      onClick={() => chatSocketRef.current?.react(m.id!, emoji)}
                                      className={`flex items-center gap-0.5 px-1 py-0.5 rounded-full text-xs hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors ${
                                        iReacted ? 'bg-[#0E8F79]/10' : ''
                                      }`}
                                      title={users.map((u) => u.username).join(', ')}
                                    >
                                      <span className="text-sm">{emoji}</span>
                                      {users.length > 1 && <span className="text-[10px] font-medium text-gray-500">{users.length}</span>}
                                    </button>
                                  );
                                })}
                              </div>
                            </div>
                          )}
                        </div>

                        {/* Time + Read receipt */}
                        <div className={`flex items-center gap-1.5 mt-0.5 ${mine ? 'justify-end mr-1' : 'ml-1'}`}>
                          <span className="text-[10px] text-gray-400 dark:text-gray-500">{formatTime(m.created_at)}</span>
                          {mine && (
                            m.read_by.length > 0
                              ? <span title={`Read by ${m.read_by.map((r) => r.username).join(', ')}`}><CheckCheck className="w-3 h-3 text-blue-400" /></span>
                              : <span title="Sent"><Check className="w-3 h-3 text-gray-400" /></span>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </React.Fragment>
            ))}

            {/* Typing indicators */}
            {typingUsers.size > 0 && (
              <div className="flex items-center gap-2 mt-2 ml-10">
                <div className="flex items-center gap-1 px-3 py-2 rounded-2xl bg-gray-100 dark:bg-gray-800">
                  <div className="flex gap-0.5">
                    <span className="w-1.5 h-1.5 rounded-full bg-gray-400 animate-bounce" style={{ animationDelay: '0ms' }} />
                    <span className="w-1.5 h-1.5 rounded-full bg-gray-400 animate-bounce" style={{ animationDelay: '150ms' }} />
                    <span className="w-1.5 h-1.5 rounded-full bg-gray-400 animate-bounce" style={{ animationDelay: '300ms' }} />
                  </div>
                </div>
                <span className="text-[10px] text-gray-400 dark:text-gray-500">
                  {Array.from(typingUsers.values()).join(', ')} typing…
                </span>
              </div>
            )}

            <div ref={chatBottomRef} />
          </div>

          {/* ── Scroll-to-bottom FAB ── */}
          {showScrollDown && (
            <div className="absolute bottom-20 left-1/2 -translate-x-1/2 z-10">
              <button
                onClick={scrollToBottom}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-white dark:bg-gray-800 shadow-lg border border-gray-200 dark:border-gray-600 text-xs text-gray-600 dark:text-gray-300 hover:shadow-xl transition-all"
              >
                <ChevronDown className="w-3.5 h-3.5" />
                {unreadCount > 0 ? `${unreadCount} new message${unreadCount > 1 ? 's' : ''}` : 'Scroll to bottom'}
              </button>
            </div>
          )}
          </div>

          {/* ── Reply Preview Bar ── */}
          {replyTo && (
            <div className="flex-shrink-0 flex items-center gap-2 px-4 py-2 border-t border-gray-200 dark:border-gray-700 bg-[#0E8F79]/5 dark:bg-[#0E8F79]/10">
              <CornerDownRight className="w-4 h-4 text-[#0E8F79] flex-shrink-0" />
              <div className="flex-1 min-w-0">
                <div className="text-[10px] font-semibold text-[#0E8F79]">Replying to {replyTo.sender_username}</div>
                <div className="text-xs text-gray-500 dark:text-gray-400 truncate break-words" style={{ overflowWrap: 'anywhere' }}>{replyTo.content}</div>
              </div>
              <button
                onClick={() => setReplyTo(null)}
                className="p-1 rounded hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-400 transition-colors flex-shrink-0"
              >
                <X className="w-3.5 h-3.5" />
              </button>
            </div>
          )}

          {/* ── Input Area ── */}
          <div className="flex-shrink-0 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/80">
            {/* Emoji Picker Popover */}
            {showInputEmoji && (
              <div className="mx-3 mt-2 bg-white dark:bg-gray-900 rounded-xl shadow-xl border border-gray-200 dark:border-gray-600 overflow-hidden">
                <div className="max-h-52 overflow-y-auto p-2 space-y-2" style={{ scrollbarWidth: 'thin' }}>
                  {INPUT_EMOJIS.map((cat) => (
                    <div key={cat.label}>
                      <div className="text-[10px] font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider px-1 mb-1">{cat.label}</div>
                      <div className="flex flex-wrap gap-0.5">
                        {cat.emojis.map((emoji) => (
                          <button
                            key={emoji}
                            onClick={() => {
                              setNewMsg((prev) => prev + emoji);
                              inputRef.current?.focus();
                            }}
                            className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 text-lg transition-transform hover:scale-110"
                          >
                            {emoji}
                          </button>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* File preview strip */}
            {previewUrls.length > 0 && (
              <div className="px-3 pt-2 flex gap-2 overflow-x-auto" style={{ scrollbarWidth: 'thin' }}>
                {previewUrls.map((p, idx) => (
                  <div key={idx} className="relative flex-shrink-0 group/preview">
                    {p.type === 'image' ? (
                      <img src={p.url} alt={p.file.name} className="w-16 h-16 rounded-lg object-cover border border-gray-200 dark:border-gray-600" />
                    ) : p.type === 'video' ? (
                      <div className="w-16 h-16 rounded-lg border border-gray-200 dark:border-gray-600 bg-gray-900 flex items-center justify-center relative overflow-hidden">
                        <video src={p.url} className="w-full h-full object-cover opacity-60" muted playsInline preload="metadata" />
                        <Play className="w-5 h-5 text-white absolute" />
                      </div>
                    ) : (
                      <div className="w-16 h-16 rounded-lg border border-gray-200 dark:border-gray-600 bg-gray-100 dark:bg-gray-700 flex flex-col items-center justify-center px-1">
                        <File className="w-5 h-5 text-gray-400 mb-0.5" />
                        <span className="text-[8px] text-gray-500 truncate w-full text-center">{p.file.name.split('.').pop()?.toUpperCase()}</span>
                      </div>
                    )}
                    {/* Remove button */}
                    <button
                      onClick={() => removePendingFile(idx)}
                      className="absolute -top-1.5 -right-1.5 w-5 h-5 rounded-full bg-red-500 text-white flex items-center justify-center shadow-md opacity-0 group-hover/preview:opacity-100 transition-opacity"
                    >
                      <X className="w-3 h-3" />
                    </button>
                    {/* File size */}
                    <div className="absolute bottom-0.5 left-0.5 right-0.5 text-center">
                      <span className="text-[8px] bg-black/50 text-white px-1 rounded">{formatFileSize(p.file.size)}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Hidden file input */}
            <input
              ref={fileInputRef}
              type="file"
              multiple
              accept="image/*,video/*,.pdf,.doc,.docx,.xls,.xlsx,.txt,.zip,.rar"
              onChange={(e) => { handleFileSelect(e.target.files); e.target.value = ''; }}
              className="hidden"
            />

            <div className="flex items-end gap-1.5 px-3 py-3">
              {/* Attachment button */}
              <button
                onClick={() => fileInputRef.current?.click()}
                className="flex-shrink-0 w-9 h-9 rounded-xl flex items-center justify-center text-gray-400 hover:text-[#0E8F79] hover:bg-gray-100 dark:hover:bg-gray-700 transition-all"
                title="Attach file"
              >
                <Paperclip className="w-5 h-5" />
              </button>

              {/* Emoji toggle button */}
              <button
                onClick={() => setShowInputEmoji(!showInputEmoji)}
                className={`flex-shrink-0 w-9 h-9 rounded-xl flex items-center justify-center transition-all ${
                  showInputEmoji
                    ? 'bg-[#0E8F79]/10 text-[#0E8F79] ring-2 ring-[#0E8F79]/30'
                    : 'text-gray-400 hover:text-[#0E8F79] hover:bg-gray-100 dark:hover:bg-gray-700'
                }`}
                title="Emoji"
              >
                <Smile className="w-5 h-5" />
              </button>

              <div className="flex-1 relative">
                <input
                  ref={inputRef}
                  value={newMsg}
                  onChange={(e) => { setNewMsg(e.target.value); handleTyping(); }}
                  onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); setShowInputEmoji(false); } }}
                  onFocus={() => { /* keep picker open */ }}
                  placeholder={replyTo ? `Reply to ${replyTo.sender_username}...` : pendingFiles.length > 0 ? 'Add a caption...' : 'Type a message...'}
                  className="w-full px-4 py-2.5 rounded-xl border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-900 text-sm text-gray-900 dark:text-gray-100 outline-none focus:ring-2 focus:ring-[#0E8F79]/30 focus:border-[#0E8F79] transition-all placeholder:text-gray-400"
                />
              </div>
              <button
                onClick={() => { sendMessage(); setShowInputEmoji(false); }}
                disabled={!newMsg.trim() && pendingFiles.length === 0}
                className="flex-shrink-0 w-10 h-10 rounded-xl bg-[#0E8F79] hover:bg-[#0b7a67] disabled:opacity-40 disabled:cursor-not-allowed flex items-center justify-center text-white transition-all hover:shadow-md disabled:hover:shadow-none"
                title="Send message"
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>
      )}
      {/* ── Admin Edit Modal ── */}
      {adminEditOpen && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-[#0f172a] border border-gray-200 dark:border-white/10 rounded-2xl w-full max-w-md shadow-2xl">
            <div className="flex items-center justify-between px-6 pt-5 pb-4 border-b border-gray-200 dark:border-white/10">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-[#3BC25B]/20 flex items-center justify-center">
                  <PenLine className="w-4 h-4 text-[#3BC25B]" />
                </div>
                <div>
                  <h3 className="text-gray-900 dark:text-white font-semibold text-sm">Edit Ticket</h3>
                  <p className="text-gray-400 dark:text-white/40 text-xs">Update status and priority</p>
                </div>
              </div>
              <button onClick={() => setAdminEditOpen(false)} className="w-8 h-8 rounded-lg bg-gray-100 dark:bg-white/5 hover:bg-gray-200 dark:hover:bg-white/10 flex items-center justify-center text-gray-400 dark:text-white/50 hover:text-gray-600 dark:hover:text-white transition-all">
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="px-6 py-5 space-y-4">
              <div>
                <label className="block text-xs text-gray-500 dark:text-white/50 font-medium mb-2 uppercase tracking-wider">Status</label>
                <select value={adminEditFields.status} onChange={(e) => setAdminEditFields((p) => ({ ...p, status: e.target.value as typeof p.status }))} className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-[#3BC25B] outline-none">
                  {ADMIN_STATUSES.map((s) => <option key={s}>{s}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs text-gray-500 dark:text-white/50 font-medium mb-2 uppercase tracking-wider">Priority</label>
                <select value={adminEditFields.priority} onChange={(e) => setAdminEditFields((p) => ({ ...p, priority: e.target.value as typeof p.priority }))} className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg text-sm bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-[#3BC25B] outline-none">
                  {ADMIN_PRIORITIES.map((p) => <option key={p}>{p}</option>)}
                </select>
              </div>
            </div>

            <div className="flex items-center gap-3 px-6 pb-6">
              <button type="button" onClick={() => setAdminEditOpen(false)} className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 text-gray-500 dark:text-white/60 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-white/5 text-sm font-medium transition-all">Cancel</button>
              <button type="button" disabled={savingAdminEdit} onClick={async () => { setSavingAdminEdit(true); await saveAdminEdit(); setSavingAdminEdit(false); }} className="flex-1 py-2.5 rounded-xl bg-[#3BC25B] text-white text-sm font-semibold hover:shadow-lg disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2">
                {savingAdminEdit ? <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Saving...</> : <>Save Changes</>}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Delete Confirmation Modal (Admin) ── */}
      {showDeleteConfirm && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-[#0f172a] border border-gray-200 dark:border-white/10 rounded-2xl w-full max-w-md shadow-2xl">
            <div className="flex items-center justify-between px-6 pt-5 pb-4 border-b border-gray-200 dark:border-white/10">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-red-100 dark:bg-red-900/20 flex items-center justify-center">
                  <Trash2 className="w-4 h-4 text-red-600" />
                </div>
                <div>
                  <h3 className="text-gray-900 dark:text-white font-semibold text-sm">Delete Ticket</h3>
                  <p className="text-gray-400 dark:text-white/40 text-xs">This action cannot be undone.</p>
                </div>
              </div>
              <button onClick={() => setShowDeleteConfirm(false)} className="w-8 h-8 rounded-lg bg-gray-100 dark:bg-white/5 hover:bg-gray-200 dark:hover:bg-white/10 flex items-center justify-center text-gray-400 dark:text-white/50 hover:text-gray-600 dark:hover:text-white transition-all">
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="px-6 py-5">
              <p className="text-sm text-gray-700 dark:text-gray-300">Are you sure you want to permanently delete ticket <span className="font-mono text-xs text-[#0E8F79]">{ticket.id}</span>?</p>
            </div>

            <div className="flex items-center gap-3 px-6 pb-6">
              <button type="button" onClick={() => setShowDeleteConfirm(false)} className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 text-gray-500 dark:text-white/60 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-white/5 text-sm font-medium transition-all">Cancel</button>
              <button type="button" disabled={deletingAdmin} onClick={confirmAdminDelete} className="flex-1 py-2.5 rounded-xl bg-red-600 text-white text-sm font-semibold hover:shadow-lg disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2">
                {deletingAdmin ? <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Deleting...</> : <>Delete Ticket</>}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Image Lightbox ── */}
      {lightboxUrl && (
        <div
          className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4"
          onClick={() => setLightboxUrl(null)}
        >
          <button
            onClick={() => setLightboxUrl(null)}
            className="absolute top-4 right-4 w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center text-white transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
          <img
            src={lightboxUrl}
            alt="Preview"
            className="max-w-full max-h-full rounded-lg shadow-2xl object-contain"
            onClick={(e) => e.stopPropagation()}
          />
          <a
            href={lightboxUrl}
            download
            onClick={(e) => e.stopPropagation()}
            className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 px-4 py-2 rounded-full bg-white/10 hover:bg-white/20 text-white text-sm transition-colors"
          >
            <Download className="w-4 h-4" /> Download
          </a>
        </div>
      )}

      {/* ── Video Lightbox ── */}
      {videoLightboxUrl && (
        <div
          className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4"
          onClick={() => setVideoLightboxUrl(null)}
        >
          <button
            onClick={() => setVideoLightboxUrl(null)}
            className="absolute top-4 right-4 w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center text-white transition-colors z-10"
          >
            <X className="w-6 h-6" />
          </button>
          <video
            src={videoLightboxUrl}
            controls
            autoPlay
            playsInline
            preload="auto"
            className="max-w-full max-h-full rounded-lg shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          />
          <a
            href={videoLightboxUrl}
            download
            onClick={(e) => e.stopPropagation()}
            className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 px-4 py-2 rounded-full bg-white/10 hover:bg-white/20 text-white text-sm transition-colors"
          >
            <Download className="w-4 h-4" /> Download
          </a>
        </div>
      )}

      {/* ── Start Work Confirm Modal ── */}
      {showStartWorkConfirm && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-[#0f172a] border border-gray-200 dark:border-white/10 rounded-2xl w-full max-w-sm shadow-2xl">
            <div className="flex items-center justify-between px-6 pt-5 pb-4 border-b border-gray-200 dark:border-white/10">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-blue-500/20 flex items-center justify-center">
                  <PlayCircle className="w-4 h-4 text-blue-500" />
                </div>
                <h3 className="text-gray-900 dark:text-white font-semibold text-sm">Start Work</h3>
              </div>
              <button onClick={() => setShowStartWorkConfirm(false)} className="w-8 h-8 rounded-lg bg-gray-100 dark:bg-white/5 hover:bg-gray-200 dark:hover:bg-white/10 flex items-center justify-center text-gray-400 dark:text-white/50 hover:text-gray-600 dark:hover:text-white transition-all">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="px-6 py-5">
              <p className="text-sm text-gray-600 dark:text-gray-300">Are you sure you want to start working on this ticket? This will record your start time.</p>
            </div>
            <div className="flex items-center gap-3 px-6 pb-6">
              <button type="button" onClick={() => setShowStartWorkConfirm(false)} className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 text-gray-500 dark:text-white/60 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-white/5 text-sm font-medium transition-all">Cancel</button>
              <button
                type="button"
                disabled={startingWork}
                onClick={() => { setShowStartWorkConfirm(false); handleStartWork(); }}
                className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-blue-500 to-blue-600 text-white text-sm font-semibold hover:shadow-lg hover:shadow-blue-500/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all"
              >
                {startingWork ? <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Starting...</> : <><PlayCircle className="w-3.5 h-3.5" /> Start Work</>}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Submit for Observation Confirm Modal ── */}
      {showObservationConfirm && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-[#0f172a] border border-gray-200 dark:border-white/10 rounded-2xl w-full max-w-sm shadow-2xl">
            <div className="flex items-center justify-between px-6 pt-5 pb-4 border-b border-gray-200 dark:border-white/10">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-indigo-500/20 flex items-center justify-center">
                  <Eye className="w-4 h-4 text-indigo-500" />
                </div>
                <h3 className="text-gray-900 dark:text-white font-semibold text-sm">Submit for Observation</h3>
              </div>
              <button onClick={() => setShowObservationConfirm(false)} className="w-8 h-8 rounded-lg bg-gray-100 dark:bg-white/5 hover:bg-gray-200 dark:hover:bg-white/10 flex items-center justify-center text-gray-400 dark:text-white/50 hover:text-gray-600 dark:hover:text-white transition-all">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="px-6 py-5">
              <p className="text-sm text-gray-600 dark:text-gray-300">Are you sure you want to submit this ticket for observation? The client will be notified to review the resolution.</p>
            </div>
            <div className="flex items-center gap-3 px-6 pb-6">
              <button type="button" onClick={() => setShowObservationConfirm(false)} className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 text-gray-500 dark:text-white/60 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-white/5 text-sm font-medium transition-all">Cancel</button>
              <button
                type="button"
                disabled={submittingObservation}
                onClick={() => { setShowObservationConfirm(false); handleSubmitForObservation(); }}
                className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-indigo-500 to-indigo-600 text-white text-sm font-semibold hover:shadow-lg hover:shadow-indigo-500/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all"
              >
                {submittingObservation ? <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Submitting...</> : <><Eye className="w-3.5 h-3.5" /> Submit</>}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Resolve Ticket Confirm Modal ── */}
      {showResolveConfirm && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-[#0f172a] border border-gray-200 dark:border-white/10 rounded-2xl w-full max-w-sm shadow-2xl">
            <div className="flex items-center justify-between px-6 pt-5 pb-4 border-b border-gray-200 dark:border-white/10">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-teal-500/20 flex items-center justify-center">
                  <CheckCircle className="w-4 h-4 text-teal-500" />
                </div>
                <h3 className="text-gray-900 dark:text-white font-semibold text-sm">Resolve Ticket</h3>
              </div>
              <button onClick={() => setShowResolveConfirm(false)} className="w-8 h-8 rounded-lg bg-gray-100 dark:bg-white/5 hover:bg-gray-200 dark:hover:bg-white/10 flex items-center justify-center text-gray-400 dark:text-white/50 hover:text-gray-600 dark:hover:text-white transition-all">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="px-6 py-5">
              <p className="text-sm text-gray-600 dark:text-gray-300">Are you sure you want to mark this ticket as resolved? Make sure all required fields and attachments are completed before proceeding.</p>
              {!canResolveTicket && (
                <p className="mt-2 text-xs text-red-500">Missing: {missingResolveFields.join(', ')}</p>
              )}
            </div>
            <div className="flex items-center gap-3 px-6 pb-6">
              <button type="button" onClick={() => setShowResolveConfirm(false)} className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 text-gray-500 dark:text-white/60 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-white/5 text-sm font-medium transition-all">Cancel</button>
              <button
                type="button"
                disabled={savingFields || !canResolveTicket}
                onClick={() => { setShowResolveConfirm(false); handleSaveFields(); }}
                className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-[#0E8F79] to-[#0b7a67] text-white text-sm font-semibold hover:shadow-lg hover:shadow-[#0E8F79]/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all"
              >
                {savingFields ? <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Resolving...</> : <><CheckCircle className="w-3.5 h-3.5" /> Resolve</>}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Feedback Ratings Modal (Admin – before closing) ── */}
      {showFeedbackRatingModal && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-[#0f172a] border border-gray-200 dark:border-white/10 rounded-2xl w-full max-w-md shadow-2xl">
            {/* Header */}
            <div className="flex items-center justify-between px-6 pt-5 pb-4 border-b border-gray-200 dark:border-white/10">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-yellow-500/20 flex items-center justify-center">
                  <Star className="w-4 h-4 text-yellow-500" />
                </div>
                <div>
                  <h3 className="text-gray-900 dark:text-white font-semibold text-sm">Feedback Ratings</h3>
                  <p className="text-gray-400 dark:text-white/40 text-xs">Submit feedback ratings before closing this ticket</p>
                </div>
              </div>
              <button onClick={() => setShowFeedbackRatingModal(false)} className="w-8 h-8 rounded-lg bg-gray-100 dark:bg-white/5 hover:bg-gray-200 dark:hover:bg-white/10 flex items-center justify-center text-gray-400 dark:text-white/50 hover:text-gray-600 dark:hover:text-white transition-all">
                <X className="w-4 h-4" />
              </button>
            </div>

            {/* Body */}
            <div className="px-6 py-5 space-y-5">
              {/* Employee info */}
              <div className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-white/5 rounded-xl">
                <div className="w-10 h-10 rounded-full bg-[#0E8F79] flex items-center justify-center text-white font-bold text-sm">
                  {ticket.assignedTo?.charAt(0)?.toUpperCase() || '?'}
                </div>
                <div>
                  <p className="text-sm font-medium text-gray-900 dark:text-white">{ticket.assignedTo || 'Technical'}</p>
                  <p className="text-xs text-gray-400">Assigned Technical</p>
                </div>
              </div>

              {/* Star Rating */}
              <div>
                <label className="block text-xs text-gray-500 dark:text-white/50 font-medium mb-3 uppercase tracking-wider">Feedback Rating</label>
                <div className="flex items-center justify-center gap-2">
                  {[1, 2, 3, 4, 5].map((s) => (
                    <button
                      key={s}
                      type="button"
                      onClick={() => setFeedbackRatingValue(s)}
                      className="p-1 transition-transform hover:scale-110"
                    >
                      <Star className={`w-8 h-8 transition-colors ${s <= feedbackRatingValue ? 'text-yellow-400 fill-yellow-400' : 'text-gray-300 dark:text-gray-600 hover:text-yellow-300'}`} />
                    </button>
                  ))}
                </div>
                <p className="text-center text-xs text-gray-400 mt-1.5">
                  {feedbackRatingValue === 0 ? 'Click a star to rate' : feedbackRatingValue <= 2 ? 'Needs Improvement' : feedbackRatingValue <= 3 ? 'Satisfactory' : feedbackRatingValue <= 4 ? 'Good' : 'Excellent'}
                </p>
              </div>

              {/* Comments */}
              <div>
                <label className="block text-xs text-gray-500 dark:text-white/50 font-medium mb-1.5 uppercase tracking-wider">Comments (Optional)</label>
                <textarea
                  value={feedbackComments}
                  onChange={(e) => setFeedbackComments(e.target.value)}
                  rows={3}
                  placeholder="Add optional comments about the service provided..."
                  className="w-full px-4 py-2.5 rounded-xl bg-gray-50 dark:bg-white/5 border border-gray-200 dark:border-white/10 text-gray-900 dark:text-white text-sm placeholder-gray-300 dark:placeholder-white/20 focus:outline-none focus:border-yellow-500/60 resize-none transition-colors"
                />
              </div>
            </div>

            {/* Footer */}
            <div className="flex items-center gap-3 px-6 pb-6">
              <button
                type="button"
                onClick={() => { setShowFeedbackRatingModal(false); setFeedbackRatingValue(0); setFeedbackComments(''); }}
                className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 text-gray-500 dark:text-white/60 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-white/5 text-sm font-medium transition-all"
              >
                Cancel
              </button>
              <button
                type="button"
                disabled={submittingFeedbackRating || feedbackRatingValue < 1}
                onClick={handleFeedbackRatingClose}
                className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-red-500 to-red-600 text-white text-sm font-semibold hover:shadow-lg hover:shadow-red-500/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all"
              >
                {submittingFeedbackRating ? (
                  <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Submitting...</>
                ) : (
                  <><Star className="w-3.5 h-3.5" /> Submit & Close</>
                )}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Close Ticket Confirmation Modal ── */}
      {showCloseConfirmModal && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-[#0f172a] border border-gray-200 dark:border-white/10 rounded-2xl w-full max-w-sm shadow-2xl">
            {/* Header */}
            <div className="flex items-center justify-between px-6 pt-5 pb-4 border-b border-gray-200 dark:border-white/10">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-red-500/20 flex items-center justify-center">
                  <AlertTriangle className="w-4 h-4 text-red-500" />
                </div>
                <h3 className="text-gray-900 dark:text-white font-semibold text-sm">Close Ticket</h3>
              </div>
              <button onClick={() => setShowCloseConfirmModal(false)} className="w-8 h-8 rounded-lg bg-gray-100 dark:bg-white/5 hover:bg-gray-200 dark:hover:bg-white/10 flex items-center justify-center text-gray-400 dark:text-white/50 hover:text-gray-600 dark:hover:text-white transition-all">
                <X className="w-4 h-4" />
              </button>
            </div>
            {/* Body */}
            <div className="px-6 py-5">
              <p className="text-sm text-gray-600 dark:text-gray-300">Are you sure you want to close this ticket? This action cannot be undone.</p>
            </div>
            {/* Footer */}
            <div className="flex items-center gap-3 px-6 pb-6">
              <button
                type="button"
                onClick={() => setShowCloseConfirmModal(false)}
                className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 text-gray-500 dark:text-white/60 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-white/5 text-sm font-medium transition-all"
              >
                Cancel
              </button>
              <button
                type="button"
                disabled={closingTicket}
                onClick={handleCloseTicket}
                className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-red-500 to-red-600 text-white text-sm font-semibold hover:shadow-lg hover:shadow-red-500/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all"
              >
                {closingTicket ? (
                  <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Closing...</>
                ) : (
                  <><X className="w-3.5 h-3.5" /> Close Ticket</>
                )}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Escalate Ticket Modal ── */}
      {showEscalateModal && createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white dark:bg-[#0f172a] border border-gray-200 dark:border-white/10 rounded-2xl w-full max-w-md shadow-2xl">
            {/* Header */}
            <div className="flex items-center justify-between px-6 pt-5 pb-4 border-b border-gray-200 dark:border-white/10">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-orange-500/20 flex items-center justify-center">
                  <ArrowUpRight className="w-4 h-4 text-orange-400" />
                </div>
                <div>
                  <h3 className="text-gray-900 dark:text-white font-semibold text-sm">Escalate Ticket</h3>
                  <p className="text-gray-400 dark:text-white/40 text-xs">Route this ticket for higher-level support</p>
                </div>
              </div>
              <button
                onClick={() => setShowEscalateModal(false)}
                className="w-8 h-8 rounded-lg bg-gray-100 dark:bg-white/5 hover:bg-gray-200 dark:hover:bg-white/10 flex items-center justify-center text-gray-400 dark:text-white/50 hover:text-gray-600 dark:hover:text-white transition-all"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            {/* Body */}
            <div className="px-6 py-5 space-y-4">
              {/* Escalation Type — employees choose internal/external; admins are locked to external */}
              {isAdmin ? (
                <div>
                  <label className="block text-xs text-gray-500 dark:text-white/50 font-medium mb-2 uppercase tracking-wider">Escalation Type</label>
                  <div className="flex items-center gap-2 px-3 py-2.5 rounded-xl border border-orange-500 bg-orange-500/10 text-orange-500 dark:text-orange-400 text-sm font-medium">
                    <Share2 className="w-4 h-4" />
                    External
                  </div>
                  <p className="mt-1.5 text-xs text-gray-400 dark:text-white/30">
                    Escalate to an external distributor or vendor.
                  </p>
                </div>
              ) : (
              <div>
                <label className="block text-xs text-gray-500 dark:text-white/50 font-medium mb-2 uppercase tracking-wider">Escalation Type</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  <button
                    type="button"
                    onClick={() => { setEscalateType('internal'); setEscalateToErr(''); }}
                    className={`flex items-center gap-2 px-3 py-2.5 rounded-xl border text-sm font-medium transition-all ${
                      escalateType === 'internal'
                        ? 'border-orange-500 bg-orange-500/10 text-orange-500 dark:text-orange-400'
                        : 'border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-white/5 text-gray-500 dark:text-white/60 hover:bg-gray-100 dark:hover:bg-white/10'
                    }`}
                  >
                    <Shield className="w-4 h-4" />
                    Internal
                  </button>
                  <button
                    type="button"
                    disabled={!!btData?.external_escalated_to}
                    onClick={() => setEscalateType('external')}
                    className={`flex items-center gap-2 px-3 py-2.5 rounded-xl border text-sm font-medium transition-all ${
                      btData?.external_escalated_to
                        ? 'border-gray-200 dark:border-white/10 bg-gray-100 dark:bg-white/5 text-gray-300 dark:text-white/20 cursor-not-allowed'
                        : escalateType === 'external'
                          ? 'border-orange-500 bg-orange-500/10 text-orange-500 dark:text-orange-400'
                          : 'border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-white/5 text-gray-500 dark:text-white/60 hover:bg-gray-100 dark:hover:bg-white/10'
                    }`}
                  >
                    <Share2 className="w-4 h-4" />
                    External {btData?.external_escalated_to ? '(Done)' : ''}
                  </button>
                </div>
                <div className="mt-2 px-3 py-2.5 rounded-xl bg-orange-50 dark:bg-orange-900/10 border border-orange-100 dark:border-orange-500/20">
                  {escalateType === 'internal' ? (
                    <div className="flex gap-2">
                      <Shield className="w-3.5 h-3.5 text-orange-400 mt-0.5 flex-shrink-0" />
                      <div>
                        <p className="text-xs font-semibold text-orange-500 dark:text-orange-400 mb-0.5">Internal Escalation</p>
                        <p className="text-xs text-gray-500 dark:text-white/50 leading-relaxed">Routes this ticket to a supervisor or admin for review and reassignment. Use this when the issue is beyond your current level and requires higher-level internal support.</p>
                      </div>
                    </div>
                  ) : (
                    <div className="flex gap-2">
                      <Share2 className="w-3.5 h-3.5 text-orange-400 mt-0.5 flex-shrink-0" />
                      <div>
                        <p className="text-xs font-semibold text-orange-500 dark:text-orange-400 mb-0.5">External Escalation</p>
                        <p className="text-xs text-gray-500 dark:text-white/50 leading-relaxed">Tags this ticket to an outside distributor or vendor for resolution. Use this when the issue requires third-party support, warranty service, or specialized external expertise.</p>
                      </div>
                    </div>
                  )}
                </div>
              </div>
              )}

              {/* External: Distributor/Vendor field */}
              {escalateType === 'external' && (
                <div>
                  <label className="block text-xs text-gray-500 dark:text-white/50 font-medium mb-1.5 uppercase tracking-wider">
                    Distributor / Vendor Name <span className="text-orange-400">*</span>
                  </label>
                  <input
                    type="text"
                    value={escalateTo}
                    onChange={e => { setEscalateTo(e.target.value); if (escalateToErr) setEscalateToErr(''); }}
                    placeholder="e.g. Acme Distributors"
                    className={`w-full px-4 py-2.5 rounded-xl bg-gray-50 dark:bg-white/5 border text-gray-900 dark:text-white text-sm placeholder-gray-300 dark:placeholder-white/20 focus:outline-none transition-colors ${
                      escalateToErr ? 'border-red-500/60 focus:border-red-500' : 'border-gray-200 dark:border-white/10 focus:border-orange-500/60'
                    }`}
                  />
                  {escalateToErr && <p className="mt-1 text-xs text-red-400">{escalateToErr}</p>}
                </div>
              )}

              {/* Notes / Reason */}
              <div>
                <label className="block text-xs text-gray-500 dark:text-white/50 font-medium mb-1.5 uppercase tracking-wider">
                  Notes / Reason <span className="text-orange-400">*</span>
                </label>
                <textarea
                  value={escalateNotes}
                  onChange={e => { setEscalateNotes(e.target.value); if (escalateNotesErr) setEscalateNotesErr(''); }}
                  rows={3}
                  placeholder="Describe why this ticket cannot be resolved at your level…"
                  className={`w-full px-4 py-2.5 rounded-xl bg-gray-50 dark:bg-white/5 border text-gray-900 dark:text-white text-sm placeholder-gray-300 dark:placeholder-white/20 focus:outline-none resize-none transition-colors ${
                    escalateNotesErr ? 'border-red-500/60 focus:border-red-500' : 'border-gray-200 dark:border-white/10 focus:border-orange-500/60'
                  }`}
                />
                {escalateNotesErr && <p className="mt-1 text-xs text-red-400">{escalateNotesErr}</p>}
              </div>
            </div>

            {/* Footer */}
            <div className="flex items-center gap-3 px-6 pb-6">
              <button
                type="button"
                onClick={() => {
                  setShowEscalateModal(false);
                  setEscalateNotes('');
                  setEscalateTo('');
                  setEscalateNotesErr('');
                  setEscalateToErr('');
                }}
                className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-white/10 text-gray-500 dark:text-white/60 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-white/5 text-sm font-medium transition-all"
              >
                Cancel
              </button>
              <button
                type="button"
                disabled={submittingEscalation}
                onClick={handleEscalateTicket}
                className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-orange-500 to-orange-600 text-white text-sm font-semibold hover:shadow-lg hover:shadow-orange-500/20 disabled:opacity-60 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all"
              >
                {submittingEscalation ? (
                  <><Loader2 className="w-3.5 h-3.5 animate-spin" /> Escalating…</>
                ) : (
                  <><ArrowUpRight className="w-3.5 h-3.5" /> Submit Escalation</>
                )}
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Reassign Ticket Modal ── */}
      {showReassignModal && createPortal(
        <div className="fixed inset-0 z-[9999] bg-black/60 flex items-center justify-center p-4">
          {hasCallPriorityWorkflow && reassignModalStep === 'stf-details' && (
            <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
              <div className="p-6">
                <div className="flex items-center justify-between mb-5">
                  <div>
                    <h3 className="text-lg font-bold text-gray-900 dark:text-white">STF Details</h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400">Review the ticket before proceeding</p>
                  </div>
                  <button
                    onClick={() => {
                      setShowReassignModal(false);
                      setReassignSearch('');
                      setReassignEmployeeId('');
                      resetCallAndPriorityState();
                    }}
                    className="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg"
                  >
                    <X className="w-5 h-5 text-gray-500" />
                  </button>
                </div>

                <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-4 space-y-2 text-sm mb-5 max-h-60 overflow-y-auto">
                  {[
                    ['STF No.', btData?.stf_no || String(ticket.id)],
                    ['Client', btData?.client || ticket.client || ''],
                    ['Contact Person', btData?.contact_person || ticket.client || ''],
                    ['Mobile', btData?.mobile_no || ticket.mobile || '—'],
                    ['Landline', btData?.landline || '—'],
                    ['Email', btData?.email_address || '—'],
                    ['Designation', btData?.designation || '—'],
                    ['Department', btData?.department_organization || '—'],
                    ['Address', btData?.address || '—'],
                    ['Type of Service', btData?.type_of_service_detail?.name || btData?.type_of_service_others || ticket.typeOfService || '—'],
                    ['Support Type', btData?.preferred_support_type || '—'],
                    ['Description', btData?.description_of_problem || ticket.description || '—'],
                  ].map(([label, value]) => (
                    <div key={String(label)} className="flex gap-2">
                      <span className="text-gray-500 dark:text-gray-400 w-32 shrink-0 font-medium">{label}:</span>
                      <span className="text-gray-900 dark:text-white break-words">{String(value || '—')}</span>
                    </div>
                  ))}
                </div>

                <button
                  onClick={handleStartCall}
                  className={`w-full flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg text-sm font-bold transition-colors mb-5 ${callCompleted ? 'bg-gray-100 dark:bg-gray-700 text-green-600 dark:text-green-400 cursor-default' : 'bg-[#3BC25B] hover:bg-[#2ea34a] text-white'}`}
                  disabled={callCompleted || (!!activeTicketCall && activeTicketCall.admin !== user?.id)}
                >
                  {callCompleted ? (
                    <><CheckCircle className="w-4 h-4" /> Call Completed</>
                  ) : (
                    <><Phone className="w-4 h-4" /> Call Client</>
                  )}
                </button>

                {!!activeTicketCall && activeTicketCall.admin !== user?.id && (
                  <div className="mb-4 px-3 py-2 rounded-lg border border-amber-300 bg-amber-50 dark:bg-amber-900/20 dark:border-amber-700 text-amber-800 dark:text-amber-300 text-xs font-medium">
                    Client is currently on call by {activeTicketCall.admin_name || 'another user'}.
                  </div>
                )}

                {canSetPriorityInCallWorkflow && (
                  <>
                    <div className={`${!callCompleted ? 'opacity-40 pointer-events-none' : ''}`}>
                      <p className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Priority Level {!callCompleted && <span className="text-xs font-normal text-gray-400 ml-1">(complete a call first)</span>}</p>
                      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                        {[
                          { label: 'Low', color: 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-700 text-blue-700 dark:text-blue-300', active: 'bg-blue-500 text-white border-blue-500 ring-2 ring-blue-300 dark:ring-blue-700' },
                          { label: 'Medium', color: 'bg-yellow-50 dark:bg-yellow-900/20 border-yellow-200 dark:border-yellow-700 text-yellow-700 dark:text-yellow-300', active: 'bg-yellow-500 text-white border-yellow-500 ring-2 ring-yellow-300 dark:ring-yellow-700' },
                          { label: 'High', color: 'bg-orange-50 dark:bg-orange-900/20 border-orange-200 dark:border-orange-700 text-orange-700 dark:text-orange-300', active: 'bg-orange-500 text-white border-orange-500 ring-2 ring-orange-300 dark:ring-orange-700' },
                          { label: 'Critical', color: 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-700 text-red-700 dark:text-red-300', active: 'bg-red-500 text-white border-red-500 ring-2 ring-red-300 dark:ring-red-700' },
                        ].map(({ label, color, active }) => (
                          <button
                            key={label}
                            type="button"
                            onClick={() => setPriorityLevel(label)}
                            className={`px-2 py-3 rounded-xl border-2 text-xs font-bold transition-all ${priorityLevel === label ? active : `${color} hover:opacity-80`}`}
                          >
                            {label}
                          </button>
                        ))}
                      </div>
                    </div>

                    <div className="mt-5">
                      <button
                        onClick={isAdmin ? handleConfirmPriority : handleSubmitSalesCallStatus}
                        disabled={!callCompleted || !priorityLevel || submittingSalesCallStatus}
                        className="w-full px-4 py-2.5 rounded-lg bg-[#3BC25B] hover:bg-[#2ea34a] text-white text-sm font-bold transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
                      >
                        {isAdmin
                          ? 'Continue to Assign'
                          : (submittingSalesCallStatus ? 'Saving Call Status...' : 'Save Call Status')}
                      </button>
                    </div>
                  </>
                )}
              </div>
            </div>
          )}

          {hasCallPriorityWorkflow && reassignModalStep === 'ongoing' && (
            <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
              <div className="p-8 text-center">
                <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-green-500 flex items-center justify-center">
                  <Phone className="w-10 h-10 text-white animate-bounce" />
                </div>
                <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">Call Connected</h3>
                <p className="text-gray-500 dark:text-gray-400 mb-2">{btData?.contact_person || ticket.client || 'Client'} — {btData?.mobile_no || btData?.landline || ticket.mobile || 'N/A'}</p>
                <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-sm font-medium mb-4 ${callOnHold ? 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400' : 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400'}`}>
                  <span className={`w-2 h-2 rounded-full ${callOnHold ? 'bg-yellow-500' : 'bg-green-500 animate-pulse'}`} /> {callOnHold ? 'On Hold' : 'Ongoing Call'}
                </div>
                <div className={`text-3xl font-bold mb-6 tabular-nums font-mono ${callOnHold ? 'text-yellow-500' : 'text-[#3BC25B]'}`}>
                  {formatCallDuration(callTimer)}
                </div>
                <div className="flex items-center justify-center gap-3">
                  <button
                    onClick={() => {
                      if (callOnHold) {
                        if (holdStartTime) {
                          setHoldOffset((prev) => prev + (Date.now() - holdStartTime));
                        }
                        setHoldStartTime(null);
                        setCallOnHold(false);
                      } else {
                        setHoldStartTime(Date.now());
                        setCallOnHold(true);
                      }
                    }}
                    className={`flex items-center gap-2 px-6 py-3 rounded-full font-semibold transition-colors shadow-lg ${
                      callOnHold
                        ? 'bg-green-500 hover:bg-green-600 text-white shadow-green-500/30'
                        : 'bg-yellow-500 hover:bg-yellow-600 text-white shadow-yellow-500/30'
                    }`}
                  >
                    {callOnHold ? <><Play className="w-5 h-5" /> Resume</> : <><Pause className="w-5 h-5" /> On Hold</>}
                  </button>
                  <button onClick={handleEndCall} className="flex items-center gap-2 px-8 py-3 bg-red-500 hover:bg-red-600 text-white rounded-full font-semibold transition-colors shadow-lg shadow-red-500/30">
                    <PhoneOff className="w-5 h-5" /> End Call
                  </button>
                </div>
              </div>
            </div>
          )}

          {isAdmin && (!hasCallPriorityWorkflow || reassignModalStep === 'assign') && (
            <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-3xl overflow-hidden">
              <div className="p-6">
                <div className="flex items-center justify-between mb-4">
                  <div>
                    <h3 className="text-lg font-bold text-gray-900 dark:text-white">{needsCallPriorityWorkflow ? 'Assign Technical' : 'Reassign Employee'}</h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400">Select a technical to handle this ticket</p>
                  </div>
                  <button
                    onClick={() => {
                      if (needsCallPriorityWorkflow) {
                        setReassignModalStep('stf-details');
                        return;
                      }
                      setShowReassignModal(false);
                      setReassignSearch('');
                      setReassignEmployeeId('');
                      resetCallAndPriorityState();
                    }}
                    className="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg"
                  >
                    <X className="w-5 h-5 text-gray-500" />
                  </button>
                </div>

                <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-3 mb-4 flex flex-col sm:flex-row sm:items-center gap-3 sm:gap-6 text-sm">
                  <div>
                    <span className="text-gray-500 dark:text-gray-400">Ticket: </span>
                    <span className="font-bold text-gray-900 dark:text-white">{btData?.stf_no || ticket.id}</span>
                  </div>
                  {needsCallPriorityWorkflow && (
                    <div>
                      <span className="text-gray-500 dark:text-gray-400">Priority: </span>
                      <span className={`font-semibold ${priorityLevel === 'Critical' ? 'text-red-600' : priorityLevel === 'High' ? 'text-orange-600' : priorityLevel === 'Medium' ? 'text-yellow-600' : 'text-blue-600'}`}>{priorityLevel || '—'}</span>
                    </div>
                  )}
                  {needsCallPriorityWorkflow && (
                    <div>
                      <span className="text-gray-500 dark:text-gray-400">Service: </span>
                      <span className="font-medium text-gray-900 dark:text-white">{btData?.type_of_service_detail?.name || btData?.type_of_service_others || ticket.typeOfService || '—'}</span>
                    </div>
                  )}
                </div>

                <div className="space-y-3 max-h-[26rem] overflow-y-auto pr-1">
                  {employees.length === 0 && (
                    <p className="text-sm text-gray-400 text-center py-4">No technicals found.</p>
                  )}
                  {employees.length > 0 && filteredEmployees.length === 0 && (
                    <p className="text-sm text-gray-400 text-center py-4">No employees match your search.</p>
                  )}
                  {filteredEmployees.map((emp) => {
                    const tickets = employeeTickets[emp.id] || [];
                    const isSelected = reassignEmployeeId === String(emp.id);
                    const name = `${emp.first_name} ${emp.last_name}`.trim() || emp.username;
                    return (
                      <div key={emp.id} className={`rounded-xl border-2 transition-all ${isSelected ? 'border-[#3BC25B] bg-[#f0fdf4] dark:bg-green-900/20 ring-1 ring-[#3BC25B]' : 'border-gray-200 dark:border-gray-600 hover:border-[#3BC25B]'}`}>
                        <button
                          type="button"
                          onClick={() => setReassignEmployeeId(isSelected ? '' : String(emp.id))}
                          className="w-full flex items-center gap-3 p-3 text-left"
                        >
                          <div className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold shrink-0 ${isSelected ? 'bg-[#3BC25B] text-white' : 'bg-gray-200 dark:bg-gray-600 text-gray-600 dark:text-gray-300'}`}>
                            {name.charAt(0).toUpperCase()}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="font-medium text-gray-900 dark:text-white text-sm truncate">{name}</div>
                            <div className="text-xs text-gray-500 dark:text-gray-400">{emp.username}</div>
                          </div>
                          <span className={`text-xs font-medium px-2 py-0.5 rounded-full shrink-0 ${emp.active_ticket_count === 0 ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : emp.active_ticket_count <= 3 ? 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400' : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'}`}>
                            {emp.active_ticket_count} active
                          </span>
                          {isSelected && <CheckCircle className="w-5 h-5 text-[#3BC25B] shrink-0" />}
                          {!isSelected && <div className="w-2 h-2 bg-green-400 rounded-full shrink-0" title="Available" />}
                        </button>

                        {tickets.length > 0 && (
                          <div className="px-3 pb-3">
                            <p className="text-[11px] font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Current Working Tickets</p>
                            <div className="space-y-1.5">
                              {tickets.slice(0, 3).map((t) => (
                                <div key={t.id} className="flex items-center gap-2 bg-white dark:bg-gray-700 rounded-lg px-3 py-2 border border-gray-100 dark:border-gray-600">
                                  <div className="flex-1 min-w-0">
                                    <div className="text-xs font-semibold text-gray-800 dark:text-gray-200 truncate">{t.stf_no}</div>
                                    <div className="text-[11px] text-gray-500 dark:text-gray-400 truncate">{t.type_of_service_detail?.name || 'N/A'}</div>
                                  </div>
                                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded shrink-0 ${priorityBadgeClass(t.priority)}`}>
                                    {formatPriorityLabel(t.priority)}
                                  </span>
                                </div>
                              ))}
                              {tickets.length > 3 && (
                                <p className="text-[10px] text-gray-400 dark:text-gray-500">+{tickets.length - 3} more active tickets</p>
                              )}
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>

                <div className="mt-5 flex gap-3">
                  <button
                    type="button"
                    onClick={() => {
                      setShowReassignModal(false);
                      setReassignSearch('');
                      setReassignEmployeeId('');
                      resetCallAndPriorityState();
                    }}
                    className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-gray-600 text-gray-500 dark:text-gray-300 hover:text-gray-700 dark:hover:text-white hover:bg-gray-50 dark:hover:bg-gray-700 text-sm font-medium transition-all"
                  >
                    Cancel
                  </button>
                  <button
                    type="button"
                    onClick={handleReassignTicket}
                    disabled={!reassignEmployeeId || reassigning}
                    className="flex-1 py-2.5 rounded-xl bg-[#3BC25B] hover:bg-[#2ea34a] text-white text-sm font-bold transition-colors disabled:opacity-40 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                  >
                    {reassigning ? (
                      <><Loader2 className="w-4 h-4 animate-spin" /> Assigning...</>
                    ) : (
                      <><UserCheck className="w-4 h-4" /> {needsCallPriorityWorkflow ? 'Assign Ticket' : 'Reassign to Employee'}</>
                    )}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>,
        document.body
      )}


      </>
      )}
    </div>
  );
}

export default TicketView;

﻿import { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card } from '../../components/ui/Card';
import { StatCard } from '../../components/ui/StatCard';
import { GreenButton } from '../../components/ui/GreenButton';
import { Users, UserCheck, UserCog, UserPlus, Plus, Pencil, Trash2, Megaphone } from 'lucide-react';
import { toast } from 'sonner';
import {
  fetchTickets,
  fetchUsers,
  fetchAnnouncements,
  createAnnouncement,
  updateAnnouncement,
  deleteAnnouncement,
} from '../../services/api';
import type { AnnouncementData, BackendTicket, BackendUser } from '../../services/api';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
  Legend } from
'recharts';

const PRIORITY_COLORS: Record<string, string> = {
  Low: '#3BC25B',
  Medium: '#F59E0B',
  High: '#EF4444',
  Critical: '#991B1B',
};

function normalize(value: string | null | undefined) {
  return (value || '').trim().toLowerCase().replace(/[\s-]+/g, '_');
}

export default function SuperAdminDashboard() {
  const navigate = useNavigate();
  const [tickets, setTickets] = useState<BackendTicket[]>([]);
  const [users, setUsers] = useState<BackendUser[]>([]);
  const [loadingDashboard, setLoadingDashboard] = useState(true);

  // ── Announcement management state ──
  const [announcements, setAnnouncements] = useState<AnnouncementData[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    announcement_type: 'info' as string,
    visibility: 'all' as string,
    is_active: true,
    start_date: '',
    end_date: '',
  });

  useEffect(() => {
    void loadAnnouncements();
    void loadDashboardData();
  }, []);

  async function loadDashboardData() {
    setLoadingDashboard(true);
    try {
      const [ticketData, userData] = await Promise.all([
        fetchTickets(),
        fetchUsers().catch(() => []),
      ]);
      setTickets(ticketData);
      setUsers(userData);
    } catch {
      toast.error('Failed to load dashboard metrics.');
    } finally {
      setLoadingDashboard(false);
    }
  }

  async function loadAnnouncements() {
    try {
      const data = await fetchAnnouncements();
      setAnnouncements(data);
    } catch {
      // silent
    }
  }

  function resetForm() {
    setFormData({
      title: '',
      description: '',
      announcement_type: 'info',
      visibility: 'all',
      is_active: true,
      start_date: '',
      end_date: '',
    });
    setEditingId(null);
    setShowForm(false);
  }

  function openEditForm(ann: AnnouncementData) {
    setFormData({
      title: ann.title,
      description: ann.description,
      announcement_type: ann.announcement_type,
      visibility: ann.visibility,
      is_active: ann.is_active,
      start_date: ann.start_date ? ann.start_date.slice(0, 16) : '',
      end_date: ann.end_date ? ann.end_date.slice(0, 16) : '',
    });
    setEditingId(ann.id);
    setShowForm(true);
  }

  async function handleSave() {
    if (!formData.title.trim() || !formData.description.trim()) {
      toast.error('Title and description are required.');
      return;
    }
    try {
      const payload: Record<string, unknown> = {
        title: formData.title,
        description: formData.description,
        announcement_type: formData.announcement_type,
        visibility: formData.visibility,
        is_active: formData.is_active,
      };
      if (formData.start_date) payload.start_date = new Date(formData.start_date).toISOString();
      if (formData.end_date) payload.end_date = new Date(formData.end_date).toISOString();
      else payload.end_date = null;

      if (editingId) {
        await updateAnnouncement(editingId, payload);
        toast.success('Announcement updated.');
      } else {
        await createAnnouncement(payload as Parameters<typeof createAnnouncement>[0]);
        toast.success('Announcement created.');
      }
      resetForm();
      loadAnnouncements();
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Failed to save announcement.');
    }
  }

  async function handleDelete(id: number) {
    try {
      await deleteAnnouncement(id);
      toast.success('Announcement deleted.');
      loadAnnouncements();
    } catch {
      toast.error('Failed to delete announcement.');
    }
  }

  const TYPE_COLORS: Record<string, string> = {
    info: 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300',
    warning: 'bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-300',
    success: 'bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-300',
    critical: 'bg-red-100 text-red-700 dark:bg-red-900/40 dark:text-red-300',
  };

  const activeUsers = useMemo(() => users.filter((user) => user.is_active).length, [users]);
  const supervisorCount = useMemo(() => users.filter((user) => normalize(user.role) === 'admin').length, [users]);
  const salesCount = useMemo(() => users.filter((user) => normalize(user.role) === 'sales').length, [users]);

  const userRoleData = useMemo(() => {
    const buckets: Record<string, number> = {};
    users.forEach((user) => {
      const role = normalize(user.role);
      if (!role) return;
      buckets[role] = (buckets[role] || 0) + 1;
    });

    return Object.entries(buckets)
      .map(([role, count]) => ({
        name: role === 'admin' ? 'Supervisors' : role === 'employee' ? 'Technical' : role === 'sales' ? 'Sales' : role === 'superadmin' ? 'Superadmin' : role,
        users: count,
      }))
      .sort((a, b) => b.users - a.users);
  }, [users]);

  const ticketCreatorRoleData = useMemo(() => {
    const buckets: Record<string, number> = {
      supervisor: 0,
      sales: 0,
      technical: 0,
      superadmin: 0,
      other: 0,
    };

    tickets.forEach((ticket) => {
      const role = normalize(String(ticket.created_by?.role || ''));
      if (role === 'admin') buckets.supervisor += 1;
      else if (role === 'sales') buckets.sales += 1;
      else if (role === 'employee') buckets.technical += 1;
      else if (role === 'superadmin') buckets.superadmin += 1;
      else buckets.other += 1;
    });

    return [
      { name: 'Supervisors', value: buckets.supervisor, color: '#0E8F79' },
      { name: 'Sales', value: buckets.sales, color: '#3BC25B' },
      { name: 'Technical', value: buckets.technical, color: '#F59E0B' },
      { name: 'Superadmin', value: buckets.superadmin, color: '#3B82F6' },
      { name: 'Other', value: buckets.other, color: '#6B7280' },
    ];
  }, [tickets]);

  const supervisorLoad = useMemo(() => {
    const buckets: Record<string, number> = {};
    tickets.forEach((ticket) => {
      const sup = ticket.supervisor;
      if (!sup) return;
      const label = `${sup.first_name || ''} ${sup.last_name || ''}`.trim() || sup.username || `Supervisor #${sup.id}`;
      buckets[label] = (buckets[label] || 0) + 1;
    });

    return Object.entries(buckets)
      .map(([name, count]) => ({ name, tickets: count }))
      .sort((a, b) => b.tickets - a.tickets)
      .slice(0, 6);
  }, [tickets]);

  const salesCreated = useMemo(() => {
    const buckets: Record<string, number> = {};
    tickets.forEach((ticket) => {
      const createdBy = ticket.created_by;
      if (normalize(createdBy?.role) !== 'sales') return;
      const label = `${createdBy.first_name || ''} ${createdBy.last_name || ''}`.trim() || createdBy.username || `Sales #${createdBy.id}`;
      buckets[label] = (buckets[label] || 0) + 1;
    });

    return Object.entries(buckets)
      .map(([name, count]) => ({ name, tickets: count }))
      .sort((a, b) => b.tickets - a.tickets)
      .slice(0, 6);
  }, [tickets]);

  if (loadingDashboard) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#3BC25B]"></div>
        <span className="ml-3 text-gray-500">Loading dashboard...</span>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">
            SuperAdmin User Analytics
          </h1>
          <p className="text-gray-500 dark:text-gray-400">
            User distribution, participation, and ticket ownership insights
          </p>
        </div>
        <GreenButton onClick={() => navigate('/superadmin/reports')}>
          View Detailed Reports
        </GreenButton>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard
          title="Total Users"
          value={users.length.toLocaleString()}
          icon={Users}
          color="green" />

        <StatCard
          title="Active Users"
          value={activeUsers.toLocaleString()}
          icon={UserCheck}
          color="orange" />

        <StatCard
          title="Supervisors"
          value={supervisorCount.toLocaleString()}
          icon={UserCog}
          color="blue" />

        <StatCard
          title="Sales Team"
          value={salesCount.toLocaleString()}
          icon={UserPlus}
          color="purple" />

      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="lg:col-span-2" accent>
          <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-6">
            Users by Role
          </h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={userRoleData}>
                <CartesianGrid
                  strokeDasharray="3 3"
                  vertical={false}
                  stroke="#E5E7EB" />

                <XAxis
                  dataKey="name"
                  axisLine={false}
                  tickLine={false}
                  tick={{ fill: '#6B7280' }} />

                <YAxis
                  axisLine={false}
                  tickLine={false}
                  tick={{ fill: '#6B7280' }} />

                <Tooltip
                  cursor={{ fill: '#F3F4F6' }}
                  contentStyle={{
                    borderRadius: '8px',
                    border: 'none',
                    boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)',
                    backgroundColor: '#fff',
                    color: '#111'
                  }} />

                <Bar
                  dataKey="users"
                  fill="url(#usersGradient)"
                  radius={[4, 4, 0, 0]} />

                <defs>
                  <linearGradient
                    id="usersGradient"
                    x1="0"
                    y1="0"
                    x2="0"
                    y2="1">

                    <stop offset="0%" stopColor="#63D44A" />
                    <stop offset="100%" stopColor="#0E8F79" />
                  </linearGradient>
                </defs>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </Card>

        <Card accent>
          <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-6">
            Ticket Creators by Role
          </h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={ticketCreatorRoleData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value">

                  {ticketCreatorRoleData.map((entry, i) =>
                  <Cell key={i} fill={entry.color} />
                  )}
                </Pie>
                <Tooltip
                  contentStyle={{
                    backgroundColor: '#ffffff',
                    border: '1px solid #E5E7EB',
                    borderRadius: '8px',
                    color: '#111827',
                    boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)'
                  }} />

                <Legend
                  verticalAlign="bottom"
                  height={36}
                  wrapperStyle={{ color: '#6b7280' }} />

              </PieChart>
            </ResponsiveContainer>
          </div>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card accent>
            <h3 className="text-lg font-bold text-gray-900 dark:text-white">
            Supervisor Ticket Ownership
            </h3>
          <div className="h-72 mt-4">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={supervisorLoad} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e5e7eb" />
                <XAxis type="number" tick={{ fontSize: 12 }} />
                <YAxis dataKey="name" type="category" tick={{ fontSize: 12 }} width={120} />
                <Tooltip />
                <Bar dataKey="tickets" fill="#0E8F79" radius={[0, 4, 4, 0]} name="Tickets" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </Card>

        <Card accent>
          <h3 className="text-lg font-bold text-gray-900 dark:text-white">
            Sales Ticket Creation
          </h3>
          <div className="h-72 mt-4">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesCreated} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e5e7eb" />
                <XAxis type="number" tick={{ fontSize: 12 }} />
                <YAxis dataKey="name" type="category" tick={{ fontSize: 12 }} width={120} />
                <Tooltip />
                <Bar dataKey="tickets" fill="#3BC25B" radius={[0, 4, 4, 0]} name="Created Tickets" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </Card>
      </div>

      <Card accent>
        <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-6">
          User Role Activity Summary
        </h3>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="text-xs text-gray-500 dark:text-gray-400 uppercase bg-gray-50 dark:bg-gray-700/50">
              <tr>
                <th className="px-4 py-3">Role</th>
                <th className="px-4 py-3">User Count</th>
                <th className="px-4 py-3">Created Tickets</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
              {userRoleData.length === 0 ? (
                <tr>
                  <td className="px-4 py-6 text-center text-sm text-gray-500 dark:text-gray-400" colSpan={3}>
                    No role analytics available.
                  </td>
                </tr>
              ) : (
                userRoleData.map((entry) => {
                  const creatorEntry = ticketCreatorRoleData.find((item) => normalize(item.name) === normalize(entry.name));
                  return (
                  <tr
                    key={entry.name}
                    className="hover:bg-gray-50 dark:hover:bg-gray-700/40"
                  >
                    <td className="px-4 py-3 font-medium text-gray-900 dark:text-white">
                      {entry.name}
                    </td>
                    <td className="px-4 py-3 text-gray-700 dark:text-gray-300">
                      {entry.users}
                    </td>
                    <td className="px-4 py-3 text-gray-700 dark:text-gray-300">
                      {creatorEntry?.value ?? 0}
                    </td>
                  </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </Card>

      {/* ── Announcement Management ── */}
      <Card accent>
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2">
            <Megaphone className="w-5 h-5 text-[#0E8F79]" />
            <h3 className="text-lg font-bold text-gray-900 dark:text-white">Announcements</h3>
          </div>
          <GreenButton onClick={() => { resetForm(); setShowForm(true); }}>
            <Plus className="w-4 h-4 mr-1" /> New Announcement
          </GreenButton>
        </div>

        {/* Create / Edit Form */}
        {showForm && (
          <div className="mb-6 rounded-xl border border-gray-200 dark:border-gray-700 p-5 bg-gray-50 dark:bg-gray-800/50 space-y-4">
            <h4 className="font-semibold text-gray-900 dark:text-white">
              {editingId ? 'Edit Announcement' : 'Create Announcement'}
            </h4>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Title</label>
              <input
                type="text"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-3 py-2 text-sm focus:ring-2 focus:ring-[#3BC25B] outline-none"
                placeholder="Announcement title"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Description</label>
              <textarea
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                rows={3}
                className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-3 py-2 text-sm focus:ring-2 focus:ring-[#3BC25B] outline-none resize-none"
                placeholder="Announcement details..."
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Type</label>
                <select
                  value={formData.announcement_type}
                  onChange={(e) => setFormData({ ...formData, announcement_type: e.target.value })}
                  className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-3 py-2 text-sm focus:ring-2 focus:ring-[#3BC25B] outline-none"
                >
                  <option value="info">Info (Blue)</option>
                  <option value="warning">Warning (Amber)</option>
                  <option value="success">Success (Green)</option>
                  <option value="critical">Critical (Red)</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Visibility</label>
                <select
                  value={formData.visibility}
                  onChange={(e) => setFormData({ ...formData, visibility: e.target.value })}
                  className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-3 py-2 text-sm focus:ring-2 focus:ring-[#3BC25B] outline-none"
                >
                  <option value="all">All (Supervisors & Technicians)</option>
                  <option value="admin">Supervisors Only</option>
                  <option value="employee">Technicians Only</option>
                </select>
              </div>

              <div className="flex items-end">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={formData.is_active}
                    onChange={(e) => setFormData({ ...formData, is_active: e.target.checked })}
                    className="rounded border-gray-300 text-[#3BC25B] focus:ring-[#3BC25B]"
                  />
                  <span className="text-sm text-gray-700 dark:text-gray-300">Active</span>
                </label>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Start Date</label>
                <input
                  type="datetime-local"
                  value={formData.start_date}
                  onChange={(e) => setFormData({ ...formData, start_date: e.target.value })}
                  className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-3 py-2 text-sm focus:ring-2 focus:ring-[#3BC25B] outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">End Date <span className="text-gray-400">(leave blank for no expiry)</span></label>
                <input
                  type="datetime-local"
                  value={formData.end_date}
                  onChange={(e) => setFormData({ ...formData, end_date: e.target.value })}
                  className="w-full rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white px-3 py-2 text-sm focus:ring-2 focus:ring-[#3BC25B] outline-none"
                />
              </div>
            </div>

            <div className="flex gap-3 pt-2">
              <GreenButton onClick={handleSave}>
                {editingId ? 'Update' : 'Create'}
              </GreenButton>
              <GreenButton variant="outline" onClick={resetForm}>Cancel</GreenButton>
            </div>
          </div>
        )}

        {/* Announcements List */}
        {announcements.length === 0 ? (
          <div className="rounded-xl border border-dashed border-gray-300 dark:border-gray-600 p-8 text-center">
            <Megaphone className="w-8 h-8 text-gray-300 dark:text-gray-600 mx-auto mb-2" />
            <p className="text-sm text-gray-500 dark:text-gray-400">No announcements yet. Create your first one above.</p>
          </div>
        ) : (
          <div className="space-y-3">
            {announcements.map((ann) => (
              <div
                key={ann.id}
                className={`rounded-xl border p-4 transition-colors ${
                  ann.is_currently_active
                    ? 'border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800'
                    : 'border-gray-100 dark:border-gray-800 bg-gray-50 dark:bg-gray-900 opacity-60'
                }`}
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap mb-1">
                      <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ${TYPE_COLORS[ann.announcement_type] || TYPE_COLORS.info}`}>
                        {ann.announcement_type.charAt(0).toUpperCase() + ann.announcement_type.slice(1)}
                      </span>
                      <span className="text-xs text-gray-400 dark:text-gray-500">
                        {ann.visibility === 'all' ? 'All' : ann.visibility === 'admin' ? 'Supervisors' : 'Technicians'}
                      </span>
                      {!ann.is_active && (
                        <span className="text-xs text-gray-400 italic">Inactive</span>
                      )}
                    </div>
                    <h4 className="font-semibold text-gray-900 dark:text-white text-sm">{ann.title}</h4>
                    <p className="text-sm text-gray-600 dark:text-gray-400 mt-1 line-clamp-2">{ann.description}</p>
                    <p className="text-xs text-gray-400 dark:text-gray-500 mt-2">
                      {ann.start_date ? new Date(ann.start_date).toLocaleDateString() : 'Now'}
                      {ann.end_date ? ` — ${new Date(ann.end_date).toLocaleDateString()}` : ' — No expiry'}
                    </p>
                  </div>
                  <div className="flex gap-1 flex-shrink-0">
                    <button
                      onClick={() => openEditForm(ann)}
                      className="p-2 rounded-lg text-gray-400 hover:text-[#0E8F79] hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                    >
                      <Pencil className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => handleDelete(ann.id)}
                      className="p-2 rounded-lg text-gray-400 hover:text-red-500 hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </Card>
    </div>);

}

﻿import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { Card } from '../../components/ui/Card';
import { GreenButton } from '../../components/ui/GreenButton';
import { User, Lock, Mail, Phone, Building, Shield, Pencil, X, Loader2, Camera, Eye, EyeOff, Archive } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { changePassword, updateProfile, uploadAvatar, removeAvatar } from '../../services/authService';
import { fetchRetentionPolicy, updateRetentionPolicy, type RetentionPolicyData } from '../../services/api';
import { toast } from 'sonner';
import {
  validatePassword,
  validateConfirmPassword,
  validateName,
  validatePhone,
  checkPasswordPwned,
  MAX_PASSWORD,
  MAX_NAME,
  MAX_PHONE,
  type PasswordRules,
} from '../../utils/validation';

export default function Settings() {
  const { user, updateUser } = useAuth();

  /* ── Profile editing state ── */
  const [editing, setEditing] = useState(false);
  const [profileLoading, setProfileLoading] = useState(false);
  const [form, setForm] = useState({
    first_name: user?.first_name || '',
    middle_name: user?.middle_name || '',
    last_name: user?.last_name || '',
    suffix: user?.suffix || '',
    phone: user?.phone || '',
  });
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});

  const startEdit = () => {
    setForm({
      first_name: user?.first_name || '',
      middle_name: user?.middle_name || '',
      last_name: user?.last_name || '',
      suffix: user?.suffix || '',
      phone: user?.phone || '',
    });
    setFieldErrors({});
    setEditing(true);
  };

  const cancelEdit = () => { setEditing(false); setFieldErrors({}); };

  /* ── Avatar upload ── */
  const avatarInputRef = useRef<HTMLInputElement>(null);
  const [avatarLoading, setAvatarLoading] = useState(false);
  const [removeAvatarLoading, setRemoveAvatarLoading] = useState(false);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null); // local blob for instant preview
  const [avatarImgError, setAvatarImgError] = useState(false);
  const [avatarLightboxOpen, setAvatarLightboxOpen] = useState(false);

  // Compute the src to show: local blob preview > server URL (with cache-bust) > nothing
  const avatarSrc = avatarPreview
    ? avatarPreview
    : user?.profile_picture_url
    ? `${user.profile_picture_url}?t=${encodeURIComponent(user.profile_picture_url.split('/').pop() || '')}`
    : null;

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const blobUrl = URL.createObjectURL(file);
    setAvatarPreview(blobUrl);
    setAvatarImgError(false);
    setAvatarLoading(true);
    // Update navbar instantly with the local blob so the circle reflects the new photo right away
    updateUser({ profile_picture_url: blobUrl });
    try {
      const updated = await uploadAvatar(file);
      // Replace blob URL in context with the permanent server URL
      updateUser({ profile_picture_url: updated.profile_picture_url ?? null });
      toast.success('Profile picture updated.');
    } catch (err) {
      setAvatarPreview(null);
      updateUser({ profile_picture_url: user?.profile_picture_url ?? null });
      toast.error(err instanceof Error ? err.message : 'Failed to upload picture.');
    } finally {
      setAvatarLoading(false);
      // Delay revocation so React can flush the server URL update to the navbar before the blob dies
      setTimeout(() => URL.revokeObjectURL(blobUrl), 5000);
      if (avatarInputRef.current) avatarInputRef.current.value = '';
    }
  };

  const handleRemoveAvatar = async () => {
    setRemoveAvatarLoading(true);
    try {
      await removeAvatar();
      setAvatarPreview(null);
      setAvatarImgError(false);
      updateUser({ profile_picture_url: null });
      toast.success('Profile picture removed.');
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to remove picture.');
    } finally {
      setRemoveAvatarLoading(false);
    }
  };

  const handleField = (field: string, value: string) => {
    setForm((p) => ({ ...p, [field]: value }));
    setFieldErrors((p) => ({ ...p, [field]: '' }));
  };

  const handleSaveProfile = async () => {
    const errs: Record<string, string> = {};
    const fnErr = validateName(form.first_name, 'First name');
    if (fnErr) errs.first_name = fnErr;
    const lnErr = validateName(form.last_name, 'Last name');
    if (lnErr) errs.last_name = lnErr;
    if (form.phone) {
      const phErr = validatePhone(form.phone);
      if (phErr) errs.phone = phErr;
    }
    if (Object.keys(errs).length) { setFieldErrors(errs); return; }

    setProfileLoading(true);
    try {
      const updated = await updateProfile(form);
      updateUser({
        first_name: updated.first_name,
        middle_name: updated.middle_name,
        last_name: updated.last_name,
        suffix: updated.suffix,
        phone: updated.phone,
      });
      toast.success('Profile updated successfully.');
      setEditing(false);
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to update profile.');
    } finally {
      setProfileLoading(false);
    }
  };

  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPw, setConfirmPw] = useState('');
  const [pwError, setPwError] = useState('');
  const [pwLoading, setPwLoading] = useState(false);
  const [pwRules, setPwRules] = useState<PasswordRules | null>(null);
  const [breachChecking, setBreachChecking] = useState(false);
  const [showCurrent, setShowCurrent] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  /* ── Retention Policy state (superadmin only) ── */
  const [retentionPolicy, setRetentionPolicy] = useState<RetentionPolicyData | null>(null);
  const [retentionForm, setRetentionForm] = useState({ audit_log_retention_days: 365, call_log_retention_days: 365 });
  const [retentionEditing, setRetentionEditing] = useState(false);
  const [retentionLoading, setRetentionLoading] = useState(false);

  useEffect(() => {
    if (user?.role === 'superadmin') {
      fetchRetentionPolicy()
        .then((p) => {
          setRetentionPolicy(p);
          setRetentionForm({ audit_log_retention_days: p.audit_log_retention_days, call_log_retention_days: p.call_log_retention_days });
        })
        .catch(() => undefined);
    }
  }, [user?.role]);
  const hibpTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Real-time debounced HIBP breach check while typing
  useEffect(() => {
    // Clear any pending timer
    if (hibpTimer.current) clearTimeout(hibpTimer.current);

    // Only check if the password passes all basic rules
    const { error } = validatePassword(newPassword);
    if (!newPassword || error) {
      // Reset breach status when password is empty or invalid
      setPwRules((prev) => prev ? { ...prev, notBreached: null } : prev);
      setBreachChecking(false);
      return;
    }

    // Show checking state
    setBreachChecking(true);
    setPwRules((prev) => prev ? { ...prev, notBreached: null } : prev);

    hibpTimer.current = setTimeout(async () => {
      try {
        const breached = await checkPasswordPwned(newPassword);
        // Only update if password hasn't changed since we started
        setPwRules((prev) => prev ? { ...prev, notBreached: !breached } : prev);
      } catch {
        // Network error — assume safe
        setPwRules((prev) => prev ? { ...prev, notBreached: true } : prev);
      } finally {
        setBreachChecking(false);
      }
    }, 800);

    return () => { if (hibpTimer.current) clearTimeout(hibpTimer.current); };
  }, [newPassword]);

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setPwError('');
    if (!currentPassword || !newPassword || !confirmPw) {
      setPwError('All fields are required.');
      return;
    }
    const { error } = validatePassword(newPassword);
    if (error) { setPwError(error); return; }
    const confirmErr = validateConfirmPassword(newPassword, confirmPw);
    if (confirmErr) { setPwError(confirmErr); return; }

    setPwLoading(true);
    try {
      // If breach check is still pending, do a final check now
      if (pwRules?.notBreached === null) {
        const breached = await checkPasswordPwned(newPassword);
        setPwRules((prev) => prev ? { ...prev, notBreached: !breached } : prev);
      }
      await changePassword(currentPassword, newPassword);
      toast.success('Password changed successfully.');
      setCurrentPassword('');
      setNewPassword('');
      setConfirmPw('');
      setPwRules(null);
    } catch (err) {
      setPwError(err instanceof Error ? err.message : 'Failed to change password.');
    } finally {
      setPwLoading(false);
    }
  };

  /* ── Helpers ── */
  const inputClass = 'w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400';
  const boxEdit = 'flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B]';
  const boxReadonly = 'flex items-center gap-2 px-3 py-2.5 rounded-lg bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700';

  return (
    <div className="space-y-6 max-w-3xl">
      <div>
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Settings</h1>
        <p className="text-gray-500 dark:text-gray-400">Manage your super admin account settings</p>
      </div>

      {/* ── Personal Details ── */}
      <Card accent>
        {/* Avatar */}
        <div className="flex items-center gap-6 mb-6">
          <div className="relative flex-shrink-0">
            {/* Circle: click image → preview; click empty circle → file picker */}
            <div
              className="w-28 h-28 rounded-full overflow-hidden bg-gray-200 dark:bg-gray-700 border-2 border-gray-300 dark:border-gray-600 flex items-center justify-center cursor-pointer group"
              onClick={() => {
                if (avatarLoading || removeAvatarLoading) return;
                if (avatarSrc && !avatarImgError) setAvatarLightboxOpen(true);
                else avatarInputRef.current?.click();
              }}
            >
              {avatarSrc && !avatarImgError ? (
                <img
                  src={avatarSrc}
                  alt="Profile"
                  className="w-full h-full object-cover"
                  onError={() => setAvatarImgError(true)}
                />
              ) : (
                <User className="w-12 h-12 text-gray-400" />
              )}
              <div className="absolute inset-0 rounded-full flex items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity">
                {avatarLoading
                  ? <Loader2 className="w-6 h-6 text-white animate-spin" />
                  : (avatarSrc && !avatarImgError)
                  ? <Eye className="w-6 h-6 text-white" />
                  : <Camera className="w-6 h-6 text-white" />}
              </div>
            </div>
            <input ref={avatarInputRef} type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
          </div>
          <div>
            <p className="text-sm font-semibold text-gray-900 dark:text-white">Profile Picture</p>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">JPG, PNG or GIF · Max 5 MB</p>
            <div className="flex items-center gap-3 mt-2">
              <button
                type="button"
                onClick={() => !avatarLoading && !removeAvatarLoading && avatarInputRef.current?.click()}
                disabled={avatarLoading || removeAvatarLoading}
                className="text-xs font-medium text-[#3BC25B] hover:text-[#63D44A] transition-colors disabled:opacity-50"
              >
                {avatarLoading ? 'Uploading…' : 'Change photo'}
              </button>
              {(user?.profile_picture_url || avatarPreview) && (
                <>
                  <span className="text-gray-500 dark:text-gray-600 text-xs">·</span>
                  <button
                    type="button"
                    onClick={handleRemoveAvatar}
                    disabled={avatarLoading || removeAvatarLoading}
                    className="text-xs font-medium text-red-400 hover:text-red-500 transition-colors disabled:opacity-50"
                  >
                    {removeAvatarLoading ? 'Removing…' : 'Remove photo'}
                  </button>
                </>
              )}
            </div>
          </div>
        </div>

        {/* Lightbox */}
        {avatarLightboxOpen && avatarSrc && createPortal(
          <div
            className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm"
            onClick={() => setAvatarLightboxOpen(false)}
          >
            <div className="relative max-w-sm w-full mx-4" onClick={(e) => e.stopPropagation()}>
              <button
                onClick={() => setAvatarLightboxOpen(false)}
                className="absolute -top-3 -right-3 z-10 w-8 h-8 rounded-full bg-gray-800 border border-gray-600 flex items-center justify-center text-gray-300 hover:text-white hover:bg-gray-700 transition-colors"
              >
                <X className="w-4 h-4" />
              </button>
              <img
                src={avatarSrc}
                alt="Profile preview"
                className="w-full rounded-2xl object-cover shadow-2xl"
              />
            </div>
          </div>,
          document.body
        )}

        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Personal Details</h2>
          {!editing ? (
            <button onClick={startEdit} className="inline-flex items-center gap-1.5 text-sm font-medium text-[#3BC25B] hover:text-[#63D44A] transition-colors">
              <Pencil className="w-4 h-4" /> Edit
            </button>
          ) : (
            <button onClick={cancelEdit} className="inline-flex items-center gap-1.5 text-sm font-medium text-gray-400 hover:text-gray-300 transition-colors">
              <X className="w-4 h-4" /> Cancel
            </button>
          )}
        </div>

        {!editing ? (
          /* Read-only view */
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {[
              { label: 'First Name', value: user?.first_name || '—', icon: User },
              { label: 'Last Name', value: user?.last_name || '—', icon: User },
              { label: 'Middle Name', value: user?.middle_name || '—', icon: User },
              { label: 'Suffix', value: user?.suffix || '—', icon: User },
              { label: 'Email', value: user?.email || '—', icon: Mail },
              { label: 'Phone', value: user?.phone || '—', icon: Phone },
              { label: 'Department', value: 'Administration', icon: Building },
              { label: 'Role', value: 'Super Administrator', icon: Shield },
            ].map((f) => (
              <div key={f.label}>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">{f.label}</label>
                <div className={boxReadonly}>
                  <f.icon className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-700 dark:text-gray-300">{f.value}</span>
                </div>
              </div>
            ))}
          </div>
        ) : (
          /* Edit form */
          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">First Name <span className="text-red-400">*</span></label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.first_name} maxLength={MAX_NAME} onChange={(e) => handleField('first_name', e.target.value)} className={inputClass} placeholder="First name" />
                </div>
                {fieldErrors.first_name && <p className="text-xs text-red-400 mt-1">{fieldErrors.first_name}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Last Name <span className="text-red-400">*</span></label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.last_name} maxLength={MAX_NAME} onChange={(e) => handleField('last_name', e.target.value)} className={inputClass} placeholder="Last name" />
                </div>
                {fieldErrors.last_name && <p className="text-xs text-red-400 mt-1">{fieldErrors.last_name}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Middle Name</label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.middle_name} maxLength={MAX_NAME} onChange={(e) => handleField('middle_name', e.target.value)} className={inputClass} placeholder="Middle name (optional)" />
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Suffix</label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.suffix} maxLength={10} onChange={(e) => handleField('suffix', e.target.value)} className={inputClass} placeholder="e.g. Jr., Sr., III" />
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Phone</label>
                <div className={boxEdit}>
                  <Phone className="w-4 h-4 text-gray-400" />
                  <input value={form.phone} maxLength={MAX_PHONE} onChange={(e) => handleField('phone', e.target.value)} className={inputClass} placeholder="+63 9XX XXX XXXX" />
                </div>
                {fieldErrors.phone && <p className="text-xs text-red-400 mt-1">{fieldErrors.phone}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Email</label>
                <div className={boxReadonly}>
                  <Mail className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-500 dark:text-gray-400">{user?.email || '—'}</span>
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Role</label>
                <div className={boxReadonly}>
                  <Shield className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-500 dark:text-gray-400">Super Administrator</span>
                </div>
              </div>
            </div>
            <div className="flex gap-3 pt-2">
              <GreenButton type="button" onClick={handleSaveProfile} disabled={profileLoading}>
                {profileLoading ? <><Loader2 className="w-4 h-4 animate-spin" /> Saving…</> : 'Save Changes'}
              </GreenButton>
              <button type="button" onClick={cancelEdit} className="px-4 py-2 rounded-lg text-sm font-medium text-gray-400 hover:text-white border border-gray-600 hover:border-gray-500 transition-colors">
                Cancel
              </button>
            </div>
          </div>
        )}
      </Card>

      <Card accent>
        <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">Change Password</h2>
        <form onSubmit={handleChangePassword} className="space-y-4 max-w-md">
          {pwError && <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 text-sm">{pwError}</div>}
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Current Password</label>
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B] relative">
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showCurrent ? 'text' : 'password'} value={currentPassword} maxLength={MAX_PASSWORD} onChange={(e) => setCurrentPassword(e.target.value)} placeholder="••••••••" className="w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400 pr-10" />
              <button type="button" onClick={() => setShowCurrent((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showCurrent ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">New Password</label>
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B] relative">
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showNew ? 'text' : 'password'} value={newPassword} maxLength={MAX_PASSWORD} onChange={(e) => { setNewPassword(e.target.value); const { rules } = validatePassword(e.target.value); setPwRules(rules); }} placeholder="••••••••" className="w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400 pr-10" />
              <button type="button" onClick={() => setShowNew((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showNew ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
            {newPassword && pwRules && (
              <ul className="text-xs space-y-0.5 mt-1.5">
                {[
                  { ok: pwRules.minLength, text: 'At least 8 characters' },
                  { ok: pwRules.hasUppercase, text: 'An uppercase letter' },
                  { ok: pwRules.hasLowercase, text: 'A lowercase letter' },
                  { ok: pwRules.hasNumber, text: 'A number' },
                  { ok: pwRules.hasSpecial, text: 'A special character' },
                ].map((r) => (
                  <li key={r.text} className={r.ok ? 'text-green-600' : 'text-red-500'}>
                    {r.ok ? '\u2713' : '\u2717'} {r.text}
                  </li>
                ))}
              </ul>
            )}
          </div>
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Confirm New Password</label>
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B] relative">
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showConfirm ? 'text' : 'password'} value={confirmPw} maxLength={MAX_PASSWORD} onChange={(e) => setConfirmPw(e.target.value)} placeholder="••••••••" className="w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400 pr-10" />
              <button type="button" onClick={() => setShowConfirm((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showConfirm ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <GreenButton type="submit" disabled={pwLoading}>
            {pwLoading ? 'Updating…' : 'Update Password'}
          </GreenButton>
        </form>
      </Card>

      {/* ── Retention Policy (Superadmin only) ── */}
      {user?.role === 'superadmin' && (
        <Card accent>
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
              <Archive className="w-5 h-5 text-amber-500" />
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Log Retention Policy</h2>
            </div>
            {!retentionEditing ? (
              <button onClick={() => setRetentionEditing(true)} className="inline-flex items-center gap-1.5 text-sm font-medium text-[#3BC25B] hover:text-[#63D44A] transition-colors">
                <Pencil className="w-4 h-4" /> Edit
              </button>
            ) : (
              <button onClick={() => { setRetentionEditing(false); if (retentionPolicy) setRetentionForm({ audit_log_retention_days: retentionPolicy.audit_log_retention_days, call_log_retention_days: retentionPolicy.call_log_retention_days }); }} className="inline-flex items-center gap-1.5 text-sm font-medium text-gray-400 hover:text-gray-300 transition-colors">
                <X className="w-4 h-4" /> Cancel
              </button>
            )}
          </div>
          <p className="text-sm text-gray-500 dark:text-gray-400 mb-4">
            Configure how long audit logs and call logs are retained before automatic cleanup. Set to 0 to keep logs indefinitely.
          </p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Audit Log Retention (days)</label>
              {retentionEditing ? (
                <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B]">
                  <Shield className="w-4 h-4 text-gray-400" />
                  <input
                    type="number"
                    min={0}
                    max={9999}
                    value={retentionForm.audit_log_retention_days}
                    onChange={(e) => setRetentionForm((p) => ({ ...p, audit_log_retention_days: Math.max(0, Math.min(9999, parseInt(e.target.value) || 0)) }))}
                    className="w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400"
                  />
                </div>
              ) : (
                <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700">
                  <Shield className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-700 dark:text-gray-300">
                    {retentionPolicy?.audit_log_retention_days === 0 ? 'Indefinite (keep forever)' : `${retentionPolicy?.audit_log_retention_days ?? 365} days`}
                  </span>
                </div>
              )}
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Call Log Retention (days)</label>
              {retentionEditing ? (
                <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B]">
                  <Phone className="w-4 h-4 text-gray-400" />
                  <input
                    type="number"
                    min={0}
                    max={9999}
                    value={retentionForm.call_log_retention_days}
                    onChange={(e) => setRetentionForm((p) => ({ ...p, call_log_retention_days: Math.max(0, Math.min(9999, parseInt(e.target.value) || 0)) }))}
                    className="w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400"
                  />
                </div>
              ) : (
                <div className="flex items-center gap-2 px-3 py-2.5 rounded-lg bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700">
                  <Phone className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-700 dark:text-gray-300">
                    {retentionPolicy?.call_log_retention_days === 0 ? 'Indefinite (keep forever)' : `${retentionPolicy?.call_log_retention_days ?? 365} days`}
                  </span>
                </div>
              )}
            </div>
          </div>

          {retentionEditing && (
            <div className="flex gap-3 pt-4">
              <GreenButton
                type="button"
                disabled={retentionLoading}
                onClick={async () => {
                  setRetentionLoading(true);
                  try {
                    const updated = await updateRetentionPolicy(retentionForm);
                    setRetentionPolicy(updated);
                    setRetentionEditing(false);
                    toast.success('Retention policy updated successfully.');
                  } catch (err) {
                    toast.error(err instanceof Error ? err.message : 'Failed to update retention policy.');
                  } finally {
                    setRetentionLoading(false);
                  }
                }}
              >
                {retentionLoading ? <><Loader2 className="w-4 h-4 animate-spin" /> Saving…</> : 'Save Policy'}
              </GreenButton>
              <button
                type="button"
                onClick={() => { setRetentionEditing(false); if (retentionPolicy) setRetentionForm({ audit_log_retention_days: retentionPolicy.audit_log_retention_days, call_log_retention_days: retentionPolicy.call_log_retention_days }); }}
                className="px-4 py-2 rounded-lg text-sm font-medium text-gray-400 hover:text-white border border-gray-600 hover:border-gray-500 transition-colors"
              >
                Cancel
              </button>
            </div>
          )}
        </Card>
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { Card } from '../../components/ui/Card';
import { GreenButton } from '../../components/ui/GreenButton';
import {
  ArrowUpRight,
  Share2,
  History,
  Clock,
  AlertTriangle,
  CheckCircle2,
  Loader2,
  RefreshCw,
  ChevronLeft,
  ChevronRight,
} from 'lucide-react';
import { toast } from 'sonner';
import {
  fetchTickets,
  escalateTicket,
  escalateExternal,
  fetchEscalationLogs,
  type BackendTicket,
  type EscalationLog,
} from '../../services/api';
import { validateReason, MAX_REASON } from '../../utils/validation';

const ESCALABLE_STATUSES = ['open', 'in_progress'];
const ITEMS_PER_PAGE = 4;

type EscalationType = 'internal' | 'external';

export default function TechnicalStaffEscalation() {
  /* ── Data ── */
  const [tickets, setTickets] = useState<BackendTicket[]>([]);
  const [logs, setLogs] = useState<EscalationLog[]>([]);
  const [loadingData, setLoadingData] = useState(true);

  /* ── Form ── */
  const [selectedId, setSelectedId] = useState<number | ''>('');
  const [escalationType, setEscalationType] = useState<EscalationType>('internal');
  const [escalateTo, setEscalateTo] = useState('');
  const [notes, setNotes] = useState('');
  const [notesError, setNotesError] = useState('');
  const [escalateToError, setEscalateToError] = useState('');
  const [submitting, setSubmitting] = useState(false);

  /* ── Pagination ── */
  const [currentPage, setCurrentPage] = useState(1);

  const escalableTickets = tickets.filter((t) =>
    ESCALABLE_STATUSES.includes(t.status)
  );

  const loadData = useCallback(async () => {
    setLoadingData(true);
    try {
      const [fetchedTickets, fetchedLogs] = await Promise.all([
        fetchTickets(),
        fetchEscalationLogs(),
      ]);
      setTickets(fetchedTickets);
      setLogs(fetchedLogs);
      // Default to first escalable ticket
      if (fetchedTickets.length > 0) {
        const first = fetchedTickets.find((t) => ESCALABLE_STATUSES.includes(t.status));
        if (first) setSelectedId(first.id);
      }
    } catch {
      toast.error('Failed to load tickets or escalation history.');
    } finally {
      setLoadingData(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const handleSubmit = async () => {
    let hasError = false;

    const notesErr = validateReason(notes, 'Notes / Reason');
    if (notesErr) { setNotesError(notesErr); hasError = true; }

    if (escalationType === 'external' && !escalateTo.trim()) {
      setEscalateToError('Distributors / vendor name is required.');
      hasError = true;
    }

    if (!selectedId) { toast.error('Please select a ticket.'); return; }
    if (hasError) return;

    setSubmitting(true);
    try {
      if (escalationType === 'internal') {
        await escalateTicket(selectedId as number, { notes });
        toast.success('Ticket escalated internally. A supervisor will reassign it.');
      } else {
        await escalateExternal(selectedId as number, {
          external_escalated_to: escalateTo.trim(),
          external_escalation_notes: notes,
        });
        toast.success(`Ticket escalated externally to "${escalateTo.trim()}".`);
      }
      setNotes('');
      setEscalateTo('');
      setNotesError('');
      setEscalateToError('');
      await loadData();
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to submit escalation.');
    } finally {
      setSubmitting(false);
    }
  };

  /* ── History pagination ── */
  const sortedLogs = [...logs].sort(
    (a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
  );
  const totalPages = Math.max(1, Math.ceil(sortedLogs.length / ITEMS_PER_PAGE));
  const pagedLogs = sortedLogs.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  /* ── Helpers ── */
  const getStfNo = (ticketId: number) =>
    tickets.find((t) => t.id === ticketId)?.stf_no ?? `#${ticketId}`;

  const formatDate = (iso: string) => {
    const d = new Date(iso);
    return d.toLocaleDateString('en-PH', { month: 'short', day: 'numeric', year: 'numeric' }) +
      ' ' + d.toLocaleTimeString('en-PH', { hour: '2-digit', minute: '2-digit' });
  };

  const typeLabel = (log: EscalationLog) =>
    log.escalation_type === 'internal' ? 'Internal' : 'External';

  const toLabel = (log: EscalationLog) =>
    log.to_external || (log.to_user ? `User #${log.to_user}` : 'Supervisor');

  return (
    <>
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Ticket Escalation</h1>
            <p className="text-gray-500 dark:text-gray-400">Escalation history for your tickets</p>
          </div>
          <button
            onClick={loadData}
            disabled={loadingData}
            className="p-2 rounded-lg text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
            title="Refresh"
          >
            <RefreshCw className={`w-4 h-4 ${loadingData ? 'animate-spin' : ''}`} />
          </button>
        </div>

        {loadingData ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 className="w-6 h-6 animate-spin text-[#3BC25B]" />
            <span className="ml-2 text-gray-500 dark:text-gray-400">Loading…</span>
          </div>
        ) : (
          <Card>
            <div className="flex items-center gap-2 mb-6">
              <History className="w-5 h-5 text-gray-500 dark:text-gray-400" />
              <h3 className="font-bold text-gray-900 dark:text-white">Escalation History</h3>
              <span className="ml-auto text-xs text-gray-400">{logs.length} total</span>
            </div>

            {logs.length === 0 ? (
              <div className="text-center py-12">
                <History className="w-10 h-10 text-gray-300 dark:text-gray-600 mx-auto mb-2" />
                <p className="text-sm text-gray-500 dark:text-gray-400">No escalations yet.</p>
              </div>
            ) : (
              <>
                <div className="space-y-4">
                  {pagedLogs.map((log) => {
                    const isInternal = log.escalation_type === 'internal';
                    return (
                      <div
                        key={log.id}
                        className={`p-4 rounded-lg border ${
                          isInternal
                              ? 'border-orange-200 dark:border-orange-800 bg-orange-50/50 dark:bg-orange-900/10'
                              : 'border-teal-200 dark:border-teal-800 bg-teal-50/50 dark:bg-teal-900/10'
                          }`}
                        >
                          <div className="flex items-start justify-between gap-3">
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-2 mb-1 flex-wrap">
                                <span className="text-sm font-bold text-gray-900 dark:text-white">
                                  {getStfNo(log.ticket)}
                                </span>
                                <span
                                  className={`text-[10px] px-2 py-0.5 rounded-full font-semibold ${
                                    isInternal
                                      ? 'bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-300'
                                      : 'bg-teal-100 dark:bg-teal-900/40 text-teal-700 dark:text-teal-300'
                                  }`}
                                >
                                  {typeLabel(log)}
                                </span>
                              </div>
                              <p className="text-sm text-gray-600 dark:text-gray-400">
                                To: <span className="font-medium text-gray-800 dark:text-gray-200">{toLabel(log)}</span>
                              </p>
                              {log.notes && (
                                <p className="text-xs text-gray-500 dark:text-gray-400 mt-1 truncate">
                                  &ldquo;{log.notes}&rdquo;
                                </p>
                              )}
                            </div>
                            <div className="text-right flex-shrink-0">
                              <span className="text-xs text-gray-400 whitespace-nowrap">
                                {formatDate(log.created_at)}
                              </span>
                              <div className="flex items-center justify-end gap-1 mt-1">
                                {isInternal ? (
                                  <AlertTriangle className="w-3.5 h-3.5 text-orange-500" />
                                ) : (
                                  <Clock className="w-3.5 h-3.5 text-teal-500" />
                                )}
                                <span className="text-xs text-gray-500 dark:text-gray-400">
                                  {isInternal ? 'Pending reassignment' : 'Externally escalated'}
                                </span>
                              </div>
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>

                  {/* Pagination */}
                  {totalPages > 1 && (
                    <div className="flex items-center justify-between mt-6 pt-4 border-t border-gray-100 dark:border-gray-700">
                      <button
                        onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                        disabled={currentPage === 1}
                        className="p-1.5 rounded-md text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                      >
                        <ChevronLeft className="w-4 h-4" />
                      </button>
                      <span className="text-xs text-gray-500 dark:text-gray-400">
                        Page {currentPage} of {totalPages}
                      </span>
                      <button
                        onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                        disabled={currentPage === totalPages}
                        className="p-1.5 rounded-md text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                      >
                        <ChevronRight className="w-4 h-4" />
                      </button>
                    </div>
                  )}
                </>
              )}
            </Card>
          )}
        </div>
    </>
  );
}

import { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Card } from '../../components/ui/Card';
import {
  Search,
  BookOpen,
  ArrowUpRight,
  Eye,
  X,
  ChevronLeft,
  ChevronRight,
  Image as ImageIcon,
  Film,
  File as FileIcon,
  ExternalLink,
  FileText,
  RefreshCw,
} from 'lucide-react';
import { toast } from 'sonner';
import type { PublishedArticle } from '../../services/api';
import { fetchPublishedArticles } from '../../services/api';

const ITEMS_PER_PAGE = 12;

function parseSteps(description: string): string[] {
  try {
    const parsed = JSON.parse(description);
    if (Array.isArray(parsed)) return parsed;
  } catch {
    // fallback: split by newlines for plain-text descriptions
  }
  return description.split('\n').filter((s: string) => s.trim());
}

function isImageUrl(url: string): boolean {
  return /\.(jpg|jpeg|png|gif|webp|svg|bmp)$/i.test(url);
}

function isVideoUrl(url: string): boolean {
  return /\.(mp4|webm|mov|avi|mkv)$/i.test(url);
}

function getFileExtension(url: string): string {
  const [path] = url.split('?');
  const name = path.split('/').pop() || '';
  return name.split('.').pop()?.toLowerCase() || '';
}

function getFileName(url: string): string {
  const [path] = url.split('?');
  const name = path.split('/').pop() || 'attachment';
  return decodeURIComponent(name);
}

function FileTypeIcon({ url }: { url: string }) {
  if (isImageUrl(url)) return <ImageIcon className="w-5 h-5 text-emerald-500" />;
  if (isVideoUrl(url)) return <Film className="w-5 h-5 text-purple-500" />;
  const ext = getFileExtension(url);
  if (['pdf', 'doc', 'docx', 'txt', 'xls', 'xlsx'].includes(ext)) {
    return <FileText className="w-5 h-5 text-blue-500" />;
  }
  return <FileIcon className="w-5 h-5 text-gray-500" />;
}

function DetailRow({ label, value }: { label: string; value: React.ReactNode }) {
  return (
    <div>
      <div className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">{label}</div>
      <div className="text-sm text-gray-800 dark:text-gray-200 break-words">{value || '—'}</div>
    </div>
  );
}

export default function TechnicalStaffKnowledgeBase() {
  const [search, setSearch] = useState('');
  const [selectedTag, setSelectedTag] = useState('All');
  const [selected, setSelected] = useState<PublishedArticle | null>(null);
  const [page, setPage] = useState(1);
  const [articles, setArticles] = useState<PublishedArticle[]>([]);
  const [loading, setLoading] = useState(false);

  const loadArticles = async () => {
    setLoading(true);
    try {
      const data = await fetchPublishedArticles(search ? { search } : undefined);
      setArticles(data);
    } catch {
      toast.error('Failed to load articles.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadArticles();
  }, []);

  // Collect unique tags across all articles
  const allTags = Array.from(new Set(articles.flatMap((a) => a.published_tags || [])));
  const TAG_OPTIONS = ['All', ...allTags];

  const filtered = articles.filter((a) => {
    const q = search.trim().toLowerCase();
    const steps = parseSteps(a.published_description);
    const matchSearch =
      !q ||
      a.published_title.toLowerCase().includes(q) ||
      steps.some((s) => s.toLowerCase().includes(q));
    const matchTag = selectedTag === 'All' || (a.published_tags || []).includes(selectedTag);
    return matchSearch && matchTag;
  });

  const totalPages = Math.ceil(filtered.length / ITEMS_PER_PAGE);
  const paged = filtered.slice((page - 1) * ITEMS_PER_PAGE, page * ITEMS_PER_PAGE);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Knowledge Hub</h1>
        <p className="text-gray-500 dark:text-gray-400">
          Troubleshooting guides and escalation procedures for common issues
        </p>
      </div>

      {/* Search & Filter */}
      <div className="flex flex-col md:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter') loadArticles(); }}
            placeholder="Search articles..."
            className="w-full pl-10 pr-4 py-2.5 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm outline-none focus:ring-2 focus:ring-[#3BC25B]"
          />
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          {TAG_OPTIONS.map((tag) => (
            <button
              key={tag}
              onClick={() => setSelectedTag(tag)}
              className={`px-3 py-1.5 rounded-full text-xs font-medium transition-colors ${
                selectedTag === tag
                  ? 'bg-[#0E8F79] text-white'
                  : 'bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
              }`}
            >
              {tag}
            </button>
          ))}
          <button
            onClick={loadArticles}
            className="p-1.5 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-400 transition-colors"
            title="Refresh"
          >
            <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
          </button>
        </div>
      </div>

      {/* Articles */}
      <div className="space-y-4">
        {loading && articles.length === 0 && (
          <div className="flex items-center justify-center py-12">
            <RefreshCw className="w-6 h-6 text-gray-400 animate-spin" />
          </div>
        )}
        {!loading && filtered.length === 0 && (
          <Card>
            <p className="text-center text-gray-500 dark:text-gray-400 py-8">No articles found matching your search.</p>
          </Card>
        )}
        {paged.length > 0 && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {paged.map((article) => {
              const steps = parseSteps(article.published_description);
              return (
                <Card
                  key={article.id}
                  className="p-0 overflow-hidden hover:shadow-lg transition-shadow cursor-pointer"
                  onClick={() => setSelected(article)}
                >
                  <div className="h-40 bg-gray-50 dark:bg-gray-900 flex items-center justify-center relative group">
                    {isImageUrl(article.file_url) ? (
                      <img
                        src={article.file_url}
                        alt={article.published_title}
                        className="w-full h-full object-cover"
                      />
                    ) : isVideoUrl(article.file_url) ? (
                      <video
                        src={article.file_url}
                        className="w-full h-full object-cover"
                        muted
                        playsInline
                        preload="metadata"
                      />
                    ) : (
                      <div className="flex flex-col items-center gap-2">
                        <FileTypeIcon url={article.file_url} />
                        <span className="text-xs text-gray-400 uppercase">{getFileExtension(article.file_url)}</span>
                      </div>
                    )}
                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/30 transition-colors flex items-center justify-center opacity-0 group-hover:opacity-100">
                      <Eye className="w-6 h-6 text-white" />
                    </div>
                  </div>

                  <div className="p-3 space-y-2">
                    <p className="text-sm font-semibold text-gray-900 dark:text-white line-clamp-2" title={article.published_title}>
                      {article.published_title}
                    </p>
                    <p className="text-xs text-[#0E8F79] font-medium">{article.stf_no}</p>

                    {article.published_tags && article.published_tags.length > 0 && (
                      <div className="flex flex-wrap gap-1">
                        {article.published_tags.slice(0, 3).map((tag, i) => (
                          <span key={i} className="px-2 py-0.5 rounded-full bg-[#0E8F79]/10 text-[#0E8F79] text-[10px] font-medium">
                            {tag}
                          </span>
                        ))}
                      </div>
                    )}

                    {steps.length > 0 && (
                      <ol className="list-decimal list-inside text-xs text-gray-500 dark:text-gray-400 space-y-0.5">
                        {steps.slice(0, 2).map((step, i) => (
                          <li key={i} className="truncate">{step}</li>
                        ))}
                      </ol>
                    )}

                    <div className="flex items-center justify-between pt-1 border-t border-gray-100 dark:border-gray-700">
                      <span className="text-[10px] text-gray-400">{article.published_by_name || 'Unknown'}</span>
                      <span className="text-[10px] text-gray-400">{new Date(article.published_at).toLocaleDateString()}</span>
                    </div>
                  </div>
                </Card>
              );
            })}
          </div>
        )}

        {totalPages > 1 && (
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 px-1">
            <p className="text-sm text-gray-500 dark:text-gray-400">
              Showing {(page - 1) * ITEMS_PER_PAGE + 1}–{Math.min(page * ITEMS_PER_PAGE, filtered.length)} of {filtered.length}
            </p>
            <div className="flex items-center gap-1">
              <button
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page === 1}
                className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-30 transition-colors"
              >
                <ChevronLeft className="w-4 h-4 text-gray-600 dark:text-gray-300" />
              </button>
              {Array.from({ length: totalPages }, (_, i) => i + 1)
                .filter((p) => p === 1 || p === totalPages || Math.abs(p - page) <= 1)
                .map((p, i, arr) => (
                  <React.Fragment key={p}>
                    {i > 0 && arr[i - 1] !== p - 1 && <span className="px-1 text-gray-400">…</span>}
                    <button
                      onClick={() => setPage(p)}
                      className={`w-8 h-8 rounded-lg text-sm font-medium transition-colors ${
                        p === page
                          ? 'bg-[#0E8F79] text-white'
                          : 'hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-600 dark:text-gray-300'
                      }`}
                    >
                      {p}
                    </button>
                  </React.Fragment>
                ))}
              <button
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-30 transition-colors"
              >
                <ChevronRight className="w-4 h-4 text-gray-600 dark:text-gray-300" />
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {selected && createPortal(
        <div
          className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4"
          onClick={() => setSelected(null)}
        >
          <div
            className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl max-w-3xl w-full max-h-[90vh] overflow-y-auto"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex items-center justify-between p-4 sm:p-5 border-b border-gray-100 dark:border-gray-700">
              <div>
                <h2 className="text-lg font-bold text-gray-900 dark:text-white">Article Details</h2>
                <p className="text-sm text-[#0E8F79] font-medium">{selected.stf_no}</p>
              </div>
              <button
                onClick={() => setSelected(null)}
                className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
              >
                <X className="w-5 h-5 text-gray-500" />
              </button>
            </div>

            <div className="p-4 sm:p-5 space-y-5">
              <div className="rounded-xl overflow-hidden bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700">
                {isImageUrl(selected.file_url) ? (
                  <img
                    src={selected.file_url}
                    alt={selected.published_title}
                    className="w-full max-h-96 object-contain"
                  />
                ) : isVideoUrl(selected.file_url) ? (
                  <div className="w-full aspect-video bg-black">
                    <video controls playsInline preload="metadata" className="w-full h-full object-cover bg-black">
                      <source src={selected.file_url} />
                      Your browser does not support the video tag.
                    </video>
                  </div>
                ) : (
                  <div className="flex flex-col items-center justify-center py-12 gap-3">
                    <FileTypeIcon url={selected.file_url} />
                    <p className="text-sm text-gray-500 dark:text-gray-400">{getFileName(selected.file_url)}</p>
                    <a
                      href={selected.file_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="inline-flex items-center gap-1.5 px-4 py-2 rounded-lg bg-[#0E8F79] text-white text-sm font-medium hover:bg-[#0b7a67] transition-colors"
                    >
                      <ExternalLink className="w-4 h-4" /> Open File
                    </a>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <DetailRow label="Title" value={selected.published_title} />
                <DetailRow label="STF Number" value={selected.stf_no} />
                <DetailRow label="File Name" value={getFileName(selected.file_url)} />
                <DetailRow label="Uploaded By" value={selected.uploaded_by_name || '—'} />
                <DetailRow label="Published By" value={selected.published_by_name || '—'} />
                <DetailRow label="Uploaded At" value={new Date(selected.uploaded_at).toLocaleString()} />
                <DetailRow label="Published At" value={new Date(selected.published_at).toLocaleString()} />
                <DetailRow
                  label="Tags"
                  value={
                    (selected.published_tags && selected.published_tags.length > 0) ? (
                      <div className="flex flex-wrap gap-1">
                        {selected.published_tags.map((tag, i) => (
                          <span key={i} className="px-2 py-0.5 rounded-full bg-[#0E8F79]/10 text-[#0E8F79] text-[10px] font-medium">
                            {tag}
                          </span>
                        ))}
                      </div>
                    ) : '—'
                  }
                />
              </div>

              <div>
                <h4 className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-2">
                  Troubleshooting Steps
                </h4>
                <ol className="list-decimal list-inside text-sm text-gray-700 dark:text-gray-300 space-y-2">
                  {parseSteps(selected.published_description).map((step, i) => (
                    <li key={i}>{step}</li>
                  ))}
                </ol>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
}

import React, { useEffect, useState, useMemo } from 'react';
import { useAuth } from '../../context/AuthContext';
import { Card } from '../../components/ui/Card';
import { StatCard } from '../../components/ui/StatCard';
import { fetchTickets } from '../../services/api';
import type { BackendTicket } from '../../services/api';
import { BarChart3, FileDown, FileSpreadsheet, ChevronDown } from 'lucide-react';
import { PieChart, Pie, Cell, Tooltip as ReTooltip, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from 'recharts';
import { toast } from 'sonner';
import { buildPdfDocument, openPrintWindow } from '../../utils/pdfTemplate';

export default function TechnicalStaffReports() {
  const { user } = useAuth();
  const [tickets, setTickets] = useState<BackendTicket[] | null>(null);
  const [loading, setLoading] = useState(true);
  const [showExportMenu, setShowExportMenu] = useState(false);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        setLoading(true);
        const raw = await fetchTickets();
        if (cancelled) return;
        setTickets(raw);
      } catch {
        if (!cancelled) setTickets([]);
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, []);

  const myId = user?.id ?? null;
  const myTickets = (tickets || []).filter((t) => t.assigned_to?.id === myId);

  const assigned = myTickets.filter((t) => t.status === 'open' || (t.status === 'open' && t.assigned_to));
  const ongoing = myTickets.filter((t) => t.status === 'in_progress');
  const resolved = myTickets.filter((t) => t.status === 'pending_closure' || t.status === 'closed');

  const pieData = useMemo(() => [
    { name: 'Assigned', value: assigned.length },
    { name: 'Ongoing', value: ongoing.length },
    { name: 'Resolved', value: resolved.length },
  ], [assigned.length, ongoing.length, resolved.length]);

  const COLORS = ['#60A5FA', '#F59E0B', '#10B981'];

  // Monthly handled tickets (last 6 months)
  const monthlyData = useMemo(() => {
    const now = new Date();
    const months: { key: string; name: string; start: Date; end: Date }[] = [];
    for (let i = 5; i >= 0; i--) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const name = d.toLocaleString('default', { month: 'short' });
      const start = new Date(d.getFullYear(), d.getMonth(), 1, 0, 0, 0);
      const end = new Date(d.getFullYear(), d.getMonth() + 1, 1, 0, 0, 0);
      months.push({ key: `${d.getFullYear()}-${d.getMonth()}`, name, start, end });
    }
    return months.map((m) => {
      const created = myTickets.filter((t) => {
        const c = new Date(t.created_at);
        return c >= m.start && c < m.end;
      }).length;
      const closed = myTickets.filter((t) => {
        const u = new Date(t.updated_at);
        return u >= m.start && u < m.end && (t.status === 'pending_closure' || t.status === 'closed');
      }).length;
      return { name: m.name, created, closed };
    });
  }, [myTickets]);

  const handleExportCSV = () => {
    const rows = [['stf_no', 'status', 'priority', 'client', 'created_at', 'updated_at']];
    for (const t of myTickets) {
      rows.push([t.stf_no, t.status, t.priority || '', t.client || '', t.created_at || '', t.updated_at || '']);
    }
    const csv = rows.map((r) => r.map((c) => `"${String(c).replace(/"/g, '""')}"`).join(',')).join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `technical_staff_${user?.id ?? 'me'}_tickets_${new Date().toISOString().slice(0,10)}.csv`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
    toast.success('CSV exported');
    setShowExportMenu(false);
  };

  const handleExportPDF = () => {
    setShowExportMenu(false);
    const dateTag = new Date().toISOString().slice(0,10);
    const body = `
      <div class="stat-grid">
        <div class="stat-card"><div class="stat-label">Assigned</div><div class="stat-value">${assigned.length}</div></div>
        <div class="stat-card"><div class="stat-label">Ongoing</div><div class="stat-value">${ongoing.length}</div></div>
        <div class="stat-card"><div class="stat-label">Resolved</div><div class="stat-value">${resolved.length}</div></div>
      </div>
      <h3>Recent Tickets</h3>
      <table>
        <thead><tr><th>STF</th><th>Status</th><th>Created</th></tr></thead>
        <tbody>
          ${myTickets.slice(0,20).map((t) => `<tr><td>${t.stf_no}</td><td>${t.status}</td><td>${new Date(t.created_at).toLocaleDateString()}</td></tr>`).join('')}
        </tbody>
      </table>
    `;
    const html = buildPdfDocument('Technical Staff Reports - Maptech Ticketing System', 'Technical Staff Reports', body, `${myTickets.length} tickets`);
    void openPrintWindow(html, `technical_staff_reports_${dateTag}.pdf`).then(() => toast.success('PDF downloaded')).catch(() => toast.error('PDF export failed'));
  };

  const renderList = (items: BackendTicket[]) => (
    <div className="space-y-2">
      {items.length === 0 && <div className="text-sm text-gray-500">No tickets</div>}
      {items.slice(0, 6).map((t) => (
        <div key={t.id} className="flex flex-col sm:flex-row sm:items-start justify-between gap-2 p-3 bg-white dark:bg-gray-800 rounded-md border border-gray-100 dark:border-gray-700">
          <div className="min-w-0 flex-1">
            <div className="font-mono text-xs font-bold text-gray-900 dark:text-white">{t.stf_no}</div>
            <div className="text-sm text-gray-600 dark:text-gray-300 whitespace-normal break-words leading-snug">
              {t.description_of_problem || t.type_of_service_detail?.name || 'No description'}
            </div>
          </div>
          <div className="text-xs text-gray-500 whitespace-nowrap sm:ml-4 sm:text-right">{new Date(t.created_at).toLocaleDateString()}</div>
        </div>
      ))}
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Reports</h1>
          <p className="text-gray-500 dark:text-gray-400">Tickets assigned / in progress / resolved by you</p>
        </div>
        <div className="relative">
          <button onClick={() => setShowExportMenu((v) => !v)} className="inline-flex items-center gap-2 px-3 py-2 bg-[#0E8F79] text-white rounded-md">
            <FileDown className="w-4 h-4" /> Export
            <ChevronDown className="w-4 h-4" />
          </button>
          {showExportMenu && (
            <>
              <div className="fixed inset-0 z-40" onClick={() => setShowExportMenu(false)} />
              <div className="absolute right-0 mt-2 w-44 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 z-50 overflow-hidden">
                <button onClick={handleExportPDF} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"><FileDown className="w-4 h-4 text-red-500" /> Export PDF</button>
                <button onClick={handleExportCSV} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"><FileSpreadsheet className="w-4 h-4 text-[#0E8F79]" /> Export CSV</button>
              </div>
            </>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <StatCard title="Assigned" value={loading ? '—' : String(assigned.length)} icon={BarChart3} color="blue" />
        <StatCard title="Ongoing" value={loading ? '—' : String(ongoing.length)} icon={BarChart3} color="orange" />
        <StatCard title="Resolved" value={loading ? '—' : String(resolved.length)} icon={BarChart3} color="green" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card>
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-bold text-gray-900 dark:text-white">Tickets by Status</h3>
            <span className="text-xs text-gray-400 dark:text-gray-500">Technical staff overview</span>
          </div>
          <div className="h-72">
            {pieData.length === 0 ? (
              <div className="h-full flex items-center justify-center text-sm text-gray-500 dark:text-gray-400">No ticket data available.</div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={pieData.map((p, i) => ({ ...p, color: COLORS[i % COLORS.length] }))}
                    cx="50%"
                    cy="46%"
                    innerRadius={58}
                    outerRadius={88}
                    paddingAngle={3}
                    dataKey="value"
                    nameKey="name"
                  >
                    {pieData.map((entry, index) => (
                      <Cell key={entry.name} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip
                    contentStyle={{
                      backgroundColor: '#ffffff',
                      border: '1px solid #E5E7EB',
                      borderRadius: '8px',
                      color: '#111827',
                      boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)',
                    }}
                  />
                  <Legend verticalAlign="bottom" height={36} wrapperStyle={{ color: '#6b7280', fontSize: '12px' }} />
                </PieChart>
              </ResponsiveContainer>
            )}
          </div>
        </Card>

        <Card>
          <h3 className="text-lg font-bold mb-4">Monthly Handling</h3>
          <div className="h-56">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e5e7eb" />
                <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                <YAxis tick={{ fontSize: 12 }} />
                <Tooltip />
                <Legend />
                <Bar dataKey="created" fill="#3BC25B" name="Created" />
                <Bar dataKey="closed" fill="#0E8F79" name="Resolved" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </Card>

        <Card>
          <h3 className="text-lg font-bold mb-4">Recent Resolved</h3>
          {loading ? <div className="text-sm text-gray-500">Loading…</div> : renderList(resolved)}
        </Card>
      </div>
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { createPortal } from 'react-dom';
import { Card } from '../../components/ui/Card';
import { GreenButton } from '../../components/ui/GreenButton';
import { User, Lock, Mail, Phone, Building, Shield, Pencil, X, Loader2, Camera, Eye, EyeOff } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { changePassword, updateProfile, uploadAvatar, removeAvatar } from '../../services/authService';
import { toast } from 'sonner';
import {
  validatePassword,
  validateConfirmPassword,
  validateName,
  validatePhone,
  checkPasswordPwned,
  MAX_PASSWORD,
  MAX_NAME,
  MAX_PHONE,
  type PasswordRules,
} from '../../utils/validation';

export default function TechnicalStaffSettings() {
  const { user, updateUser } = useAuth();

  /* ── Profile editing state ── */
  const [editing, setEditing] = useState(false);
  const [profileLoading, setProfileLoading] = useState(false);
  const [form, setForm] = useState({
    first_name: user?.first_name || '',
    middle_name: user?.middle_name || '',
    last_name: user?.last_name || '',
    suffix: user?.suffix || '',
    phone: user?.phone || '',
  });
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});

  const startEdit = () => {
    setForm({
      first_name: user?.first_name || '',
      middle_name: user?.middle_name || '',
      last_name: user?.last_name || '',
      suffix: user?.suffix || '',
      phone: user?.phone || '',
    });
    setFieldErrors({});
    setEditing(true);
  };

  const cancelEdit = () => { setEditing(false); setFieldErrors({}); };

  /* ── Avatar upload ── */
  const avatarInputRef = useRef<HTMLInputElement>(null);
  const [avatarLoading, setAvatarLoading] = useState(false);
  const [removeAvatarLoading, setRemoveAvatarLoading] = useState(false);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
  const [avatarImgError, setAvatarImgError] = useState(false);
  const [avatarLightboxOpen, setAvatarLightboxOpen] = useState(false);

  const avatarSrc = avatarPreview
    ? avatarPreview
    : user?.profile_picture_url
    ? `${user.profile_picture_url}?t=${encodeURIComponent(user.profile_picture_url.split('/').pop() || '')}`
    : null;

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const blobUrl = URL.createObjectURL(file);
    setAvatarPreview(blobUrl);
    setAvatarImgError(false);
    setAvatarLoading(true);
    // Update navbar instantly with the local blob so the circle reflects the new photo right away
    updateUser({ profile_picture_url: blobUrl });
    try {
      const updated = await uploadAvatar(file);
      // Replace blob URL in context with the permanent server URL
      updateUser({ profile_picture_url: updated.profile_picture_url ?? null });
      toast.success('Profile picture updated.');
    } catch (err) {
      setAvatarPreview(null);
      updateUser({ profile_picture_url: user?.profile_picture_url ?? null });
      toast.error(err instanceof Error ? err.message : 'Failed to upload picture.');
    } finally {
      setAvatarLoading(false);
      // Delay revocation so React can flush the server URL update to the navbar before the blob dies
      setTimeout(() => URL.revokeObjectURL(blobUrl), 5000);
      if (avatarInputRef.current) avatarInputRef.current.value = '';
    }
  };

  const handleRemoveAvatar = async () => {
    setRemoveAvatarLoading(true);
    try {
      await removeAvatar();
      setAvatarPreview(null);
      setAvatarImgError(false);
      updateUser({ profile_picture_url: null });
      toast.success('Profile picture removed.');
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to remove picture.');
    } finally {
      setRemoveAvatarLoading(false);
    }
  };

  const handleField = (field: string, value: string) => {
    setForm((p) => ({ ...p, [field]: value }));
    setFieldErrors((p) => ({ ...p, [field]: '' }));
  };

  const handleSaveProfile = async () => {
    const errs: Record<string, string> = {};
    const fnErr = validateName(form.first_name, 'First name');
    if (fnErr) errs.first_name = fnErr;
    const lnErr = validateName(form.last_name, 'Last name');
    if (lnErr) errs.last_name = lnErr;
    if (form.phone) {
      const phErr = validatePhone(form.phone);
      if (phErr) errs.phone = phErr;
    }
    if (Object.keys(errs).length) { setFieldErrors(errs); return; }

    setProfileLoading(true);
    try {
      const updated = await updateProfile(form);
      updateUser({
        first_name: updated.first_name,
        middle_name: updated.middle_name,
        last_name: updated.last_name,
        suffix: updated.suffix,
        phone: updated.phone,
      });
      toast.success('Profile updated successfully.');
      setEditing(false);
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to update profile.');
    } finally {
      setProfileLoading(false);
    }
  };

  /* ── Password state ── */
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [pwError, setPwError] = useState('');
  const [pwLoading, setPwLoading] = useState(false);
  const [pwRules, setPwRules] = useState<PasswordRules | null>(null);
  const [showCurrent, setShowCurrent] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setPwError('');
    if (!currentPassword || !newPassword || !confirmPassword) {
      setPwError('All fields are required.');
      return;
    }
    const { error } = validatePassword(newPassword);
    if (error) { setPwError(error); return; }
    const confirmErr = validateConfirmPassword(newPassword, confirmPassword);
    if (confirmErr) { setPwError(confirmErr); return; }

    setPwLoading(true);
    try {
      const breached = await checkPasswordPwned(newPassword);
      if (breached) {
        setPwError('This password has been found in a data breach. Please choose a different password.');
        setPwRules((prev) => prev ? { ...prev, notBreached: false } : prev);
        return;
      }
      await changePassword(currentPassword, newPassword);
      toast.success('Password changed successfully.');
      setCurrentPassword('');
      setNewPassword('');
      setConfirmPassword('');
      setPwRules(null);
    } catch (err) {
      setPwError(err instanceof Error ? err.message : 'Failed to change password.');
    } finally {
      setPwLoading(false);
    }
  };

  /* ── Helpers ── */
  const inputClass = 'w-full bg-transparent outline-none text-sm text-gray-900 dark:text-white placeholder-gray-400';
  const boxEdit = 'flex items-center gap-2 px-3 py-2.5 rounded-lg bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 focus-within:ring-2 focus-within:ring-[#3BC25B]';
  const boxReadonly = 'flex items-center gap-2 px-3 py-2.5 rounded-lg bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700';

  return (
    <div className="space-y-6 max-w-3xl">
      <div>
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Settings</h1>
        <p className="text-gray-500 dark:text-gray-400">Manage your account settings</p>
      </div>

      {/* ── Personal Details ── */}
      <Card accent>
        {/* Avatar */}
        <div className="flex items-center gap-6 mb-6">
          <div className="relative flex-shrink-0">
            {/* Circle: click image → preview; click empty circle → file picker */}
            <div
              className="w-28 h-28 rounded-full overflow-hidden bg-gray-200 dark:bg-gray-700 border-2 border-gray-300 dark:border-gray-600 flex items-center justify-center cursor-pointer group"
              onClick={() => {
                if (avatarLoading || removeAvatarLoading) return;
                if (avatarSrc && !avatarImgError) setAvatarLightboxOpen(true);
                else avatarInputRef.current?.click();
              }}
            >
              {avatarSrc && !avatarImgError ? (
                <img
                  src={avatarSrc}
                  alt="Profile"
                  className="w-full h-full object-cover"
                  onError={() => setAvatarImgError(true)}
                />
              ) : (
                <User className="w-12 h-12 text-gray-400" />
              )}
              <div className="absolute inset-0 rounded-full flex items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity">
                {avatarLoading
                  ? <Loader2 className="w-6 h-6 text-white animate-spin" />
                  : (avatarSrc && !avatarImgError)
                  ? <Eye className="w-6 h-6 text-white" />
                  : <Camera className="w-6 h-6 text-white" />}
              </div>
            </div>
            <input ref={avatarInputRef} type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
          </div>
          <div>
            <p className="text-sm font-semibold text-gray-900 dark:text-white">Profile Picture</p>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">JPG, PNG or GIF · Max 5 MB</p>
            <div className="flex items-center gap-3 mt-2">
              <button
                type="button"
                onClick={() => !avatarLoading && !removeAvatarLoading && avatarInputRef.current?.click()}
                disabled={avatarLoading || removeAvatarLoading}
                className="text-xs font-medium text-[#3BC25B] hover:text-[#63D44A] transition-colors disabled:opacity-50"
              >
                {avatarLoading ? 'Uploading…' : 'Change photo'}
              </button>
              {(user?.profile_picture_url || avatarPreview) && (
                <>
                  <span className="text-gray-500 dark:text-gray-600 text-xs">·</span>
                  <button
                    type="button"
                    onClick={handleRemoveAvatar}
                    disabled={avatarLoading || removeAvatarLoading}
                    className="text-xs font-medium text-red-400 hover:text-red-500 transition-colors disabled:opacity-50"
                  >
                    {removeAvatarLoading ? 'Removing…' : 'Remove photo'}
                  </button>
                </>
              )}
            </div>
          </div>
        </div>

        {/* Lightbox */}
        {avatarLightboxOpen && avatarSrc && createPortal(
          <div
            className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm"
            onClick={() => setAvatarLightboxOpen(false)}
          >
            <div className="relative max-w-sm w-full mx-4" onClick={(e) => e.stopPropagation()}>
              <button
                onClick={() => setAvatarLightboxOpen(false)}
                className="absolute -top-3 -right-3 z-10 w-8 h-8 rounded-full bg-gray-800 border border-gray-600 flex items-center justify-center text-gray-300 hover:text-white hover:bg-gray-700 transition-colors"
              >
                <X className="w-4 h-4" />
              </button>
              <img
                src={avatarSrc}
                alt="Profile preview"
                className="w-full rounded-2xl object-cover shadow-2xl"
              />
            </div>
          </div>,
          document.body
        )}

        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Personal Details</h2>
        </div>

        {!editing ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {[
              { label: 'First Name', value: user?.first_name || '—', icon: User },
              { label: 'Last Name', value: user?.last_name || '—', icon: User },
              { label: 'Middle Name', value: user?.middle_name || '—', icon: User },
              { label: 'Suffix', value: user?.suffix || '—', icon: User },
              { label: 'Email', value: user?.email || '—', icon: Mail },
              { label: 'Phone', value: user?.phone || '—', icon: Phone },
              { label: 'Department', value: 'Technical Support', icon: Building },
              { label: 'Role', value: 'Technical Staff', icon: Shield },
            ].map((f) => (
              <div key={f.label}>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">{f.label}</label>
                <div className={boxReadonly}>
                  <f.icon className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-700 dark:text-gray-300">{f.value}</span>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">First Name <span className="text-red-400">*</span></label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.first_name} maxLength={MAX_NAME} onChange={(e) => handleField('first_name', e.target.value)} className={inputClass} placeholder="First name" />
                </div>
                {fieldErrors.first_name && <p className="text-xs text-red-400 mt-1">{fieldErrors.first_name}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Last Name <span className="text-red-400">*</span></label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.last_name} maxLength={MAX_NAME} onChange={(e) => handleField('last_name', e.target.value)} className={inputClass} placeholder="Last name" />
                </div>
                {fieldErrors.last_name && <p className="text-xs text-red-400 mt-1">{fieldErrors.last_name}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Middle Name</label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.middle_name} maxLength={MAX_NAME} onChange={(e) => handleField('middle_name', e.target.value)} className={inputClass} placeholder="Middle name (optional)" />
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Suffix</label>
                <div className={boxEdit}>
                  <User className="w-4 h-4 text-gray-400" />
                  <input value={form.suffix} maxLength={10} onChange={(e) => handleField('suffix', e.target.value)} className={inputClass} placeholder="e.g. Jr., Sr., III" />
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Phone</label>
                <div className={boxEdit}>
                  <Phone className="w-4 h-4 text-gray-400" />
                  <input value={form.phone} maxLength={MAX_PHONE} onChange={(e) => handleField('phone', e.target.value)} className={inputClass} placeholder="+63 9XX XXX XXXX" />
                </div>
                {fieldErrors.phone && <p className="text-xs text-red-400 mt-1">{fieldErrors.phone}</p>}
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Email</label>
                <div className={boxReadonly}>
                  <Mail className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-500 dark:text-gray-400">{user?.email || '—'}</span>
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Role</label>
                <div className={boxReadonly}>
                  <Shield className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-gray-500 dark:text-gray-400">Technical Staff</span>
                </div>
              </div>
            </div>
            <div className="flex gap-3 pt-2">
              <GreenButton type="button" onClick={handleSaveProfile} disabled={profileLoading}>
                {profileLoading ? <><Loader2 className="w-4 h-4 animate-spin" /> Saving…</> : 'Save Changes'}
              </GreenButton>
              <button type="button" onClick={cancelEdit} className="px-4 py-2 rounded-lg text-sm font-medium text-gray-400 hover:text-white border border-gray-600 hover:border-gray-500 transition-colors">
                Cancel
              </button>
            </div>
          </div>
        )}
      </Card>

      {/* ── Change Password ── */}
      <Card accent>
        <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">Change Password</h2>
        <form onSubmit={handleChangePassword} className="space-y-4 max-w-md">
          {pwError && <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 text-sm">{pwError}</div>}
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Current Password</label>
            <div className={`${boxEdit} relative`}>
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showCurrent ? 'text' : 'password'} value={currentPassword} maxLength={MAX_PASSWORD} onChange={(e) => setCurrentPassword(e.target.value)} placeholder="••••••••" className={`${inputClass} pr-10`} />
              <button type="button" onClick={() => setShowCurrent((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showCurrent ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">New Password</label>
            <div className={`${boxEdit} relative`}>
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showNew ? 'text' : 'password'} value={newPassword} maxLength={MAX_PASSWORD} onChange={(e) => { setNewPassword(e.target.value); const { rules } = validatePassword(e.target.value); setPwRules(rules); }} placeholder="••••••••" className={`${inputClass} pr-10`} />
              <button type="button" onClick={() => setShowNew((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showNew ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
            {newPassword && pwRules && (
              <ul className="text-xs space-y-0.5 mt-1.5">
                {[
                  { ok: pwRules.minLength, text: 'At least 8 characters' },
                  { ok: pwRules.hasUppercase, text: 'An uppercase letter' },
                  { ok: pwRules.hasLowercase, text: 'A lowercase letter' },
                  { ok: pwRules.hasNumber, text: 'A number' },
                  { ok: pwRules.hasSpecial, text: 'A special character' },
                ].map((r) => (
                  <li key={r.text} className={r.ok ? 'text-green-600' : 'text-red-500'}>
                    {r.ok ? '\u2713' : '\u2717'} {r.text}
                  </li>
                ))}
              </ul>
            )}
          </div>
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Confirm New Password</label>
            <div className={`${boxEdit} relative`}>
              <Lock className="w-4 h-4 text-gray-400" />
              <input type={showConfirm ? 'text' : 'password'} value={confirmPassword} maxLength={MAX_PASSWORD} onChange={(e) => setConfirmPassword(e.target.value)} placeholder="••••••••" className={`${inputClass} pr-10`} />
              <button type="button" onClick={() => setShowConfirm((s) => !s)} className="absolute right-3 text-gray-500 hover:text-gray-700 dark:hover:text-gray-300" aria-label="Toggle password visibility">
                {showConfirm ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <GreenButton type="submit" disabled={pwLoading}>
            {pwLoading ? 'Updating…' : 'Update Password'}
          </GreenButton>
        </form>
      </Card>
    </div>
  );
}

import { MAPTECH_LOGO_BASE64 } from './pdfLogo';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

/**
 * Shared PDF template system for professional Maptech-branded exports.
 * Provides consistent CSS, header, and footer across all PDF exports.
 */

export const PDF_CSS = `
  @page { margin: 0; size: A4; }
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    font-family: 'Segoe UI', -apple-system, BlinkMacSystemFont, Roboto, 'Helvetica Neue', Arial, sans-serif;
    color: #1f2937; background: #fff; padding: 0 0 60px 0;
    -webkit-print-color-adjust: exact; print-color-adjust: exact;
    font-size: 11px;
    line-height: 1.4;
  }
  .page-wrapper { padding: 0 32px 60px 32px; }
  /* ── Header Banner ── */
  .header-banner {
    background: #ffffff;
    padding: 20px 32px 16px 32px;
    display: flex; align-items: center; gap: 16px;
    margin-bottom: 0;
    border-bottom: 3px solid #154734;
  }
  .header-logo { height: 52px; width: auto; }
  .header-text { flex: 1; }
  .header-title {
    font-size: 20px; font-weight: 700; color: #154734; letter-spacing: 0.3px;
    margin-bottom: 2px;
  }
  .header-company {
    font-size: 9px; color: #6b7280; text-transform: uppercase;
    letter-spacing: 1.5px; font-weight: 500;
  }
  /* ── Sub-header ── */
  .sub-header {
    background: #e8faf0; padding: 8px 32px;
    display: flex; justify-content: space-between; align-items: center;
    border-bottom: 2px solid #2FAD52;
    margin-bottom: 20px;
  }
  .sub-header-left { font-size: 11px; color: #154734; font-weight: 600; }
  .sub-header-right { font-size: 10px; color: #6b7280; }
  /* ── Stat Cards ── */
  .stat-grid {
    display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px;
    margin-bottom: 20px;
  }
  .stat-card {
    background: #ffffff; border: 1px solid #d1fae5; border-radius: 8px;
    border-left: 4px solid #154734;
    padding: 12px 14px; overflow: hidden;
    min-height: 70px;
  }
  .stat-label {
    font-size: 9px; color: #6b7280; text-transform: uppercase;
    letter-spacing: 0.6px; font-weight: 600; margin-bottom: 4px;
  }
  .stat-value { 
    font-size: 16px; font-weight: 700; color: #154734; 
    line-height: 1.2; word-break: break-word;
  }
  /* ── Section Headings ── */
  h2 {
    font-size: 13px; font-weight: 700; color: #154734;
    margin: 18px 0 10px; padding: 6px 0 6px 12px;
    border-left: 4px solid #2FAD52; background: #f0fdf4;
    border-radius: 0 6px 6px 0; letter-spacing: 0.2px;
  }
  h2:first-child { margin-top: 0; }
  h3 {
    font-size: 13px;
    font-weight: 700;
    color: #154734;
    margin: 18px 0 10px;
    line-height: 1.3;
  }
  /* ── Tables ── */
  table { width: 100%; border-collapse: collapse; margin-bottom: 16px; font-size: 10px; }
  thead tr {
    background: #154734;
  }
  th {
    padding: 8px 8px; text-align: left; color: #ffffff;
    font-weight: 600; text-transform: uppercase; font-size: 8px;
    letter-spacing: 0.5px; border: none;
  }
  td {
    padding: 6px 8px; border-bottom: 1px solid #e8faf0; color: #374151;
    font-size: 10px; vertical-align: top;
  }
  tbody tr:nth-child(even) { background: #f8fdf9; }
  /* ── Info Grid (for detail pages) ── */
  .info-grid {
    display: grid; grid-template-columns: 1fr 1fr; gap: 4px 24px;
    margin-bottom: 12px; padding: 10px 14px;
    background: #fafffe; border: 1px solid #e8faf0; border-radius: 6px;
  }
  .info-row { display: flex; gap: 6px; padding: 4px 0; font-size: 11px; align-items: flex-start; }
  .info-label { font-weight: 600; color: #154734; min-width: 120px; flex-shrink: 0; font-size: 10px; }
  .info-value { color: #1f2937; font-size: 11px; word-break: break-word; }
  .desc {
    padding: 12px 14px; background: #f8fdf9; border: 1px solid #e8faf0;
    border-radius: 6px; font-size: 11px; line-height: 1.6; margin-bottom: 12px;
    white-space: pre-wrap; color: #374151;
  }
  /* ── Signature Section ── */
  .signature-section {
    margin-top: 16px;
    padding: 12px 14px;
    background: #fafffe;
    border: 1px solid #e8faf0;
    border-radius: 6px;
  }
  .signature-row {
    display: flex;
    gap: 24px;
    align-items: flex-start;
  }
  .signature-item {
    flex: 1;
  }
  .signature-item .info-label {
    display: block;
    margin-bottom: 6px;
    font-weight: 600;
    color: #154734;
    font-size: 10px;
  }
  .signature-box {
    display: inline-block;
    padding: 8px 12px;
    background: #ffffff;
    border: 1px solid #d1fae5;
    border-radius: 6px;
    text-align: center;
    min-width: 150px;
    min-height: 60px;
  }
  .signature-box img {
    max-height: 60px;
    max-width: 180px;
    object-fit: contain;
  }
  /* ── Page Break Control ── */
  h2 { page-break-after: avoid; }
  .info-grid, .stat-grid, table { page-break-inside: avoid; }
  tr { page-break-inside: avoid; }
  .desc { page-break-inside: avoid; }
  .signature-section { page-break-inside: avoid; }
  /* ── Badge ── */
  .badge {
    display: inline-block; padding: 2px 8px; border-radius: 12px;
    font-size: 9px; font-weight: 700; letter-spacing: 0.3px;
  }
  /* ── Footer ── */
  .footer-wrap {
    position: fixed;
    bottom: 0;
    left: 0;
    width: 100%;
  }
  .footer-divider {
    height: 3px; background: #2FAD52;
    margin-bottom: 0;
  }
  .footer-bar {
    background: #154734;
    padding: 10px 20px; display: flex;
    justify-content: space-between; align-items: center;
  }
  .footer-left { color: #ffffff; font-size: 10px; font-weight: 600; }
  .footer-right { color: rgba(255,255,255,0.8); font-size: 9px; text-align: right; line-height: 1.4; }
  /* ── Print ── */
  @media print {
    body { padding: 0 0 60px 0; }
    .page-wrapper { padding: 0 32px 60px 32px; }
    .header-banner { padding: 20px 32px 16px 32px; }
    .sub-header { padding: 8px 32px; }
    .footer-wrap {
      position: fixed;
      bottom: 0;
      left: 0;
      width: 100%;
    }
    .footer-bar { padding: 10px 20px; }
  }
`;

/** Generate the branded header banner HTML */
export function pdfHeader(
  reportTitle: string,
  dateStr: string,
  timeStr: string,
): string {
  return `
    <div class="header-banner">
      <img src="${MAPTECH_LOGO_BASE64}" alt="Maptech" class="header-logo" />
      <div class="header-text">
        <div class="header-title">${reportTitle}</div>
        <div class="header-company">Maptech Information Solutions Inc.</div>
      </div>
    </div>
    <div class="sub-header">
      <span class="sub-header-left">Official Document</span>
      <span class="sub-header-right">Generated on ${dateStr} at ${timeStr}</span>
    </div>
  `;
}

/** Generate the branded footer HTML */
export function pdfFooter(recordCount: string, dateIso: string, timeStr: string): string {
  return `
    <div class="footer-wrap">
      <div class="footer-divider"></div>
      <div class="footer-bar">
        <div class="footer-left">Maptech Information Solutions Inc.</div>
        <div class="footer-right">
          ${recordCount} &bull; ${dateIso} ${timeStr}<br/>
          Confidential &mdash; For Authorized Use Only
        </div>
      </div>
    </div>
  `;
}

/** Build a full PDF document string ready for window.document.write() */
export function buildPdfDocument(
  title: string,
  reportTitle: string,
  bodyContent: string,
  recordSummary: string,
  _signatureData?: string,
  _signedBy?: string,
): string {
  const now = new Date();
  const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
  const timeStr = now.toLocaleTimeString();
  const dateIso = now.toISOString().slice(0, 10);

  return `<!DOCTYPE html><html><head>
    <title>${title}</title>
    <style>${PDF_CSS}</style>
  </head><body>
    ${pdfHeader(reportTitle, dateStr, timeStr)}
    <div class="page-wrapper">
      ${bodyContent}
    </div>
    ${pdfFooter(recordSummary, dateIso, timeStr)}
  </body></html>`;
}

function sanitizeFileName(fileName: string): string {
  const trimmed = fileName.trim() || 'maptech-report';
  const safe = trimmed.replace(/[\\/:*?"<>|]+/g, '-').replace(/\s+/g, '_');
  return safe.toLowerCase().endsWith('.pdf') ? safe : `${safe}.pdf`;
}

/**
 * Generate and automatically download a PDF file from branded report HTML.
 * Keeps the existing function name for backward compatibility across pages.
 */
export async function openPrintWindow(html: string, fileName = 'maptech-report.pdf'): Promise<void> {
  const safeFileName = sanitizeFileName(fileName);

  const iframe = document.createElement('iframe');
  iframe.setAttribute('aria-hidden', 'true');
  iframe.style.position = 'fixed';
  iframe.style.visibility = 'hidden';
  iframe.style.right = '-10000px';
  iframe.style.bottom = '-10000px';
  iframe.style.width = '794px';
  iframe.style.height = '1123px';
  iframe.style.border = '0';
  document.body.appendChild(iframe);

  const cleanup = () => {
    if (iframe.parentNode) {
      iframe.parentNode.removeChild(iframe);
    }
  };

  const exportTask = async () => {
    const frameDoc = iframe.contentDocument;
    if (!frameDoc) throw new Error('Unable to initialize PDF document frame.');

    frameDoc.open();
    frameDoc.write(html);
    frameDoc.close();

    await new Promise<void>((resolve) => {
      if (frameDoc.readyState === 'complete') {
        resolve();
        return;
      }
      iframe.onload = () => resolve();
      setTimeout(resolve, 400);
    });

    try {
      await frameDoc.fonts.ready;
    } catch {
      // continue even if fonts API is unavailable
    }

    const body = frameDoc.body;

    // Capture header and footer separately so they can be pinned to every
    // PDF page. The header is composed of `.header-banner` + `.sub-header`.
    const headerBanner = frameDoc.querySelector<HTMLElement>('.header-banner');
    const subHeader = frameDoc.querySelector<HTMLElement>('.sub-header');
    let headerCanvas: HTMLCanvasElement | null = null;
    if (headerBanner || subHeader) {
      const headerWrapper = frameDoc.createElement('div');
      headerWrapper.style.width = '100%';
      headerWrapper.style.boxSizing = 'border-box';
      if (headerBanner) headerWrapper.appendChild(headerBanner.cloneNode(true));
      if (subHeader) headerWrapper.appendChild(subHeader.cloneNode(true));
      // place the wrapper at the top so CSS applies correctly
      frameDoc.body.insertBefore(headerWrapper, frameDoc.body.firstChild);
      headerCanvas = await html2canvas(headerWrapper as any, {
        useCORS: true,
        backgroundColor: null,
        scale: 2,
        windowWidth: 794,
      });
      // remove the temporary wrapper
      headerWrapper.remove();
      // hide the original header elements so the main body capture does not
      // include them (we will draw the header separately on each page).
      if (headerBanner) headerBanner.style.display = 'none';
      if (subHeader) subHeader.style.display = 'none';
    }

    // Move footer from fixed positioning into normal document flow so we can
    // measure the true full-document height and capture it separately.
    const footerEl = frameDoc.querySelector<HTMLElement>('.footer-wrap');
    if (footerEl) {
      footerEl.style.position = 'static';
      footerEl.style.width = '100%';
    }

    // Reflow + expand iframe height.
    await new Promise<void>((r) => setTimeout(r, 80));
    iframe.style.height = `${body.scrollHeight}px`;
    await new Promise<void>((r) => setTimeout(r, 80));

    // Capture footer as its own canvas, then hide it from the body capture.
    let footerCanvas: HTMLCanvasElement | null = null;
    if (footerEl) {
      footerCanvas = await html2canvas(footerEl, {
        useCORS: true,
        backgroundColor: null,   // let the element's own CSS supply the background
        scale: 2,
        windowWidth: 794,
      });
      footerEl.style.display = 'none';
    }

    // Allow layout to recalculate without the footer.
    await new Promise<void>((r) => setTimeout(r, 30));
    const contentScrollH = body.scrollHeight;

    // Capture body content (footer already hidden).
    const contentCanvas = await html2canvas(body, {
      useCORS: true,
      backgroundColor: '#ffffff',
      scale: 2,
      windowWidth: 794,
      windowHeight: contentScrollH,
    });

    // PDF setup.
    const pdf = new jsPDF({ orientation: 'portrait', unit: 'pt', format: 'a4' });
    const pageW = pdf.internal.pageSize.getWidth();   // 595.28 pt
    const pageH = pdf.internal.pageSize.getHeight();  // 841.89 pt

    // pt per canvas-pixel conversion (content canvas is 794×scale wide → pageW pt wide).
    const ptPerPx = pageW / contentCanvas.width;

    // Footer height in PDF points.
    let footerH_pt = 0;
    let footerImgData = '';
    if (footerCanvas && footerCanvas.width > 0) {
      footerImgData = footerCanvas.toDataURL('image/png');
      footerH_pt = footerCanvas.height * ptPerPx;
    }

    // Header height in PDF points.
    let headerH_pt = 0;
    let headerImgData = '';
    if (headerCanvas && headerCanvas.width > 0) {
      headerImgData = headerCanvas.toDataURL('image/png');
      headerH_pt = headerCanvas.height * ptPerPx;
    }

    // Usable content height per page (between header and footer).
    const contentAreaH_pt = pageH - headerH_pt - footerH_pt;
    // Equivalent in canvas pixels — use Math.floor to guarantee no overrun.
    const maxSliceH_px = Math.floor(contentAreaH_pt / ptPerPx);

    // Collect every table-row's bottom edge (in canvas pixels) so we can find
    // page-break positions that fall between rows rather than through them.
    function rowBottomPx(row: HTMLElement): number {
      let top = 0;
      let el: HTMLElement | null = row;
      while (el && el !== body) {
        top += el.offsetTop;
        el = el.offsetParent as HTMLElement | null;
      }
      // ×2 because html2canvas was captured at scale 2.
      return Math.round((top + row.offsetHeight) * 2);
    }

    const rowEnds = Array.from(frameDoc.querySelectorAll<HTMLElement>('tr'))
      .map(rowBottomPx)
      .filter((y) => y > 0)
      .sort((a, b) => a - b);

    // Determine each page's start position in canvas pixels, snapping breaks
    // to the nearest row boundary so rows are never split mid-height.
    const sliceStarts: number[] = [];
    let cursor = 0;

    while (cursor < contentCanvas.height) {
      sliceStarts.push(cursor);
      const rawEnd = cursor + maxSliceH_px;
      if (rawEnd >= contentCanvas.height) break;

      // Best break = last row that ends at or before the raw cut point.
      const snapped = [...rowEnds].filter((y) => y > cursor && y <= rawEnd).pop();
      cursor = snapped ?? rawEnd;
    }

    // Render each page.
    for (let i = 0; i < sliceStarts.length; i++) {
      const top = sliceStarts[i];
      const bot =
        i + 1 < sliceStarts.length ? sliceStarts[i + 1] : contentCanvas.height;
      const sliceH_px = bot - top;
      const sliceH_pt = sliceH_px * ptPerPx; // always ≤ contentAreaH_pt

      if (i > 0) pdf.addPage();

      // Crop exactly this page's content slice from the full content canvas.
      const slice = document.createElement('canvas');
      slice.width = contentCanvas.width;
      slice.height = sliceH_px;
      const ctx = slice.getContext('2d');
      if (ctx) {
        ctx.drawImage(
          contentCanvas,
          0, top, contentCanvas.width, sliceH_px,
          0, 0,   contentCanvas.width, sliceH_px,
        );
      }

      // Place header at the top of the page (if available).
      if (headerImgData && headerH_pt > 0) {
        pdf.addImage(headerImgData, 'PNG', 0, 0, pageW, headerH_pt);
      }

      // Place the content slice below the header.
      pdf.addImage(slice.toDataURL('image/png'), 'PNG', 0, headerH_pt, pageW, sliceH_pt);

      // Pin footer flush to the bottom of every page.
      if (footerImgData && footerH_pt > 0) {
        pdf.addImage(footerImgData, 'PNG', 0, pageH - footerH_pt, pageW, footerH_pt);
      }
    }

    pdf.save(safeFileName);
  };

  try {
    await exportTask();
  } finally {
    cleanup();
  }
}
